  const host = document.getElementById('topology-rec-host');
  if (!host) return;
  try {
    host.innerHTML = _pageRecCard(_pickTopologyRecommendation());
    host.hidden = false;
  } catch (err) {
    console.warn('[topology rec] failed', err);
    host.hidden = true;
  }
