function renderWrongBankBtn() {
  const bank = loadWrongBank();
  // v4.41.0: legacy #wrong-bank-row removed. The preset tile is the only
  // drill entry point; a Clear button lives inside Settings.
  // v4.76.0: legacy #wrong-preset-tile + #wrong-preset-sub kept as compat
  // shims (always hidden) so this function doesn't crash. The visible
  // "Drill Mistakes" tile now lives in the Mode Ladder Quick tier as
  // #modes-wrong-tile + #modes-wrong-sub. Toggle BOTH sets so old code
  // that watches the legacy ids still gets the right is-hidden state.
  const wrongTile = document.getElementById('wrong-preset-tile');
  const wrongSub = document.getElementById('wrong-preset-sub');
  const modesTile = document.getElementById('modes-wrong-tile');
  const modesSub = document.getElementById('modes-wrong-sub');
  const subText = bank.length === 0
    ? '0 wrong answers saved'
    : bank.length + ' wrong answer' + (bank.length !== 1 ? 's' : '') + ' saved';
  if (wrongTile) {
    if (bank.length === 0) {
      wrongTile.classList.add('is-hidden');
    } else {
      wrongTile.classList.remove('is-hidden');
      if (wrongSub) wrongSub.textContent = subText;
    }
  }
  if (modesTile) {
    if (bank.length === 0) {
      modesTile.classList.add('is-hidden');
    } else {
      modesTile.classList.remove('is-hidden');
      if (modesSub) modesSub.textContent = subText;
    }
  }
  // Settings → Clear Wrong Answers Bank count badge
  const clearCount = document.getElementById('wrong-bank-clear-count');
  if (clearCount) clearCount.textContent = bank.length;
}

function renderTodaySection() {
  const section = document.getElementById('today-section');
  if (!section) return;
  // v4.81.22: properly hide the wrapper when nothing meaningful renders inside.
  // Pre-fix the wrapper always showed because the original comment assumed
  // "daily goal card is always visible." But the v4.54.0 hero v2 redesign
  // hides #daily-goal-card via `body.hero-v2-active` CSS rule, AND the v4.81.18
  // consolidation made #todays-focus / #rotation-row / #session-banner permanent
  // hidden compat shims. Result: when `#today-plan` was also correctly hidden
  // (plan done today, isStudyPlanDoneToday true), the section rendered as an
  // empty card with just the "TODAY" title — surfaced by user dogfood screenshot.
  // Now check actual visibility per child + account for hero-v2 CSS rule.
  const candidateIds = [
    '#daily-goal-card',         // v4.54.0 hero v2 hides this via CSS
    '#streak-defender',         // amber warning when streak at risk
    '#daily-challenge-card',    // shown until daily challenge done
    '#today-plan'               // v4.81.18 consolidated card (gates on isStudyPlanDoneToday)
  ];
  const isHeroV2 = document.body && document.body.classList && document.body.classList.contains('hero-v2-active');
  let anyVisible = false;
  for (const sel of candidateIds) {
    const el = section.querySelector(sel);
    if (!el) continue;
    if (el.classList.contains('is-hidden')) continue;
    // Hero v2 hides #daily-goal-card via CSS (`display: none !important`)
    // — treat it as effectively hidden when computing section visibility.
    if (isHeroV2 && sel === '#daily-goal-card') continue;
    anyVisible = true;
    break;
  }
  if (anyVisible) {
    section.classList.remove('is-hidden');
  } else {
    section.classList.add('is-hidden');
  }
}

function clearWrongBank() {
  const bank = loadWrongBank();
  if (bank.length === 0) return;
  // v4.81.11: stronger confirmation copy (Codex r9 #3) — explicit
  // about what gets removed + the recovery path via auto-backup.
  const msg = 'Delete ' + bank.length + ' saved wrong answers?\n\n' +
    'This will:\n' +
    '  • Remove your "Drill Mistakes" study material from the home page\n' +
    '  • Reset which questions appear in the Spaced Repetition queue\n' +
    '  • Clear the wrong-answer counter\n\n' +
    'Cannot be undone via Edit menu. If you have an automatic backup ' +
    'from today (Settings → Automatic backups), you can restore from ' +
    'there if you change your mind.';
  if (!confirm(msg)) return;
  localStorage.removeItem(STORAGE.WRONG_BANK);
  renderWrongBankBtn();
}

// v4.54.8: session-specific Drill my mistakes CTA on Results page.
// Builds a fresh quiz from THIS session's wrong log entries (not the global
// wrong-bank). If every answer was correct the button is hidden upstream.
function drillMistakesFromResults() {
  if (!Array.isArray(log) || log.length === 0) return;
  const wrongEntries = log.filter(e => e && e.isRight === false);
  if (wrongEntries.length === 0) {
    if (typeof showErrorToast === 'function') showErrorToast('Nothing to drill \u2014 you got them all right.');
    return;
  }
  wrongDrillMode = true;
  examMode = false;
  sessionMode = false;
  activeQuizTopic = 'Session \u00b7 mistakes drill';
  // Reuse the question objects from the session log so full context + PBQs survive.
  questions = wrongEntries.map(e => e.q).filter(Boolean);
  current = 0; score = 0; streak = 0; bestStreak = 0; answered = 0; log = [];
  quizFlags = new Array(questions.length).fill(false);
  _sessionStartTs = Date.now();
  showCacheNotice(false);
  showPage('quiz');
  render();
}

// v4.54.8: render inline review-answers list on Results page (prototype pattern).
// Each session question becomes a tappable row: N\u00ba + truncated prompt + topic/domain
// + verdict badge. Click routes to the full Review page (showReview handles the
// index). Unlike the Review page, this list is visible *as part of* the results
// artifact \u2014 makes post-session review one click closer.
function _renderResultsReviewList() {
  const root = document.getElementById('results-review-list');
  if (!root) return;
  if (!Array.isArray(log) || log.length === 0) {
    root.innerHTML = '<div class="results-v2-review-empty">No answers recorded this session.</div>';
    return;
  }
  const esc = (typeof escHtml === 'function') ? escHtml : (s => String(s).replace(/</g, '&lt;'));
  const items = log.map((entry, i) => {
    const q = entry.q || {};
    const prompt = (q.question || q.prompt || '').slice(0, 140);
    const topic = q.topic || '\u2014';
    const domain = (typeof TOPIC_DOMAINS !== 'undefined' && TOPIC_DOMAINS[topic]) ? TOPIC_DOMAINS[topic] : '';
    const isRight = entry.isRight === true;
    const verdictClass = isRight ? 'ok' : 'bad';
    const verdictText = isRight ? 'Correct' : 'Wrong';
    const num = String(i + 1).padStart(2, '0');
    return `<button type="button" class="results-v2-review-row" onclick="showReview(false, ${i})" aria-label="Review question ${i + 1} \u2014 ${verdictText}">
      <div class="results-v2-review-num">N\u00b0 ${num}</div>
      <div class="results-v2-review-body">
        <div class="results-v2-review-q">${esc(prompt)}${prompt.length >= 140 ? '\u2026' : ''}</div>
        <div class="results-v2-review-meta">${esc(topic)}${domain ? ' \u00b7 ' + esc(domain) : ''}</div>
      </div>
      <div class="results-v2-review-mark results-v2-review-mark-${verdictClass}">${verdictText}</div>
    </button>`;
  }).join('');
  root.innerHTML = items;
}

function startWrongDrill() {
  const bank = loadWrongBank();
  if (bank.length === 0) {
    alert('No wrong answers saved yet. Keep quizzing!');
    return;
  }

  const key = document.getElementById('api-key').value.trim();
  apiKey = key; // May be empty, but wrong drill doesn't need API

  wrongDrillMode = true;
  examMode = false;
  sessionMode = false;
  activeQuizTopic = 'Wrong Answers Drill';

  // Pick up to 10 questions from the bank (shuffle)
  const shuffled = [...bank].sort(() => Math.random() - 0.5);
  questions = shuffled.slice(0, 10).map(b => ({
    question: b.question,
    options: b.options,
    answer: b.answer,
    answers: b.answers,
    type: b.type || 'mcq',
    items: b.items,
    correctOrder: b.correctOrder,
    explanation: b.explanation,
    topic: b.topic,
    difficulty: b.difficulty
  }));

  current = 0; score = 0; streak = 0; bestStreak = 0; answered = 0; log = [];
  quizFlags = new Array(questions.length).fill(false);
  showCacheNotice(false);
  showPage('quiz');
  render();
}

// ══════════════════════════════════════════
// WEAK TOPIC DETECTOR
// ══════════════════════════════════════════
function getWeakTopic() {
  const h = loadHistory().filter(e => e.topic !== MIXED_TOPIC && e.topic !== EXAM_TOPIC && e.total >= 5);
  if (h.length < 1) return null;
  const map = {};
  h.forEach(e => {
    if (!map[e.topic]) map[e.topic] = { correct: 0, total: 0 };
    map[e.topic].correct += e.score;
    map[e.topic].total   += e.total;
  });
  let weakest = null, lowestPct = 100;
  Object.entries(map).forEach(([t, s]) => {
    const pct = (s.correct / s.total) * 100;
    if (pct < lowestPct) { lowestPct = pct; weakest = t; }
  });
  return weakest && lowestPct < 75 ? { topic: weakest, pct: Math.round(lowestPct) } : null;
}

// v4.41.0: renderWeakBanner() removed — the amber #weak-banner is redundant
// with the #todays-focus "Weak Spots" chip row which offers the same
// drill-the-weakest-topic UX with better density and no layout jank.
// getWeakTopic() is still used by applyPreset('focused') as a fallback.

// ══════════════════════════════════════════
// API KEY VALIDATION
// ══════════════════════════════════════════
// v4.99.33 — signed-in users skip the BYOK check entirely.
//
// Background: v4.99.2 Phase E.3 introduced _claudeFetch (line 270) which
// auto-routes signed-in users to /api/ai/generate (server-held key, JWT-
// authed) and anonymous users with a stored key through the legacy direct-
// to-Anthropic BYOK path. validateApiKey was written for the BYOK path
// only, but startQuiz() / startExam() / startWrongDrill() / etc. were never
// updated to skip the check when signed-in. The hidden #api-key input
// (v4.99.3 Phase E.4) means signed-in users got empty-string here, which
// failed validation, which blocked Generate Quiz with "Please enter your
// Anthropic API key" — even though they don't need one. Fixing at the
// validateApiKey layer means all 5 callers (startQuiz, startExam, three
// drill-launchers) unblock simultaneously without needing per-callsite
// edits. The actual API call still routes correctly through _claudeFetch.
//
// Reported by founder on iPhone Safari running PROD as a tester1@ playtest
// account, 2026-05-10 12:19 — toast fired on Generate Quiz click despite
// being signed-in Pro.
function validateApiKey(key) {
  // Signed-in users → server proxy, no client key needed. _claudeFetch
  // (line 270) handles the actual routing based on session presence.
  if (typeof window !== 'undefined' && window._certanvilSignedIn === true) return null;
  if (!key) return 'Please enter your Anthropic API key.';
  if (!key.startsWith('sk-ant-')) return 'Invalid API key format. Anthropic keys start with "sk-ant-".';
  if (key.length < 20) return 'API key looks too short. Please check and try again.';
  return null;
}

// Auto-open collapsed sections and scroll to error when API key is missing (v4.32)
function showSetupError() {
  const cqs = document.getElementById('custom-quiz-section'); if (cqs && !cqs.open) cqs.open = true;
  const adv = document.getElementById('advanced-section'); if (adv && !adv.open) adv.open = true;
  const errBox = document.getElementById('setup-err');
  if (errBox) errBox.scrollIntoView({ behavior: 'smooth', block: 'center' });
}

// ══════════════════════════════════════════
// START REGULAR QUIZ
// ══════════════════════════════════════════
async function startQuiz() {
  if (!_gateActivityForQuota('practice quizzes')) return;
  const key = document.getElementById('api-key').value.trim();
  const errBox = document.getElementById('setup-err');
  errBox.classList.add('is-hidden');
  const keyErr = validateApiKey(key);
  if (keyErr) {
    errBox.textContent = keyErr; errBox.classList.remove('is-hidden');
    showSetupError();
    return;
  }
  apiKey = key;
  localStorage.setItem(STORAGE.KEY, key);
  examMode = false;
  wrongDrillMode = false;

  // v4.54.15: Smart + Multi: handled alongside single-topic + Mixed.
  activeQuizTopic = topic.includes('Smart')
    ? getSpacedRepTopic()
    : topic;

  document.getElementById('load-progress').classList.add('is-hidden');
  showPage('loading');
  // v4.81.19: comma-safe count — naive split(',') over-counts when any
  // topic name contains commas (e.g. "NTP, ICMP & Traffic Types").
  const _multiCount = topic.startsWith('Multi: ')
    ? (typeof _parseMultiTopicSentinel === 'function'
        ? _parseMultiTopicSentinel(topic).length
        : topic.slice(7).split(',').length)
    : 0;
  document.getElementById('loading-msg').textContent = topic.includes('Smart')
    ? '\ud83e\udde0 Smart pick: ' + activeQuizTopic + '\u2026'
    : _multiCount >= 2
      ? `Generating ${qCount} ${diff} questions across ${_multiCount} topics\u2026`
      : 'Generating ' + qCount + ' ' + diff + ' questions on ' + activeQuizTopic + '\u2026';

  // v4.82.1: surface the smooth loading progress bar with stage milestones.
  _loadingProgressBegin('Generating questions\u2026');

  showCacheNotice(false);
  // Fire topic brief in parallel (non-blocking). Skip for Mixed AND Multi
  // modes \u2014 a brief only makes sense for a single focused topic.
  const briefTopic = activeQuizTopic;
  if (!briefTopic.includes('Mixed') && !briefTopic.startsWith('Multi: ')) {
    fetchTopicBrief(key, briefTopic);
  } else {
    const tb = document.getElementById('topic-brief');
    if (tb) tb.classList.add('is-hidden');
  }
  try {
    // v4.43.4 — over-request to absorb validation dropout + retry-to-fill if short.
    // The 4-layer validation pipeline (prompt self-check → Sonnet validator →
    // programmatic validateQuestions → GT guards) typically drops 10–40% of
    // generated questions. Pre-v4.43.4 the code tolerated shortfalls as
    // "acceptable", which consistently shipped 6-9 questions for a requested 10.
    // Now: over-request by 30% (min +3), then if we're still short after validation,
    // do ONE retry for the exact deficit + buffer, then slice to qCount.
    const DROPOUT_BUFFER = Math.max(3, Math.ceil(qCount * 0.3));
    document.getElementById('loading-msg').textContent =
      'Generating ' + qCount + ' ' + diff + ' questions on ' + activeQuizTopic + '\u2026';
    let raw = await fetchQuestions(key, activeQuizTopic, diff, qCount + DROPOUT_BUFFER);
    _loadingProgressUpdate('Verifying quality\u2026', 45);
    // Enhancement 1: AI second-pass validation
    document.getElementById('loading-msg').textContent = 'Verifying question accuracy\u2026';
    raw = await aiValidateQuestions(key, raw);
    _loadingProgressUpdate('Finalizing\u2026', 80);
    // Enhancement 2 + 4: Programmatic validation + reported question exclusion
    questions = validateQuestions(raw);
    if (questions.length === 0) throw new Error('All generated questions failed validation. Try again.');

    // Retry-to-fill: if validation left us short of qCount, fetch the deficit + buffer.
    if (questions.length < qCount) {
      const deficit = qCount - questions.length;
      _loadingProgressUpdate('Topping up (' + deficit + ' more)\u2026', 85);
      document.getElementById('loading-msg').textContent =
        'Generating ' + deficit + ' more to complete your ' + qCount + '-question set\u2026';
      try {
        const extraRaw = await fetchQuestions(key, activeQuizTopic, diff, deficit + DROPOUT_BUFFER);
        const extraValidated = validateQuestions(await aiValidateQuestions(key, extraRaw));
        questions = questions.concat(extraValidated);
      } catch (retryErr) {
        // If the retry fails (network/API hiccup), ship what we have — better than
        // blocking the user entirely. They'll see a slight shortfall rather than an error.
        console.warn('Retry fetch failed, shipping what we have:', retryErr);
      }
    }

    // Slice to exact count — truncates buffer overage from the initial over-request
    // and/or retry overage. If we're STILL short after retry (rare — both rounds
    // dropped heavily), ship what we have rather than error out.
    if (questions.length > qCount) {
      questions = questions.slice(0, qCount);
    }
  } catch(e) {
    const cached = getCachedQuestions(activeQuizTopic, diff, qCount);
    if (cached) {
      questions = cached.slice(0, qCount);
      showCacheNotice(true);
    } else {
      _loadingProgressFinish(); // hide bar before returning to setup
      showPage('setup');
      errBox.textContent = '\u26a0\ufe0f ' + (e.message || 'Failed. Check your API key.');
      errBox.classList.remove('is-hidden');
      return;
    }
  }
  // Inject CLI sim / topology PBQs from predefined bank
  const pbqInjectCount = qCount >= 10 ? 1 : 0;
  if (pbqInjectCount > 0) {
    questions = injectPBQs(questions, activeQuizTopic, pbqInjectCount);
  }
  current = 0; score = 0; streak = 0; bestStreak = 0; answered = 0; log = [];
  quizFlags = new Array(questions.length).fill(false);
  // v4.54.8: mark session start for the elapsed-time row on Results
  _sessionStartTs = Date.now();
  // v4.82.1: snap progress bar to 100% then hide before the quiz renders.
  _loadingProgressFinish();
  showPage('quiz');
  render();
}

// v4.54.8: render segmented per-question progress dots. Derives state
// from `log` entries (which store isRight per answered question) + `current`
// for the active-question pill. Pending questions get a small grey dot.
// v4.82.0: dots are now clickable <button>s wired to jumpToQuestion(i).
// Numbered labels, hover lift, full keyboard reachability. The visual
// styling for the new circular treatment lives in `#quiz-prog-dots .qpd-cell`
// (scoped to quiz only — exam dots stay thin since exam has its own
// navigator UI).
function _renderQuizProgressDots() {
  const el = document.getElementById('quiz-prog-dots');
  if (!el || !Array.isArray(questions)) return;
  const n = questions.length;
  // Build a quick lookup of question -> log index (log entries are in answered order;
  // we match on the question object identity since log.push({q, ...}) preserves refs).
  const logByQ = new Map();
  (log || []).forEach(entry => { if (entry && entry.q) logByQ.set(entry.q, entry); });
  const cells = [];
  for (let i = 0; i < n; i++) {
    const q = questions[i];
    const entry = logByQ.get(q);
    let cls = 'qpd-cell';
    let aria;
    let stateLabel;
    // v4.82.0: classes are no longer mutually exclusive — when revisiting a
    // previously-answered question, the dot is BOTH qpd-now AND qpd-done/wrong
    // so styling can show "you're here, and here's the past outcome."
    if (i === current) cls += ' qpd-now';
    if (entry && entry.isRight === true) { cls += ' qpd-done'; stateLabel = 'correct'; }
    else if (entry && entry.isRight === false) { cls += ' qpd-wrong'; stateLabel = 'wrong'; }
    else stateLabel = 'pending';
    aria = `Question ${i + 1}, ${stateLabel}` + (i === current ? ' (current)' : '');
    cells.push(`<button type="button" class="${cls}" onclick="jumpToQuestion(${i})" title="${aria}" aria-label="${aria}">${i + 1}</button>`);
  }
  el.innerHTML = cells.join('');
}

// ══════════════════════════════════════════
// v4.82.0 — Quiz revisit nav helpers
// ══════════════════════════════════════════
// All three helpers are pure index navigation. They re-render and refresh
// the prev/next arrow enabled-state. `render()` checks for an existing
// log entry on the target question and restores its answered-state UI
// (markers + explanation + revisit banner + re-enabled inputs) so the
// user can re-pick.

// Find the existing log entry for a question (by object identity, matching
// how _renderQuizProgressDots builds its map). Returns { entry, idx } or null.
function _findLogEntryFor(q) {
  if (!Array.isArray(log) || !q) return null;
  for (let i = 0; i < log.length; i++) {
    if (log[i] && log[i].q === q) return { entry: log[i], idx: i };
  }
  return null;
}

// v4.82.0: recompute score + answered from `log` after a re-pick. Streak
// is intentionally NOT recomputed — we treat streak as a forward-only
// "you got X correct in a row on first attempt" signal. Re-picks after
// seeing the answer don't move it.
function _recomputeQuizCounters() {
  if (!Array.isArray(log)) return;
  answered = log.length;
  score = log.filter(e => e && e.isRight === true).length;
  const scoreEl = document.getElementById('live-score');
  const streakEl = document.getElementById('live-streak');
  if (scoreEl) scoreEl.textContent = `${score} / ${answered}`;
  if (streakEl) streakEl.textContent = `Streak ${streak}`;
}

// v4.82.0: enable/disable prev/next arrows based on current position.
// Prev: enabled when current > 0.
// Next-arrow: enabled when current < questions.length - 1 AND the current
//             question is either answered OR a future question is answered
//             (so user can navigate over already-answered questions freely
//             without being forced to re-answer pending ones first).
function _renderQuizNavArrows() {
  const prevBtn = document.getElementById('quiz-prev-btn');
  const nextBtn = document.getElementById('quiz-next-arrow-btn');
  if (!prevBtn || !nextBtn || !Array.isArray(questions)) return;
  const total = questions.length;
  prevBtn.disabled = current <= 0;
  // Enable next-arrow if there's any answered or current question after this one,
  // OR this question is already answered (so we can move forward).
  const thisAnswered = !!_findLogEntryFor(questions[current]);
  let canForward = false;
  if (current < total - 1) {
    if (thisAnswered) {
      canForward = true;
    } else {
      // Pending current — only allow forward if any LATER question is also answered.
      // (This handles the case where user jumped over a pending and came back.)
      for (let i = current + 1; i < total; i++) {
        if (_findLogEntryFor(questions[i])) { canForward = true; break; }
      }
    }
  }
  nextBtn.disabled = !canForward;
}

function jumpToQuestion(idx) {
  if (!Array.isArray(questions)) return;
  if (typeof idx !== 'number' || idx < 0 || idx >= questions.length) return;
  if (idx === current) return;
  current = idx;
  render();
  window.scrollTo(0, 0);
}

// v4.82.0: TEST-ONLY hook so Playwright can drop us into a quiz session
// without making real Haiku API calls. The top-level `let questions` etc.
// aren't reachable via `window.questions = ...` (let-declared vars don't
// attach to window), so without this hook the E2E flow can't seed state.
// Always safe — no destructive behavior; just resets module state.
window._testInjectQuiz = function(qs) {
  if (!Array.isArray(qs) || qs.length === 0) return false;
  questions = qs;
  current = 0;
  score = 0;
  streak = 0;
  bestStreak = 0;
  answered = 0;
  log = [];
  quizFlags = qs.map(() => false);
  msSelections = [];
  orderSequence = [];
  topoDevices = {};
  topic = MIXED_TOPIC;
  activeQuizTopic = MIXED_TOPIC;
  showPage('quiz');
  render();
  return true;
};

function prevQuestion() {
  if (current > 0) jumpToQuestion(current - 1);
}

function nextQuestion() {
  if (!Array.isArray(questions)) return;
  if (current < questions.length - 1) jumpToQuestion(current + 1);
  else if (current === questions.length - 1 && _findLogEntryFor(questions[current])) {
    // Last question + answered → show results.
    finish();
  }
}

// v4.82.0: surface/hide the revisit banner. Visible whenever the rendered
// question has a log entry (i.e. user is looking at a question they've
// already answered). Inert affordance — just sets expectation.
function _renderRevisitBanner(hasEntry) {
  const banner = document.getElementById('quiz-revisit-banner');
  if (!banner) return;
  if (hasEntry) banner.classList.remove('is-hidden');
  else banner.classList.add('is-hidden');
}

// ══════════════════════════════════════════
// v4.82.1 — Smooth quiz/diagnostic loading progress
// ══════════════════════════════════════════
// User feature request: "when the questions are loading there needs to be
// some kind of loading bar aswell." Pre-fix, regular quizzes showed only a
// skeleton + status text — exam mode had a per-batch percentage bar but
// quizzes/diagnostic flows didn't. This module surfaces the existing
// #load-progress element on the loading page with a determinate stage-based
// fill that smoothly eases between milestones.
//
// Smoothness is the key UX requirement. Three patterns combined:
//   1. Each milestone is a real event (Haiku resolved, Sonnet resolved,
//      programmatic validation done) — no fakery.
//   2. The fill width transitions via cubic-bezier(0.16, 1, 0.3, 1) over
//      1.6s — races forward then decelerates. Makes the bar feel responsive
//      at first then settle near the milestone (creates anticipation for
//      the next jump).
//   3. A shimmer overlay (CSS pseudo-element + @keyframes) animates
//      continuously regardless of width changes, so the bar always feels
//      "alive" even between real events.
//
// Stage milestones (default for `startQuiz`):
//   Start   →   8% (immediate visual "we're working")
//   Generating questions   →   45%
//   Verifying quality   →   80%
//   Finalizing   →   95%
//   Complete   →   100% (fade out)
//
// For multi-batch flows (n>10 parallel batches OR exam mode), call
// `_loadingProgressUpdate(label, pct)` directly with real per-batch %.

let _loadingProgressBar = null;
let _loadingProgressLabel = null;

function _loadingProgressBegin(initialLabel) {
  const prog = document.getElementById('load-progress');
  _loadingProgressBar = document.getElementById('load-bar-fill');
  _loadingProgressLabel = document.getElementById('load-progress-label');
  if (!prog || !_loadingProgressBar) return;
  prog.classList.remove('is-hidden');
  // Reset to 0 instantly, then fade to initial milestone after a tiny tick.
  _loadingProgressBar.style.transition = 'none';
  _loadingProgressBar.style.width = '0%';
  // Force reflow so the next transition fires from 0 cleanly.
  void _loadingProgressBar.offsetWidth;
  _loadingProgressBar.style.transition = ''; // restore CSS-defined transition
  // Initial visual nudge so the bar shows immediate progress on click.
  setTimeout(() => {
    if (_loadingProgressBar) _loadingProgressBar.style.width = '8%';
  }, 30);
  if (_loadingProgressLabel && initialLabel) _loadingProgressLabel.textContent = initialLabel;
}

function _loadingProgressUpdate(label, pct) {
  if (!_loadingProgressBar) return;
  if (typeof pct === 'number') {
    const clamped = Math.max(0, Math.min(100, pct));
    _loadingProgressBar.style.width = clamped + '%';
  }
  if (_loadingProgressLabel && label) _loadingProgressLabel.textContent = label;
}

function _loadingProgressFinish() {
  if (!_loadingProgressBar) return;
  // Snap to 100% then schedule hide. The 100% bump uses the same eased
  // transition so it doesn't feel jarring relative to the prior milestones.
  _loadingProgressBar.style.width = '100%';
  if (_loadingProgressLabel) _loadingProgressLabel.textContent = 'Ready!';
  setTimeout(() => {
    const prog = document.getElementById('load-progress');
    if (prog) prog.classList.add('is-hidden');
    _loadingProgressBar = null;
    _loadingProgressLabel = null;
  }, 400);
}

// v4.54.9: exam-mode segmented progress dots. Mirrors the quiz version but
// reads examAnswers[i].chosen/msChosen/orderSeq to decide per-question state.
// In exam mode we can't know correct/wrong until submit, so we only distinguish
// "answered" (green-ish) vs "flagged" (yellow) vs "current" vs "pending".
function _renderExamProgressDots() {
  const el = document.getElementById('exam-prog-dots');
  if (!el || !Array.isArray(examQuestions)) return;
  const n = examQuestions.length;
  const cells = [];
  for (let i = 0; i < n; i++) {
    const ans = examAnswers[i] || {};
    const answered = (ans.chosen !== null && ans.chosen !== undefined) ||
                     (Array.isArray(ans.msChosen) && ans.msChosen.length > 0) ||
                     (Array.isArray(ans.orderSeq) && ans.orderSeq.length > 0) ||
                     (ans.topoState && Object.keys(ans.topoState).length > 0);
    let cls = 'qpd-cell';
    let aria;
    if (i === examCurrent) { cls += ' qpd-now'; aria = `Question ${i + 1}, current`; }
    else if (ans.flagged) { cls += ' qpd-flagged'; aria = `Question ${i + 1}, flagged`; }
    else if (answered) { cls += ' qpd-done'; aria = `Question ${i + 1}, answered`; }
    else { aria = `Question ${i + 1}, pending`; }
    cells.push(`<span class="${cls}" role="presentation" title="${aria}"></span>`);
  }
  el.innerHTML = cells.join('');
}

// v4.54.8: track quiz session start time for elapsed-time row in Results.
let _sessionStartTs = 0;
function _formatElapsed(ms) {
  if (!ms || ms < 0) return '\u2014';
  const s = Math.round(ms / 1000);
  const m = Math.floor(s / 60);
  const rs = s % 60;
  return m > 0 ? `${m}m ${String(rs).padStart(2,'0')}s` : `${rs}s`;
}

// ══════════════════════════════════════════
// START EXAM SIMULATION
// ══════════════════════════════════════════
async function startExam() {
  if (!_gateActivityForQuota('exam simulator')) return;
  const key = document.getElementById('api-key').value.trim();
  const errBox = document.getElementById('setup-err');
  errBox.classList.add('is-hidden');
  const keyErr = validateApiKey(key);
  if (keyErr) { errBox.textContent = keyErr; errBox.classList.remove('is-hidden'); showSetupError(); return; }
  apiKey = key;
  localStorage.setItem(STORAGE.KEY, key);

  examMode = true;
  // Hardcore mode (#48): read the persisted checkbox state at start time
  examHardcore = localStorage.getItem(STORAGE.HARDCORE_EXAM) === '1';
  const examPage = document.getElementById('page-exam');
  if (examPage) examPage.classList.toggle('hardcore-active', examHardcore);
  wrongDrillMode = false;
  examQuestions = [];
  examAnswers   = [];
  examCurrent   = 0;
  examTimeLeft  = EXAM_TIME_SECONDS;
  navOpen       = false;

  showPage('loading');
  document.getElementById('loading-msg').textContent = 'Building 90-question exam\u2026';
  // v4.82.1: use the unified smooth loading-progress module so exam mode
  // gets the same eased transition + shimmer overlay as quiz/diagnostic.
  // The label updates per-batch use _loadingProgressUpdate(label, pct).
  _loadingProgressBegin('Building 90-question exam\u2026');
  const lbl = document.getElementById('load-progress-label'); // kept for legacy textContent writes

  // v4.43.5 — Exam now runs the same validation pipeline as quiz mode (was
  // shipping raw Haiku batches). Per-batch: over-request → Sonnet semantic pass
  // → programmatic validator → retry-to-fill if short. Graceful degradation:
  // if BOTH rounds drop heavily on a batch, ship what we have and surface a
  // banner on the exam page (score scaling is correct/total so a shortfall
  // scales proportionally — 720 pass threshold stays honest).
  const BATCHES = 5, EXAM_BATCH_BASE = 18, EXAM_BATCH_BUFFER = 5, MAX_RETRIES = 2;
  try {
    for (let i = 0; i < BATCHES; i++) {
      _loadingProgressUpdate(`Batch ${i + 1} / ${BATCHES} \u2014 generating\u2026`, (i / BATCHES) * 100);

      // Step 1: Generate (over-request) with fetch-retry on throw
      document.getElementById('loading-msg').textContent =
        `Generating questions (${examQuestions.length} / 90)\u2026`;
      let rawBatch = null;
      for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
          // v4.81.15: pass batch index `i` (0..4) as staleSliceIdx so each
          // of the 5 sequential exam batches sees a different rotating
          // window of stale topics. Without this all 5 batches would see
          // the SAME stale-topic top-N and Haiku would cluster picks at
          // the top, defeating the breadth goal across a 90-Q exam.
          rawBatch = await fetchQuestions(key, MIXED_TOPIC, 'Mixed', EXAM_BATCH_BASE + EXAM_BATCH_BUFFER, i);
          break;
        } catch(retryErr) {
          if (attempt === MAX_RETRIES) throw retryErr;
          lbl.textContent = `Batch ${i + 1} failed, retrying (${attempt + 1}/${MAX_RETRIES})\u2026`;
          await new Promise(r => setTimeout(r, 1500));
        }
      }

      // Step 2: Validate — Sonnet semantic pass + programmatic checks
      // (same pipeline as startQuiz, per v4.43.5 parity decision)
      lbl.textContent = `Batch ${i + 1} / ${BATCHES} \u2014 verifying\u2026`;
      const aiValidated = await aiValidateQuestions(key, rawBatch);
      let batch = validateQuestions(aiValidated);

      // v4.81.14: cross-batch dedup (user report: same questions repeating
      // across the 5 exam batches). fetchQuestions dedupes within a single
      // call; this catches duplicates between sequential exam batches where
      // Haiku has no state from prior batches. Drop duplicates here so the
      // retry-to-fill logic below treats them as deficit and refills.
      if (examQuestions.length > 0) {
        const seenStems = new Set(examQuestions.map(q => _normalizeStemForDedup(q && q.question)));
        const before = batch.length;
        batch = batch.filter(q => {
          const norm = _normalizeStemForDedup(q && q.question);
          if (!norm) return true; // keep questions with no stem (defensive)
          if (seenStems.has(norm)) return false;
          seenStems.add(norm);
          return true;
        });
        if (batch.length < before) {
          console.info(`[exam] batch ${i + 1}: dropped ${before - batch.length} duplicate stem(s) already in earlier batches`);
        }
      }

      // Step 3: Retry-to-fill if post-validation short — ONE retry per batch
      if (batch.length < EXAM_BATCH_BASE) {
        const deficit = EXAM_BATCH_BASE - batch.length;
        lbl.textContent = `Batch ${i + 1} / ${BATCHES} \u2014 filling ${deficit} more\u2026`;
        try {
          // v4.81.15: retry-to-fill stays on the same staleSliceIdx as
          // the parent batch so we keep filling the same rotation window.
          const extraRaw = await fetchQuestions(key, MIXED_TOPIC, 'Mixed', deficit + EXAM_BATCH_BUFFER, i);
          let extraValidated = validateQuestions(await aiValidateQuestions(key, extraRaw));
          // v4.81.14: dedupe the retry-to-fill payload against accumulated
          // examQuestions + the current batch's already-deduped contents.
          // Otherwise we'd undo the dedup we just did.
          const seenStemsRetry = new Set([
            ...examQuestions.map(q => _normalizeStemForDedup(q && q.question)),
            ...batch.map(q => _normalizeStemForDedup(q && q.question))
          ]);
          extraValidated = extraValidated.filter(q => {
            const norm = _normalizeStemForDedup(q && q.question);
            if (!norm) return true;
            if (seenStemsRetry.has(norm)) return false;
            seenStemsRetry.add(norm);
            return true;
          });
          batch = batch.concat(extraValidated);
        } catch(retryErr) {
          console.warn(`Exam batch ${i + 1} retry-to-fill failed, continuing with partial batch:`, retryErr);
        }
      }

      // Step 4: Slice batch to EXAM_BATCH_BASE (truncate overage, accept shortage).
      // If still < EXAM_BATCH_BASE here, the final exam will be short of 90 — handled below.
      examQuestions = examQuestions.concat(batch.slice(0, EXAM_BATCH_BASE));
    }
    _loadingProgressUpdate('Finalizing…', 98);
    // Inject 2 CLI/topo PBQs into exam (predefined bank — already known good, skip validation)
    examQuestions = injectPBQs(examQuestions, MIXED_TOPIC, 2);
    // Defensive truncate: if injectPBQs somehow grew past 90 (shouldn't — it splices 1-for-1)
    if (examQuestions.length > EXAM_QUESTION_COUNT) {
      examQuestions = examQuestions.slice(0, EXAM_QUESTION_COUNT);
    }
    // Capture final count before render so we can surface the shortfall banner if needed
    const examShortfall = examQuestions.length < EXAM_QUESTION_COUNT;

    examAnswers = examQuestions.map(() => ({ chosen: null, flagged: false, msChosen: [], orderSeq: [], cliRan: [], topoState: {} }));
    // v4.82.1: hide loading bar before swapping to the exam page.
    _loadingProgressFinish();
    showPage('exam');
    renderExam();
    startExamTimer();
    // Option B (user-approved, v4.43.5): graceful degradation — ship the exam
    // with what we have rather than error out. Show a non-blocking banner.
    if (examShortfall) showExamShortfallBanner(examQuestions.length);
  } catch(e) {
    examMode = false;
    _loadingProgressFinish();
    showPage('setup');
    errBox.textContent = e.message;
    errBox.classList.remove('is-hidden');
  }
}

// v4.43.5: surface a subtle banner when exam ships fewer than 90 questions
// because both the initial generation and the retry-to-fill dropped questions.
// Non-blocking — user can dismiss and take the exam. Scaling (correct/total)
// handles the shortfall proportionally so the 720 pass mark stays honest.
function showExamShortfallBanner(actualCount) {
  const examPage = document.getElementById('page-exam');
  if (!examPage) return;
  const existing = document.getElementById('exam-shortfall-banner');
  if (existing) existing.remove();
  const filtered = EXAM_QUESTION_COUNT - actualCount;
  const banner = document.createElement('div');
  banner.id = 'exam-shortfall-banner';
  banner.className = 'exam-shortfall-banner';
  banner.setAttribute('role', 'status');
  banner.innerHTML = `
    <span class="exam-shortfall-icon" aria-hidden="true"></span>
    <span class="exam-shortfall-text">This exam has <strong>${actualCount} of ${EXAM_QUESTION_COUNT}</strong> questions \u2014 ${filtered} were filtered out by the quality validator. Your score scales against the actual count, so the ${EXAM_PASS_SCORE} pass mark stays accurate.</span>
    <button class="exam-shortfall-dismiss" onclick="document.getElementById('exam-shortfall-banner')?.remove()" aria-label="Dismiss">\u00D7</button>
  `;
  examPage.insertBefore(banner, examPage.firstChild);
}

// ══════════════════════════════════════════
// API — FETCH QUESTIONS (with PBQ support)
// ══════════════════════════════════════════
// v4.56.1: batching layer added. Large requests (n > QUIZ_BATCH_THRESHOLD) are
// split into concurrent batches of ≤QUIZ_BATCH_SIZE so each prompt stays in
// Haiku's comfort zone. PBQ budget is computed once at the outer level and
// parcelled out so the overall PBQ ratio doesn't drift when we batch.
const QUIZ_BATCH_SIZE      = 10;  // per-batch question count — chosen so Haiku reliably emits well-formed JSON
const QUIZ_BATCH_THRESHOLD = 12;  // requests at or below this size stay single-shot (no batching overhead)

// v4.81.14: stem-normalize for cross-batch dedup (user report: "some
// questions kept repeating themselves" in exam mode + occasionally in
// regular quizzes). Lowercase + strip punctuation + collapse whitespace
// + length-cap for stable comparison. Catches "Which of the following
// best describes ARP?" vs "which of the following BEST describes arp."
// as the same stem.
function _normalizeStemForDedup(stem) {
  if (!stem) return '';
  return String(stem)
    .toLowerCase()
    .replace(/[^\w\s]/g, '')   // strip punctuation
    .replace(/\s+/g, ' ')       // collapse whitespace
    .trim()
    .slice(0, 200);             // cap to avoid weird unicode tail issues
}

async function fetchQuestions(key, qTopic, difficulty, n, staleSliceIdx) {
  // v4.81.15: optional staleSliceIdx threads through to the per-batch
  // prompt builder for stale-topic rotation. Callers who fire fetchQuestions
  // multiple times (startExam's 5 sequential calls) pass i=0..4 so each
  // batch sees a different rotating window of stale topics. Default 0.
  // Single-shot path for small requests — avoids concurrency overhead + keeps
  // cache semantics identical to pre-v4.56.1 behaviour.
  if (n <= QUIZ_BATCH_THRESHOLD) {
    const result = await _fetchQuestionsBatch(key, qTopic, difficulty, n, undefined, staleSliceIdx);
    cacheQuestions(qTopic, difficulty, n, result);
    return result;
  }

  // Batched path — split n into ≤QUIZ_BATCH_SIZE chunks as evenly as possible.
  // e.g. n=20 → [10, 10]; n=26 (20+DROPOUT_BUFFER) → [9, 9, 8]; n=50 → [10]×5.
  const numBatches = Math.ceil(n / QUIZ_BATCH_SIZE);
  const base = Math.floor(n / numBatches);
  const remainder = n - (base * numBatches);
  const batchSizes = Array.from({ length: numBatches }, (_, i) => base + (i < remainder ? 1 : 0));

  // Compute the TOTAL PBQ budget once (so batching doesn't inflate PBQ ratio)
  // then distribute across batches — early batches absorb the budget.
  const totalPbqBudget = n >= 10 ? 2 : (n >= 7 ? 1 : 0);
  const pbqBudgets = new Array(numBatches).fill(0);
  for (let i = 0; i < totalPbqBudget; i++) pbqBudgets[i % numBatches]++;

  // v4.81.15: inner-batch rotation. Each parallel sub-batch within this
  // single fetchQuestions call gets a different sliceIdx so they don't
  // all see the same top-of-list stale topics. Combined with the outer
  // staleSliceIdx (from startExam) this gives coverage breadth at both
  // levels.
  const outerIdx = (typeof staleSliceIdx === 'number') ? staleSliceIdx : 0;

  // Fire all batches concurrently — Haiku handles this well and end-to-end
  // latency ends up close to a single batch's latency (~3-5s) instead of
  // n×batch-latency sequential.
  const settled = await Promise.allSettled(
    batchSizes.map((size, i) => _fetchQuestionsBatch(key, qTopic, difficulty, size, pbqBudgets[i], outerIdx + i))
  );

  const merged = _mergeBatchedFetchResults(settled, numBatches, n);
  cacheQuestions(qTopic, difficulty, n, merged);
  return merged;
}

// v4.85.7: extracted from fetchQuestions() to keep it under 80 lines. Merges
// the Promise.allSettled results, dedupes cross-batch duplicate stems by
// normalized stem (first-seen wins), bubbles up API errors, and emits diag
// console.warn/info messages so partial failures show in dev.
function _mergeBatchedFetchResults(settled, numBatches, n) {
  const merged = [];
  const seenStems = new Set();
  let failed = 0;
  let deduped = 0;
  settled.forEach(r => {
    if (r.status === 'fulfilled') {
      r.value.forEach(q => {
        const norm = _normalizeStemForDedup(q && q.question);
        if (norm && seenStems.has(norm)) { deduped++; return; }
        if (norm) seenStems.add(norm);
        merged.push(q);
      });
    } else {
      failed++;
      if (r.reason && r.reason.apiError) throw r.reason;
    }
  });
  if (merged.length === 0) {
    throw new Error('AI returned malformed data. Please try again.');
  }
  if (failed > 0 && typeof console !== 'undefined' && console.warn) {
    console.warn(`[fetchQuestions] ${failed}/${numBatches} batches failed — returning ${merged.length}/${n} questions; caller will retry-to-fill if needed`);
  }
  if (deduped > 0 && typeof console !== 'undefined' && console.info) {
    console.info(`[fetchQuestions] dropped ${deduped} duplicate stem(s) across batches; merged ${merged.length}/${n}`);
  }
  return merged;
}

// v4.56.1: single-batch worker — contains all the prompt construction + fetch
// + parse + retry-without-scenario logic. Exposed via _fetchQuestionsBatch so
// the outer fetchQuestions can batch large requests concurrently. pbqCountOverride
// lets the outer coordinator parcel out PBQ budget across batches.
// v4.81.15: staleSliceIdx threaded through from fetchQuestions for stale-
// topic rotation in the prompt-injection layer. See _computeStaleTopics.
async function _fetchQuestionsBatch(key, qTopic, difficulty, n, pbqCountOverride, staleSliceIdx) {
  const topicHints = {
    'Integrating Networked Devices': 'IoT devices, ICS/SCADA systems, OT/IT convergence, smart building tech, embedded systems, segmentation of IoT, industrial control risks.',
    'Network Troubleshooting & Tools': 'Troubleshooting methodology, ping, traceroute/tracert, ipconfig/ifconfig, nslookup, dig, netstat, arp, route, Wireshark/packet capture, cable testers, TDR, loopback testing, common network faults.',
    'NAT & IP Services': 'Static NAT, dynamic NAT, PAT/NAT overload, inside/outside local/global, port forwarding, NAT64, private vs public IP ranges, IP helper addresses.',
    'AAA & Authentication': 'AAA framework, RADIUS protocol and ports, TACACS+, RADIUS vs TACACS+ differences, 802.1X port-based authentication, EAP variants, Kerberos, LDAP, MFA, certificate-based auth.',
    'NTP, ICMP & Traffic Types': 'NTP stratum levels, NTP hierarchy, ICMP message types (echo, TTL exceeded, unreachable, redirect), ping and traceroute mechanics, unicast vs multicast vs broadcast vs anycast, IGMP.',
    'Ethernet Standards': '802.3 standards, 10BASE-T, 100BASE-TX, 1000BASE-T, 10GBASE-T, 1000BASE-SX/LX, 10GBASE-SR/LR, fibre vs copper, auto-negotiation, duplex, PoE (802.3af/at/bt), MDI/MDIX.',
    'IPsec & VPN Protocols': 'IPsec tunnel vs transport mode, AH vs ESP, IKEv1 vs IKEv2, IKE Phase 1 (main/aggressive), IKE Phase 2, ISAKMP, SA negotiation, site-to-site VPN, remote access VPN, SSL/TLS VPN, split tunneling, GRE tunnels, L2TP/IPsec, OpenVPN.',
    'SMB & Network File Services': 'SMB protocol versions (SMBv1/2/3), CIFS, NFS (v3/v4), Samba, file share permissions vs NTFS, UNC paths, port 445 (SMB), port 2049 (NFS), iSCSI, SAN vs NAS, FTP/SFTP/FTPS, SCP.',
    'Cloud Networking & VPCs': 'VPC (Virtual Private Cloud), subnets in cloud, route tables, internet gateways, NAT gateways, security groups vs NACLs, VPC peering, transit gateways, VPN to cloud, Direct Connect / ExpressRoute, cloud service models (IaaS/PaaS/SaaS), shared responsibility model, multi-tenant networking.',
    'Port Numbers': 'Every question must be about matching a protocol to its port number or transport (TCP/UDP). Cover: FTP data 20/TCP, FTP control 21/TCP, SSH & SFTP 22/TCP, Telnet 23/TCP, SMTP 25/TCP, DNS 53 (TCP & UDP), DHCP server 67/UDP & client 68/UDP, TFTP 69/UDP, HTTP 80/TCP, Kerberos 88 (TCP & UDP), POP3 110/TCP, NTP 123/UDP, NetBIOS name 137/UDP, NetBIOS datagram 138/UDP, NetBIOS session 139/TCP, IMAP 143/TCP, SNMP queries 161/UDP & traps 162/UDP, LDAP 389/TCP, HTTPS 443/TCP, SMB 445/TCP, Syslog 514/UDP, SMTP submission/TLS 587/TCP, LDAPS 636/TCP, iSCSI 3260/TCP, TACACS+ 49/TCP, BGP 179/TCP, RADIUS auth 1812/UDP & accounting 1813/UDP, NFS 2049/TCP & UDP, MySQL 3306/TCP, RDP 3389/TCP, SIP 5060/UDP & TLS 5061/TCP, VNC 5900/TCP, IKE/IPsec 500/UDP, IPsec NAT-T 4500/UDP, L2TP 1701/UDP, OpenVPN 1194/UDP, FTPS implicit 990/TCP. Use tricky distractors.',
    'PKI & Certificate Management': 'Public Key Infrastructure: Root CA, Intermediate CA, end-entity (leaf) certificates and the full chain of trust. Certificate fields: CN, SAN, issuer, expiry. Self-signed vs CA-signed. CRL and OCSP. TLS handshake steps. Cipher suites. Wildcard certificates. Certificate pinning. Private vs public keys. PKI use cases: HTTPS, email signing (S/MIME), VPN certificate auth, code signing.',
    'CompTIA Troubleshooting Methodology': 'The CompTIA 7-step troubleshooting methodology: 1) Identify the problem, 2) Establish a theory, 3) Test the theory, 4) Establish a plan of action, 5) Implement the solution or escalate, 6) Verify full system functionality and implement preventive measures, 7) Document findings. When to escalate vs implement.',
    'Firewalls, DMZ & Security Zones': 'Stateful vs stateless firewalls. NGFW. UTM. Security zones: trusted, untrusted, DMZ. Screened subnet. Implicit deny. Firewall rule order and ACL processing. Content/URL filtering. Active-passive HA. Proxy firewalls. Host-based vs network-based firewalls.',
    'WPA3 & EAP Authentication': 'WPA3-Personal: SAE/Dragonfly. WPA3-Enterprise: 192-bit security. OWE. WPA3 vs WPA2. EAP types: EAP-TLS, PEAP, EAP-TTLS, EAP-FAST. 802.1X roles: Supplicant, Authenticator, Authentication Server. Wi-Fi Easy Connect. Transition mode.',
    'SDN, NFV & Automation': 'SDN: control/data plane separation. SDN controller, northbound/southbound APIs, OpenFlow. NFV: VNF, virtualising network functions. IaC: Ansible, Terraform, Puppet. YANG/NETCONF. Intent-based networking. REST APIs. Zero-touch provisioning.',
    'Network Appliances & Device Functions': 'Load balancers (hardware vs software, Layer 4 vs Layer 7, algorithms: round-robin / least-connections / weighted / source-IP hash, active-active vs active-passive, health checks, SSL/TLS offloading). Proxy servers: forward proxy (outbound filtering, anonymity, caching), reverse proxy (inbound distribution, caching, SSL termination, hides backend topology), transparent proxy (inline, no client config needed). IDS/IPS/NIDS/NIPS: detection vs prevention, signature-based vs anomaly-based/behavioural, in-line vs passive/tap placement. Next-Generation Firewall (NGFW) and Unified Threat Management (UTM) — app-aware filtering, deep packet inspection, bundled AV + IPS + content filter. VPN concentrator. Content/URL filter / web filter. Wireless access points (WAP) and Wireless LAN Controllers (WLC) — autonomous vs lightweight APs. Layer 3 capable switch / multilayer switch. Cable modem, DSL modem, ONT (fiber optical network terminal). Covers device selection, placement, distinctions between similar appliances (proxy vs reverse proxy vs load balancer; IDS vs IPS; NGFW vs UTM).'
  };
  // v4.85.8: N10-009 domain-weighted distribution + per-batch TOPIC LOTTERY for
  // Mixed mode. Pre-samples specific topics from each domain (vs letting Haiku
  // choose) so the user gets a genuinely random spread instead of Haiku's
  // 4-5 default-favorite topics. Each batch independently re-samples, so two
  // back-to-back Mixed sessions produce different topic mixes.
  let mixedDistributionStr = '';
  if (qTopic === MIXED_TOPIC) {
    const dist = computeDomainDistribution(n);
    const sampled = _sampleTopicsForMixedBatch(dist);
    const fmt = (arr) => arr.length === 0 ? '  (none this batch)' : arr.map(t => '  - "' + t + '"').join('\n');
    mixedDistributionStr = `\n\nMANDATORY TOPIC LOTTERY — Of the ${n} questions, generate EXACTLY ONE question per topic listed below (${n} topics total). Each question's .topic field MUST match the assigned topic verbatim. This is a true random sample — do NOT skip topics, do NOT repeat topics, and do NOT substitute "easier" topics for the ones listed.

Domain 1.0 — Networking Concepts (${dist.concepts} questions, 23% of exam):
${fmt(sampled.concepts)}

Domain 2.0 — Network Implementation (${dist.implementation} questions, 20%):
${fmt(sampled.implementation)}

Domain 3.0 — Network Operations (${dist.operations} questions, 19%):
${fmt(sampled.operations)}

Domain 4.0 — Network Security (${dist.security} questions, 14%):
${fmt(sampled.security)}

Domain 5.0 — Network Troubleshooting (${dist.troubleshooting} questions, 24%):
${fmt(sampled.troubleshooting)}
`;
  }
  // v4.54.15: multi-topic mode \u2014 Custom Quiz selected 2+ specific topics.
  // Parse the list out of the "Multi: ..." sentinel and build a distribution
  // prompt that tells Claude to split the n questions evenly across the
  // selected topics (rounded up, with overage from the tail truncation later).
  const isMulti = typeof qTopic === 'string' && qTopic.startsWith('Multi: ');
  let multiTopicList = [];
  if (isMulti) {
    // v4.81.19: comma-safe parse — preserves topic names like
    // "NTP, ICMP & Traffic Types" verbatim instead of mis-splitting them.
    // Critical for the prompt to Haiku — a mis-split list would tell Haiku
    // to write questions tagged with "NTP" + "ICMP & Traffic Types" instead
    // of the canonical "NTP, ICMP & Traffic Types" topic.
    multiTopicList = (typeof _parseMultiTopicSentinel === 'function')
      ? _parseMultiTopicSentinel(qTopic)
      : qTopic.slice(7).split(',').map(s => s.trim()).filter(Boolean);
    const per = Math.max(1, Math.floor(n / multiTopicList.length));
    const remainder = n - (per * multiTopicList.length);
    mixedDistributionStr = `\n\nMANDATORY MULTI-TOPIC DISTRIBUTION: Of the ${n} questions, generate ${per} question${per === 1 ? '' : 's'} per topic from this list of ${multiTopicList.length} topics:\n${multiTopicList.map((t, i) => `- ${t}${topicHints[t] ? ' \u2014 ' + topicHints[t] : ''}${i < remainder ? ' (generate 1 EXTRA here)' : ''}`).join('\n')}\n\nDo not stray outside these ${multiTopicList.length} topics. Each question must explicitly focus on ONE of them, and the .topic field of every returned question must match one of these exact strings.`;
  }
  const expectedObj = (!isMulti && qTopic !== MIXED_TOPIC && topicResources[qTopic]) ? topicResources[qTopic].obj : null;
  // v4.87.0: cert-aware prompt voice. Substitutes CERT_NAME_FULL so Haiku
  // generates SY0-701 questions in Security+ mode + N10-009 in Network+ mode.
  const topicStr = qTopic === MIXED_TOPIC
    ? `Cover a broad mix of ${CERT_NAME_FULL} exam topics across all 5 official CompTIA domains.`
    : isMulti
      ? `Cover these ${multiTopicList.length} specific ${CERT_NAME_FULL} topics selected by the user: ${multiTopicList.map(t => '"' + t + '"').join(', ')}. See the mandatory distribution block below.`
      : `Focus only on: "${qTopic}" for the ${CERT_NAME_FULL} exam (primary objective ${expectedObj || 'N/A'}).${topicHints[qTopic] ? ' Specifically cover: ' + topicHints[qTopic] : ''}`;

  const diffStr = {
    'Foundational':  'Foundational: test basic recall and definitions. Clear right answers.',
    'Exam Level':    'Exam Level: scenario-based, mirrors real CompTIA style. Plausible distractors.',
    'Hard / Tricky': 'Hard: tricky edge cases, near-identical distractors, deep understanding required.',
    'Mixed':         'Mix of foundational, exam-level, and hard questions across all difficulties.'
  }[difficulty] || DEFAULT_DIFF;

  // Determine PBQ count. If the outer coordinator parcelled out a specific
  // budget for this batch (batching path), use it; otherwise fall back to the
  // single-shot formula (pre-v4.56.1 behaviour).
  const pbqCount = (typeof pbqCountOverride === 'number')
    ? Math.min(pbqCountOverride, n)
    : (n >= 10 ? 2 : (n >= 7 ? 1 : 0));
  const mcqCount = n - pbqCount;

  const pbqInstructions = pbqCount > 0 ? `

IMPORTANT: Out of the ${n} questions, generate exactly ${mcqCount} as standard MCQ and ${pbqCount} as performance-based questions (PBQ).

For standard MCQ, use this format (scenario is OPTIONAL — only include on ~30-40% of Exam Level / Hard questions where real-world context genuinely disambiguates the answer):
{"type":"mcq","question":"...","scenario":"(optional — 1-2 sentences of setup context)","difficulty":"...","topic":"...","objective":"X.Y","options":{"A":"...","B":"...","C":"...","D":"..."},"answer":"A|B|C|D","explanation":"..."}

For PBQ, use MULTI-SELECT format (choose 2 or 3 correct answers from 5 options):
{"type":"multi-select","question":"(Choose TWO) ...","difficulty":"...","topic":"...","objective":"X.Y","options":{"A":"...","B":"...","C":"...","D":"...","E":"..."},"answers":["A","C"],"explanation":"..."}

CRITICAL — MULTI-SELECT QUALITY CRITERIA (CompTIA exam style):
- BOTH (or all 3) correct answers must be CORE, well-known facts about the topic — at similar levels of prominence/familiarity. Do NOT make one correct answer obvious and the other obscure or edge-case. Difficulty in multi-select comes from BREADTH (knowing multiple facts apply), NOT from one being a buried trivia point.
- DISTRACTORS must be FACTUALLY WRONG about the topic. They should describe things that are categorically false, NOT things that are "less correct" or are correct facts about an adjacent/related topic. The user must be able to rule them out with actual knowledge — not by elimination.
- AVOID the trap of "1 obvious correct + 1 obscure correct + 2 plausible-sounding adjacent-topic distractors" — that produces partial-credit scoring and frustration without testing real understanding.
- The EXPLANATION must enumerate, separately and concretely:
  • WHY each correct answer is correct (1-2 sentences each)
  • WHY each distractor is wrong — naming a specific factual error, not just "less applicable" or "not the best fit"
- Multi-select stems should ask about what IS true / IS valid / DOES apply — not about ranking, fit, or "best."
- NEVER create a question where MORE options are factually correct than the stem asks for. Example: 6to4, Teredo, AND NAT64 are ALL valid IPv6 transition methods — a "Which TWO" stem forces the student to guess which 2 of 3 correct answers the grader prefers, which is NOT how CompTIA writes exams. If a topic has N valid answers, either ask for all N or reframe the stem to narrow which subset is being tested (e.g., "Which TWO are tunneling methods?" excludes NAT64 since it's translation, not tunneling).
- SELF-TEST before finalizing: for each correct answer, ask "could a student who studied this topic for 2 weeks identify this as correct?" If the answer is no for ANY correct option, the question fails the balance test. Replace the obscure correct answer with a more recognizable one.
- CONCRETE EXAMPLES of good vs bad multi-select:
  BAD: "Which TWO describe OSPF?" → A) Uses Dijkstra's algorithm (obvious) B) Uses area 0 as backbone (obscure detail) — student gets A easily, guesses on B.
  GOOD: "Which TWO are link-state routing protocols?" → A) OSPF B) IS-IS — both are CORE facts at the same prominence level. A student who studied routing protocols knows both.
  BAD: "Which TWO are used for network monitoring?" → A) SNMP (obvious) B) NetFlow (less obvious) C) Syslog (also valid!) — 3 correct answers crammed into "pick 2."
  GOOD: "Which TWO protocols use UDP port 161 or 162?" → A) SNMP GET B) SNMP TRAP — narrow, factual, both equally knowable.` : '';

  // v4.58.0: pull 3-5 curated exemplars matching this topic/domain to inject
  // as few-shot style references. Empty bank → no-op (returns empty block) so
  // current behaviour is unchanged until Phase 2 content lands.
  const exemplarBlock = _formatExemplarsForPrompt(
    _pickExemplarsForTopic(qTopic, 3)
  );

  // v4.62.3: Priority Retention Concepts — injected into every batch so
  // Haiku is nudged (not mandated) toward testing the user's recently-
  // studied gap topics whenever the current scenario permits. Empty
  // RETENTION_GAP_CONCEPTS → no-op empty string.
  const retentionBlock = (typeof _formatRetentionConceptsForPrompt === 'function')
    ? _formatRetentionConceptsForPrompt()
    : '';

  // v4.81.15: stale-topic rotation block — surfaces topics the user
  // hasn't practised in WEAK_STALENESS_DAYS+ as a depth/difficulty hint
  // within the v4.85.8 TOPIC LOTTERY. Only fires for MIXED_TOPIC
  // (single-topic quizzes already focus there; multi-topic mode honours
  // the user's explicit selection). Defensive — never blocks the fetch
  // on a stale-topic compute error.
  let staleBlock = '';
  if (qTopic === MIXED_TOPIC && (difficulty === 'Mixed' || difficulty === 'Exam Level' || difficulty === 'Foundational' || difficulty === 'Hard / Tricky')) {
    try {
      if (typeof _computeStaleTopics === 'function' && typeof loadHistory === 'function') {
        const hist = loadHistory();
        if (Array.isArray(hist) && hist.length >= STALE_CHIP_MIN_HISTORY) {
          const staleTopics = _computeStaleTopics(hist, STALE_PROMPT_TOPIC_COUNT, staleSliceIdx, STALE_PROMPT_SLICE_SIZE);
          staleBlock = _formatStaleTopicsForPrompt(staleTopics);
        }
      }
    } catch (_) { staleBlock = ''; }
  }

  // v4.56.1: Scenario field instructions isolated so they can be omitted on
  // retry. They were the main prompt bloat added in v4.56.0 and on complex
  // runs (multi-topic + Mixed + 20 questions) they occasionally push Haiku
  // into producing malformed JSON — retry without them usually succeeds.
  const scenarioInstructions = `
SCENARIO CONTEXT FIELD (optional, exam-realism):
- On roughly 30-40% of Exam Level and Hard questions, include an optional "scenario" field with 1-2 short sentences (max ~30 words) of real-world setup BEFORE the question is asked. This mirrors real N10-009 exam framing ("A technician is configuring...", "A user reports...", "An administrator notices...").
- CRITICAL RULE — scenario describes the ENVIRONMENT the answer depends on; it NEVER restates the subject of the question in technical terms. ❌ "Consider a Layer 2 switch..." inside a question that asks which layer a switch operates at (this telegraphs the answer). ✅ "A technician sees frames being forwarded between hosts on the same subnet but traffic never leaves the local broadcast domain." (forces the learner to reason).
- Scenario should help DISAMBIGUATE context that makes one answer clearly right, not give the answer away.
- DO NOT include scenario on: pure recall questions (what port is HTTPS? which protocol uses X?), acronym definitions, or Foundational difficulty. Scenario adds noise on those.
- Omit the field entirely for questions that don't need it — don't set it to empty string.
`;

  const buildPrompt = (includeScenario) => `You are a CompTIA Network+ N10-009 exam question writer. You ONLY write questions that map to the official N10-009 exam objectives. Never write questions about content outside the N10-009 blueprint.

${topicStr}${mixedDistributionStr}
Difficulty: ${diffStr}
${exemplarBlock}${retentionBlock}${staleBlock}
Generate exactly ${n} multiple choice questions. Requirements:
- 4 options each (or 5 for multi-select): A, B, C, D (E for multi-select)
- One correct answer only (unless multi-select)
- Distractors must be plausible - never obviously wrong
- Vary the correct answer letter across questions
- Each explanation must state WHY the answer is correct AND briefly why the main wrong option is wrong (2-3 sentences max)
- No repeated questions
${includeScenario ? scenarioInstructions : ''}
MANDATORY N10-009 OBJECTIVE TAGGING:
- Every question MUST include an "objective" field with the CompTIA N10-009 exam objective number (format "X.Y" — e.g., "1.4", "2.1", "4.3", "5.1")
- Valid objectives are 1.1–1.8 (Concepts), 2.1–2.4 (Implementation), 3.1–3.5 (Operations), 4.1–4.5 (Security), 5.1–5.5 (Troubleshooting)
- If you cannot map the question to a specific N10-009 objective, do NOT write the question — write a different one that does map${expectedObj ? `\n- For this topic, use objective "${expectedObj}" (or an adjacent sub-objective in the same domain if more appropriate)` : ''}
${pbqInstructions}

CRITICAL — SELF-VERIFICATION PROTOCOL (you MUST follow these steps for EVERY question):
Step 1: Write the question and all options.
Step 2: INDEPENDENTLY determine which option is factually correct by reasoning through the networking concept. Do NOT just pick a letter — think through WHY.
Step 3: Set the "answer" field to the letter of the option you verified in Step 2.
Step 4: Write the explanation referencing that SAME letter and option text.
Step 5: CROSS-CHECK: Re-read the option text at your chosen answer letter. Does it match what your explanation says? If not, fix the answer field.
Step 6: PREMISE-ANSWER CONSISTENCY CHECK: Re-read the question stem. Does the correct answer CONTRADICT any fact explicitly stated in the stem? If the stem says "both devices are on VLAN 30", the answer CANNOT be "they are on different VLANs." If you find a contradiction, rewrite the question or change the answer so the stem and answer are logically consistent.

MANDATORY RULES:
- The "answer" field must ALWAYS match the letter whose option text is factually correct
- The "explanation" must explicitly reference why the correct option is right and why at least one wrong option is wrong
- If you notice ANY mismatch between answer letter, option text, and explanation — fix it before outputting
- Never output a question where the explanation and the answer field disagree
- NEVER write a question where the correct answer contradicts a fact stated in the question stem. If the question says something IS the case, the answer cannot say it ISN'T. This is the most common AI question-writing error — check for it explicitly.

CONCEPTUAL COHERENCE RULES (v4.57.0 — enforce rigorously):
- Do NOT conflate deprecated classful addressing (Class A/B/C) with modern TCP/IP or CIDR/subnet principles. Classful addressing was obsoleted by CIDR in 1993 (RFC 1519). If you reference classful terminology, it must be explicitly about legacy concepts or historical context — never framed as a "fundamental TCP/IP principle."
- Do NOT conflate distinct concepts under one label. If the stem asks about "a TCP/IP principle," the answer must be about the TCP/IP protocol stack (layers, encapsulation, ports, the four-layer model), not about IP address classes. If the stem asks about "an OSI Layer 3 function," the answer must actually be a Layer 3 function, not a Layer 2 one.
- MATCH THE ABSTRACTION LEVEL: If the stem asks for a "principle," "fundamental concept," or "root cause," the answer must be at that level of abstraction — NOT a specific configuration step or tool. ("Default gateway not configured" is a configuration detail, not a principle.) If the stem asks for a specific fix or symptom, don't give an abstract principle.
- STEM MUST MATCH WHAT THE QUESTION ACTUALLY TESTS: If the stem says "which protocol operates at Layer 3?", the question must test Layer 3 protocol knowledge — not addressing theory, not encapsulation. Read your own stem and make sure the answer directly addresses what you asked.

DISTRACTOR QUALITY RULES:
- At least TWO of the three wrong options must be plausible-enough to tempt a student who only partially knows the material. If 3 of 4 options are obviously wrong (e.g. completely unrelated or factually nonsensical), the question becomes a giveaway that doesn't test real knowledge.
- Distractors should represent common misconceptions, adjacent concepts, or nearly-right answers — not random unrelated facts.

STEM MUST BE AN ACTUAL QUESTION (v4.57.2):
- The "question" field MUST contain a real interrogative, not pure declarative setup. Either end with "?" OR use explicit question words: "which", "what", "why", "how", "when", "where", or CompTIA-style imperatives: "Select the...", "Identify the...", "Choose the...", "Arrange these in order", "Place each device in the correct...", "Match each protocol with...", "Given the scenario, which...".
- ❌ WRONG: "A system administrator is deploying a remote access VPN solution that requires users to authenticate and access corporate resources through a web browser without installing additional VPN client software." (This is pure setup. No question is asked. The learner has no cue what to pick.)
- ✅ RIGHT: "A system administrator is deploying a remote access VPN that must work from any browser without installing client software. **Which VPN type best fits this requirement?**"
- If you want to include setup context, put it in the OPTIONAL "scenario" field — but the "question" field itself MUST still pose a direct question. Scenario + question is additive; scenario is never a substitute for the question.

Respond ONLY with a raw JSON array - no markdown, no extra text:
[{"type":"mcq","question":"...",${includeScenario ? '"scenario":"(optional)",' : ''}"difficulty":"Foundational|Exam Level|Hard","topic":"...","objective":"X.Y","options":{"A":"...","B":"...","C":"...","D":"..."},"answer":"A|B|C|D","explanation":"..."}]`;

  // v4.56.1/v4.56.2: single-attempt helper — does the API call + parse.
  // Takes a model arg (v4.56.2) so the last-ditch fallback can escalate to
  // Sonnet when Haiku fails twice in a row on the same batch. Throws on
  // API-level errors with `.apiError = true`, or on parse failures with
  // `.raw` attached so the caller can log the raw response for diagnosis.
  const attempt = async (prompt, label, model) => {
    const res = await _claudeFetch( {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': key,
        'anthropic-version': '2023-06-01',
        'anthropic-dangerous-direct-browser-access': 'true'
      },
      // _metered: true → counts against the user's daily 20-Q quota.
      // The proxy strips this before forwarding to Anthropic.
      body: JSON.stringify({ model: model || CLAUDE_MODEL, max_tokens: MAX_TOKENS_GENERATION, messages: [{ role: 'user', content: prompt }], _metered: true })
    });
    if (!res.ok) {
      const b = await res.json().catch(() => ({}));
      const apiErr = new Error(b?.error?.message || 'API error ' + res.status);
      apiErr.apiError = true;
      throw apiErr;
    }
    const data = await res.json();
    const raw = data.content?.[0]?.text || '';
    const m = raw.match(/\[[\s\S]*\]/);
    if (!m) {
      const e = new Error(`[${label}] Could not locate JSON array in AI response`);
      e.raw = raw;
      throw e;
    }
    try {
      return { parsed: JSON.parse(m[0]), raw };
    } catch (parseErr) {
      const e = new Error(`[${label}] JSON.parse failed: ${parseErr.message}`);
      e.raw = raw;
      throw e;
    }
  };

  let parsed;
  try {
    parsed = (await attempt(buildPrompt(true), 'haiku-full', CLAUDE_MODEL)).parsed;
  } catch (primaryErr) {
    if (primaryErr.apiError) throw primaryErr;           // API errors don't retry
    _logAiParseFail({ attempt: 'haiku-full', qTopic, difficulty, n, error: primaryErr.message, rawPrefix: (primaryErr.raw || '').slice(0, 600) });
    // v4.56.1: retry once with the scenario block stripped — recovers from the
    // prompt-length-induced malformed-JSON failures we saw on 20-Q Mixed runs.
    try {
      parsed = (await attempt(buildPrompt(false), 'haiku-retry', CLAUDE_MODEL)).parsed;
    } catch (retryErr) {
      if (retryErr.apiError) throw retryErr;
      _logAiParseFail({ attempt: 'haiku-retry', qTopic, difficulty, n, error: retryErr.message, rawPrefix: (retryErr.raw || '').slice(0, 600) });
      // v4.56.2: Sonnet escalation tier. Both Haiku attempts failed — this is
      // the rare hard case where the prompt is just too much for Haiku. Spend
      // the ~5x cost on Sonnet for this one batch and get the right answer.
      // Uses the stripped prompt (no scenario instructions) — keeps the call
      // as light as possible while leveraging the stronger model's JSON
      // consistency. Silent to the user on success; same user-facing error
      // only if Sonnet ALSO fails.
      try {
        if (typeof console !== 'undefined' && console.info) {
          console.info(`[fetchQuestions] escalating batch (${qTopic} / ${difficulty} / n=${n}) to ${CLAUDE_VALIDATOR_MODEL} after both Haiku attempts failed`);
        }
        parsed = (await attempt(buildPrompt(false), 'sonnet-escalation', CLAUDE_VALIDATOR_MODEL)).parsed;
      } catch (sonnetErr) {
        if (sonnetErr.apiError) throw sonnetErr;
        _logAiParseFail({ attempt: 'sonnet-escalation', qTopic, difficulty, n, error: sonnetErr.message, rawPrefix: (sonnetErr.raw || '').slice(0, 600) });
        throw new Error('AI returned malformed data. Please try again.');
      }
    }
  }

  // Normalize: add type:'mcq' if missing. Caching is handled by the outer
  // fetchQuestions coordinator so batched results cache under the original n.
  parsed.forEach(q => { if (!q.type) q.type = 'mcq'; });
  return parsed;
}

// v4.56.1: rolling log of the last 5 AI parse failures from fetchQuestions,
// stored to localStorage for future diagnosis. Used in both the primary and
// retry paths so we can see what Haiku actually returned when a run breaks.
function _logAiParseFail(entry) {
  try {
    const key = STORAGE.AI_PARSE_FAILS;
    const arr = JSON.parse(localStorage.getItem(key) || '[]');
    arr.unshift({ ts: Date.now(), ...entry });
    localStorage.setItem(key, JSON.stringify(arr.slice(0, 5)));
    if (typeof console !== 'undefined' && console.warn) {
      console.warn(`[fetchQuestions] parse fail (${entry.attempt}):`, entry.error, '\nraw prefix:', (entry.rawPrefix || '').slice(0, 200));
    }
  } catch (_) { /* never crash the main flow on a logging error */ }
}

// ══════════════════════════════════════════
// QUESTION TYPE HELPERS
// ══════════════════════════════════════════
function getQType(q) {
  return q.type || 'mcq';
}

// v4.56.0 — Scenario context block helper. Exam-realism practice: real N10-009
// questions lean on scenario framing ("A technician is configuring X..."). We
// render an optional 1-3 sentence context block between the question stem and
// the answer grid. Only fires for MCQ / multi-select types — cli-sim
// and topology already have their own scenario containers inside the options
// box. Rule enforced by authors: scenario describes ENVIRONMENT, never restates
// the subject of the question (avoid the "L2 switch → which layer?" trap).
function _renderScenarioBlock(elId, q, qType) {
  const el = document.getElementById(elId);
  if (!el) return;
  const scenario = typeof q.scenario === 'string' ? q.scenario.trim() : '';
  const isNestedType = qType === 'cli-sim' || qType === 'topology';
  if (!scenario || isNestedType) {
    el.hidden = true;
    el.innerHTML = '';
    return;
  }
  el.hidden = false;
  // escape user-facing text (questions can be AI-generated) — no keyword highlighting
  // here since scenario is setup prose, not the stem that keyword emphasis helps with
  el.innerHTML = '<span class="q-scenario-rule" aria-hidden="true"></span>' +
                 '<span class="q-scenario-body">' + escHtml(scenario) + '</span>';
}

// ══════════════════════════════════════════
// REGULAR QUIZ RENDER
// ══════════════════════════════════════════
function render() {
  const q     = questions[current];
  const total = questions.length;
  const pct   = Math.round((current / total) * 100);
  const qType = getQType(q);

  document.getElementById('live-score').textContent  = `${score} / ${answered}`;
  document.getElementById('live-streak').textContent = `Streak ${streak}`;
  document.getElementById('q-label').textContent     = `Question ${current + 1} of ${total}`;
  document.getElementById('q-pct').textContent       = pct + '%';
  document.getElementById('prog-fill').style.width   = pct + '%';
  document.getElementById('q-num').textContent       = `Q${current + 1}`;
  // v4.54.8: segmented per-question progress dots. State derived from `log` entries.
  _renderQuizProgressDots();

  const badge = document.getElementById('diff-badge');
  const dc    = (q.difficulty || DEFAULT_DIFF).replace(/[^a-zA-Z]/g, '');
  badge.className   = `diff-badge diff-${dc}`;
  badge.textContent = q.difficulty || DEFAULT_DIFF;

  // PBQ badge
  const pbqBadge = document.getElementById('pbq-badge');
  if (pbqBadge) {
    if (qType === 'multi-select') { pbqBadge.textContent = 'Multi-Select'; pbqBadge.classList.remove('is-hidden'); }
    else if (qType === 'order') { pbqBadge.textContent = 'Ordering'; pbqBadge.classList.remove('is-hidden'); }
    else if (qType === 'cli-sim') { pbqBadge.textContent = 'CLI Sim'; pbqBadge.classList.remove('is-hidden'); }
    else if (qType === 'topology') { pbqBadge.textContent = 'Topology'; pbqBadge.classList.remove('is-hidden'); }
    else if (qType === 'hot-area') {
      // v4.83.0 — sub-shape-aware label
      const sub = q.subShape === 'osi' ? 'OSI' : q.subShape === 'cable-grid' ? 'Cable' : 'Topology';
      pbqBadge.textContent = 'Hot Area · ' + sub;
      pbqBadge.classList.remove('is-hidden');
    }
    else { pbqBadge.classList.add('is-hidden'); }
  }

  setQuestionText(document.getElementById('q-text'), q.question);

  // v4.56.0 — optional scenario context block. Only rendered for MCQ / multi-select /
  // order types; cli-sim and topology already render their own scenario container
  // inside the options box via renderCliSim/renderTopology, so skip to avoid doubling.
  _renderScenarioBlock('q-scenario', q, qType);

  // Flag button
  const flagBtn = document.getElementById('quiz-flag-btn');
  flagBtn.className = 'flag-btn' + (quizFlags[current] ? ' flagged' : '');
  flagBtn.textContent = quizFlags[current] ? 'Flagged' : 'Flag';
  flagBtn.setAttribute('aria-pressed', quizFlags[current] ? 'true' : 'false');

  const box = document.getElementById('options');
  box.innerHTML = '';

  if (qType === 'multi-select') {
    renderMultiSelect(q, box);
  } else if (qType === 'order') {
    renderOrder(q, box);
  } else if (qType === 'cli-sim') {
    renderCliSim(q, box);
  } else if (qType === 'topology') {
    renderTopology(q, box);
  } else if (qType === 'hot-area') {
    // v4.83.0 — hot-area click-on-diagram PBQ
    renderHotArea(q, box);
  } else {
    renderMCQ(q, box);
  }

  const expBox = document.getElementById('exp-box');
  expBox.className = 'explanation-box';
  expBox.classList.add('is-hidden');

  const btnNext = document.getElementById('btn-next');
  btnNext.className = 'btn-next';
  btnNext.textContent = current === total - 1 ? 'See Results' : 'Next \u2192';
  btnNext.onclick = current === total - 1 ? finish : advance;

  // v4.44.0 — question reveal: re-trigger the .q-text-reveal + .option-stagger-in
  // animations on every new question by removing the class, forcing reflow, then
  // re-adding. Without the reflow the browser coalesces the class toggle and the
  // animation doesn't re-fire. Options get a per-index animation-delay so they
  // stagger in one after the other rather than all-at-once.
  const qTextEl = document.getElementById('q-text');
  if (qTextEl) {
    qTextEl.classList.remove('q-text-reveal');
    void qTextEl.offsetWidth;
    qTextEl.classList.add('q-text-reveal');
  }
  const allOptionEls = box.querySelectorAll('.option, .ms-option, .order-item');
  allOptionEls.forEach((el, i) => {
    el.classList.remove('option-stagger-in');
    el.style.animationDelay = '';
    void el.offsetWidth;
    el.style.animationDelay = (i * 80) + 'ms';
    el.classList.add('option-stagger-in');
  });

  // v4.82.0: refresh score/streak header (in case re-pick recomputed them)
  // and refresh prev/next arrow enabled-state.
  _recomputeQuizCounters();
  _renderQuizNavArrows();

  // v4.82.0: if this question is already in the log, restore its answered-
  // state UI on top of the pristine render — markers, explanation, revisit
  // banner, and re-enabled inputs so the user can re-pick.
  const existingEntry = _findLogEntryFor(q);
  if (existingEntry) {
    _restoreAnsweredQuizState(q, existingEntry.entry);
    _renderRevisitBanner(true);
    const qLabelEl = document.getElementById('q-label');
    if (qLabelEl) qLabelEl.textContent = `Question ${current + 1} of ${total} · revisiting`;
  } else {
    _renderRevisitBanner(false);
  }

  // Focus the question text for screen readers, first option for keyboard users
  setTimeout(() => {
    const firstOption = box.querySelector('.option, .ms-option, .order-item, button');
    if (firstOption) firstOption.focus();
  }, 150);
}

// v4.82.0: restore the answered-state UI on top of a pristine render. Walks
// the just-rendered options and applies correct/wrong/reveal-correct/dimmed
// markers based on q's answer key + entry.chosen. Crucially does NOT
// disable the option click handlers — re-picks are allowed. Then surfaces
// showExplanation so the user sees their previous outcome + the correct
// answer + the explanation. Submit buttons for PBQ types are kept visible
// so the user can re-submit after re-arranging.
function _restoreAnsweredQuizState(q, entry) {
  if (!q || !entry) return;
  const qType = getQType(q);
  const box = document.getElementById('options');
  if (!box) return;
  // Tag the options container so CSS can re-enable clickable affordance.
  box.classList.add('is-revisiting');

  if (qType === 'mcq' || qType === 'cli-sim') {
    const chosen = entry.chosen;
    const correct = q.answer;
    const optionEls = box.querySelectorAll('.option');
    optionEls.forEach((btn, i) => {
      const l = ['A', 'B', 'C', 'D'][i];
      btn.classList.remove('correct', 'wrong', 'reveal-correct', 'dimmed');
      if (l === correct && l === chosen) btn.classList.add('correct');
      else if (l === chosen && l !== correct) btn.classList.add('wrong');
      else if (l === correct) btn.classList.add('reveal-correct');
      else btn.classList.add('dimmed');
    });
    if (qType === 'cli-sim') {
      const diag = document.getElementById('cli-diagnosis');
      if (diag) diag.classList.remove('is-hidden');
    }
  } else if (qType === 'multi-select') {
    const chosenSet = new Set((entry.chosen || '').split(',').filter(Boolean));
    const correctSet = new Set(q.answers || []);
    msSelections = [...chosenSet];
    const optBtns = box.querySelectorAll('.option');
    optBtns.forEach(btn => {
      const l = btn.dataset.letter;
      if (!l) return;
      btn.classList.remove('correct', 'wrong', 'reveal-correct', 'dimmed', 'ms-selected');
      const cb = btn.querySelector('.ms-checkbox');
      if (chosenSet.has(l)) { btn.classList.add('ms-selected'); if (cb) cb.textContent = '✓'; }
      else if (cb) cb.textContent = '';
      if (correctSet.has(l) && chosenSet.has(l)) btn.classList.add('correct');
      else if (chosenSet.has(l) && !correctSet.has(l)) btn.classList.add('wrong');
      else if (correctSet.has(l)) btn.classList.add('reveal-correct');
      else btn.classList.add('dimmed');
    });
    const submitBtn = document.getElementById('ms-submit-btn');
    if (submitBtn) {
      submitBtn.classList.remove('is-hidden');
      const reqCount = (q.answers || []).length || 2;
      submitBtn.disabled = msSelections.length !== reqCount;
      submitBtn.classList.toggle('is-dimmed', submitBtn.disabled);
    }
  } else if (qType === 'order') {
    const chosen = (entry.chosen || '').split(',').filter(Boolean).map(Number);
    orderSequence = chosen.slice();
    const items = q.items || [];
    document.querySelectorAll('#order-items .order-item').forEach(btn => {
      const idx = parseInt(btn.dataset.idx);
      btn.classList.toggle('placed', orderSequence.includes(idx));
    });
    const list = document.getElementById('order-placed-list');
    if (list) {
      if (orderSequence.length === 0) {
        list.innerHTML = '<span style="color:var(--text-dim);font-size:13px">Click items above in the correct order</span>';
      } else {
        list.innerHTML = orderSequence.map((idx, pos) =>
          `<div class="order-placed-item"><span class="order-placed-num">${pos + 1}</span>${escHtml(items[idx])}</div>`
        ).join('');
      }
    }
    const submitBtn = document.getElementById('order-submit-btn');
    if (submitBtn) {
      submitBtn.classList.remove('is-hidden');
      submitBtn.disabled = orderSequence.length !== items.length;
      submitBtn.classList.toggle('is-dimmed', submitBtn.disabled);
    }
  } else if (qType === 'topology') {
    try { topoDevices = JSON.parse(entry.chosen || '{}'); }
    catch (_) { topoDevices = {}; }
    const zones = q.zones || [];
    zones.forEach(zone => {
      const zoneId = 'topo-zone-' + zone.replace(/[^a-zA-Z0-9]/g, '-');
      const el = document.getElementById(zoneId);
      if (!el) return;
      const placed = topoDevices[zone] || [];
      el.innerHTML = placed.map(d => `<span class="topo-placed">${escHtml(d)}</span>`).join('');
    });
    const submitBtn = document.getElementById('topo-submit-btn');
    if (submitBtn) submitBtn.classList.remove('is-hidden');
    const resetBtn = document.querySelector('.topo-controls .btn-ghost');
    if (resetBtn) resetBtn.classList.remove('is-hidden');
  } else if (qType === 'hot-area') {
    // v4.83.0 — hot-area revisit: re-apply reveal markers based on stored entry
    _restoreAnsweredHotAreaState(q, entry);
  }

  // Show explanation populated from THIS log entry (not log[log.length-1] which
  // is the most-recently-pushed entry — could be a different question now).
  showExplanation(q, entry.isRight, entry);
}

// ── MCQ Render (unified quiz + exam mode) ──
function renderMCQ(q, box, ans) {
  box.setAttribute('role', 'radiogroup');
  box.setAttribute('aria-label', 'Answer options');
  ['A','B','C','D'].forEach(l => {
    const btn = document.createElement('button');
    const isSelected = ans && ans.chosen === l;
    btn.className = 'option' + (isSelected ? ' exam-selected' : '');
    btn.setAttribute('role', 'radio');
    btn.setAttribute('aria-checked', isSelected ? 'true' : 'false');
    btn.setAttribute('aria-label', `Option ${l}: ${q.options[l]}`);
    btn.innerHTML = `<span class="opt-letter">${l}</span><span class="opt-text">${escHtml(q.options[l])}</span>`;
    if (ans) {
      btn.onclick = () => { examAnswers[examCurrent].chosen = l; renderExam(); };
    } else {
      btn.onclick = () => pick(l, q);
    }
    box.appendChild(btn);
  });
}

// ── Multi-Select Render (unified quiz + exam mode) ──
function renderMultiSelect(q, box, ans) {
  const letters = Object.keys(q.options).sort();
  const reqCount = (q.answers || []).length || 2;
  if (!ans) msSelections = [];

  letters.forEach(l => {
    const btn = document.createElement('button');
    const isSelected = ans ? ans.msChosen.includes(l) : false;
    btn.className = 'option' + (isSelected ? ' ms-selected' : '');
    btn.dataset.letter = l;
    btn.setAttribute('role', 'checkbox');
    btn.setAttribute('aria-checked', isSelected ? 'true' : 'false');
    btn.setAttribute('aria-label', `Option ${l}: ${q.options[l]}`);
    btn.innerHTML = `<span class="ms-checkbox">${isSelected ? '\u2713' : ''}</span><span class="opt-text">${escHtml(q.options[l])}</span>`;
    btn.onclick = () => {
      if (ans) {
        const idx = ans.msChosen.indexOf(l);
        if (idx >= 0) ans.msChosen.splice(idx, 1);
        else ans.msChosen.push(l);
        renderExam();
      } else {
        // v4.82.0: removed the post-submit click-guard so re-picks are
        // possible during revisit. submitMultiSelect's update-branch
        // handles truth-up.
        const idx = msSelections.indexOf(l);
        if (idx >= 0) {
          msSelections.splice(idx, 1);
          btn.classList.remove('ms-selected');
          btn.querySelector('.ms-checkbox').textContent = '';
          btn.setAttribute('aria-checked', 'false');
        } else {
          msSelections.push(l);
          btn.classList.add('ms-selected');
          btn.querySelector('.ms-checkbox').textContent = '\u2713';
          btn.setAttribute('aria-checked', 'true');
        }
        updateMsSubmitBtn(reqCount);
      }
    };
    box.appendChild(btn);
  });

  if (ans) {
    // Exam: selection hint only
    const hint = document.createElement('div');
    hint.className = 'ms-hint';
    hint.style.marginTop = '8px';
    hint.textContent = `Select ${reqCount} answers (${ans.msChosen.length} selected)`;
    box.appendChild(hint);
  } else {
    // Quiz: submit row
    const row = document.createElement('div');
    row.className = 'ms-submit-row';
    row.innerHTML = `<span class="ms-hint">Select ${reqCount} answers</span>`;
    const submitBtn = document.createElement('button');
    submitBtn.className = 'btn btn-primary';
    submitBtn.id = 'ms-submit-btn';
    submitBtn.textContent = 'Submit';
    submitBtn.disabled = true;
    submitBtn.classList.add('is-dimmed');
    submitBtn.onclick = () => submitMultiSelect(q);
    row.appendChild(submitBtn);
    box.appendChild(row);
  }
}

function updateMsSubmitBtn(reqCount) {
  const btn = document.getElementById('ms-submit-btn');
  if (!btn) return;
  const ready = msSelections.length === reqCount;
  btn.disabled = !ready;
  btn.classList.toggle('is-dimmed', !ready);
}

function submitMultiSelect(q) {
  const correctAnswers = (q.answers || []).sort();
  const chosen = [...msSelections].sort();
  const isRight = JSON.stringify(chosen) === JSON.stringify(correctAnswers);
  const existing = _findLogEntryFor(q);

  if (existing) {
    // v4.82.0: re-submit path — update existing entry, recompute counters, truth-up wrong-bank
    const wasRight = existing.entry.isRight === true;
    log[existing.idx] = { q, chosen: chosen.join(','), correct: correctAnswers.join(','), isRight, flagged: quizFlags[current] };
    if (!isRight && wasRight) addToWrongBank(q, chosen.join(','));
    else if (isRight && !wasRight) graduateFromBank(q.question);
    _recomputeQuizCounters();
  } else {
    answered++;
    updateTypeStat('multi-select', isRight);
    if (isRight) { score++; streak++; if (streak > bestStreak) bestStreak = streak; }
    else { streak = 0; }
    log.push({ q, chosen: chosen.join(','), correct: correctAnswers.join(','), isRight, flagged: quizFlags[current] });
    if (!isRight) addToWrongBank(q, chosen.join(','));
    else if (wrongDrillMode) graduateFromBank(q.question);
    document.getElementById('live-score').textContent = `${score} / ${answered}`;
    const streakEl = document.getElementById('live-streak');
    streakEl.textContent = `Streak ${streak}`;
  }

  // Highlight options. v4.82.0: don't disable — re-picks via toggle remain possible.
  const optBtns = document.querySelectorAll('#options .option');
  optBtns.forEach(btn => {
    const l = btn.dataset.letter;
    if (!l) return;
    btn.classList.remove('correct', 'wrong', 'reveal-correct', 'dimmed');
    if (correctAnswers.includes(l) && chosen.includes(l)) btn.classList.add('correct');
    else if (chosen.includes(l) && !correctAnswers.includes(l)) btn.classList.add('wrong');
    else if (correctAnswers.includes(l)) btn.classList.add('reveal-correct');
    else btn.classList.add('dimmed');
  });

  // v4.82.0: keep the options container tagged for revisit affordance.
  const optionsBox = document.getElementById('options');
  if (optionsBox) optionsBox.classList.add('is-revisiting');

  // v4.82.0: keep submit button visible (re-submittable). It re-disables based
  // on whether selection still matches reqCount when user toggles.
  const submitBtn = document.getElementById('ms-submit-btn');
  if (submitBtn) submitBtn.classList.remove('is-hidden');

  _renderQuizProgressDots();
  _renderQuizNavArrows();

  const currentEntry = _findLogEntryFor(q);
  showExplanation(q, isRight, currentEntry ? currentEntry.entry : null);
}

// ── Order Render (unified quiz + exam mode) ──
function renderOrder(q, box, ans) {
  const items = q.items || [];
  if (!ans) orderSequence = [];
  const currentSeq = () => ans ? ans.orderSeq : orderSequence;

  // Items to pick from
  const itemsDiv = document.createElement('div');
  itemsDiv.className = 'order-items';
  itemsDiv.id = 'order-items';

  items.forEach((item, idx) => {
    const btn = document.createElement('button');
    btn.className = 'order-item' + (currentSeq().includes(idx) ? ' placed' : '');
    btn.dataset.idx = idx;
    btn.setAttribute('aria-label', `Item ${idx + 1}: ${item}`);
    btn.innerHTML = `<span class="order-num">${idx + 1}</span><span class="order-item-text">${escHtml(item)}</span>`;
    btn.onclick = () => {
      if (ans) {
        if (!ans.orderSeq.includes(idx)) { ans.orderSeq.push(idx); renderExam(); }
      } else {
        addToOrderSequence(idx, items, q);
      }
    };
    itemsDiv.appendChild(btn);
  });
  box.appendChild(itemsDiv);

  // Sequence display
  const seqDiv = document.createElement('div');
  seqDiv.className = 'order-sequence';
  if (ans) {
    let seqHtml = '<h4>Your Order:</h4><div class="order-placed-list">';
    if (ans.orderSeq.length === 0) {
      seqHtml += '<span style="color:var(--text-dim);font-size:13px">Click items above in order</span>';
    } else {
      seqHtml += ans.orderSeq.map((idx, pos) =>
        `<div class="order-placed-item"><span class="order-placed-num">${pos + 1}</span>${escHtml(items[idx])}</div>`
      ).join('');
    }
    seqHtml += '</div>';
    seqDiv.innerHTML = seqHtml;
  } else {
    seqDiv.innerHTML = '<h4>Your Order:</h4><div class="order-placed-list" id="order-placed-list"><span style="color:var(--text-dim);font-size:13px">Click items above in the correct order</span></div>';
  }
  box.appendChild(seqDiv);

  // Controls
  if (ans) {
    const resetBtn = document.createElement('button');
    resetBtn.className = 'btn btn-ghost';
    resetBtn.style.cssText = 'font-size:13px;margin-top:8px';
    resetBtn.textContent = 'Reset Order';
    resetBtn.onclick = () => { ans.orderSeq = []; renderExam(); };
    box.appendChild(resetBtn);
  } else {
    const controls = document.createElement('div');
    controls.className = 'order-controls';
    const resetBtn = document.createElement('button');
    resetBtn.className = 'btn btn-ghost';
    resetBtn.style.fontSize = '13px';
    resetBtn.textContent = 'Reset';
    resetBtn.onclick = () => { orderSequence = []; renderOrderState(items, q); };
    controls.appendChild(resetBtn);

    const submitBtn = document.createElement('button');
    submitBtn.className = 'btn btn-primary';
    submitBtn.id = 'order-submit-btn';
    submitBtn.textContent = 'Submit Order';
    submitBtn.disabled = true;
    submitBtn.classList.add('is-dimmed');
    submitBtn.onclick = () => submitOrder(q);
    controls.appendChild(submitBtn);
    box.appendChild(controls);
  }
}

function addToOrderSequence(idx, items, q) {
  if (orderSequence.includes(idx)) return;
  orderSequence.push(idx);
  renderOrderState(items, q);
}

function renderOrderState(items, q) {
  // Update item buttons
  const itemBtns = document.querySelectorAll('#order-items .order-item');
  itemBtns.forEach(btn => {
    const idx = parseInt(btn.dataset.idx);
    btn.classList.toggle('placed', orderSequence.includes(idx));
  });

  // Update placed list
  const list = document.getElementById('order-placed-list');
  if (orderSequence.length === 0) {
    list.innerHTML = '<span style="color:var(--text-dim);font-size:13px">Click items above in the correct order</span>';
  } else {
    list.innerHTML = orderSequence.map((idx, pos) =>
      `<div class="order-placed-item"><span class="order-placed-num">${pos + 1}</span>${escHtml(items[idx])}</div>`
    ).join('');
  }

  // Update submit button
  const btn = document.getElementById('order-submit-btn');
  if (btn) {
    const ready = orderSequence.length === items.length;
    btn.disabled = !ready;
    btn.classList.toggle('is-dimmed', !ready);
  }
}

function submitOrder(q) {
  const correctOrder = q.correctOrder || [];
  const isRight = JSON.stringify(orderSequence) === JSON.stringify(correctOrder);
  const existing = _findLogEntryFor(q);

  if (existing) {
    // v4.82.0: re-submit path
    const wasRight = existing.entry.isRight === true;
    log[existing.idx] = { q, chosen: orderSequence.join(','), correct: correctOrder.join(','), isRight, flagged: quizFlags[current] };
    if (!isRight && wasRight) addToWrongBank(q, orderSequence.join(','));
    else if (isRight && !wasRight) graduateFromBank(q.question);
    _recomputeQuizCounters();
  } else {
    answered++;
    updateTypeStat('order', isRight);
    if (isRight) { score++; streak++; if (streak > bestStreak) bestStreak = streak; }
    else { streak = 0; }
    log.push({ q, chosen: orderSequence.join(','), correct: correctOrder.join(','), isRight, flagged: quizFlags[current] });
    if (!isRight) addToWrongBank(q, orderSequence.join(','));
    else if (wrongDrillMode) graduateFromBank(q.question);
    document.getElementById('live-score').textContent = `${score} / ${answered}`;
    const streakEl = document.getElementById('live-streak');
    streakEl.textContent = `Streak ${streak}`;
  }

  // v4.82.0: keep items + submit button clickable so user can re-arrange + re-submit.
  // (Previous behavior was to disable everything after first submit.)
  document.querySelectorAll('#order-items .order-item').forEach(btn => { btn.style.pointerEvents = ''; });
  const orderSubmitBtn = document.getElementById('order-submit-btn');
  if (orderSubmitBtn) orderSubmitBtn.classList.remove('is-hidden');
  const orderResetBtn = document.querySelector('.order-controls .btn-ghost');
  if (orderResetBtn) orderResetBtn.classList.remove('is-hidden');
  const optionsBox = document.getElementById('options');
  if (optionsBox) optionsBox.classList.add('is-revisiting');
  _renderQuizProgressDots();
  _renderQuizNavArrows();

  // Show correct vs wrong in placed list
  const items = q.items || [];
  const list = document.getElementById('order-placed-list');
  if (isRight) {
    // All correct — show green ticks
    list.innerHTML = orderSequence.map((idx, pos) => {
      return `<div class="order-placed-item order-correct"><span class="order-placed-num">${pos + 1}</span>${escHtml(items[idx])} \u2713</div>`;
    }).join('');
  } else {
    // Wrong — show user's order with X marks, then animate to correct order
    list.innerHTML = orderSequence.map((idx, pos) => {
      const isCorrectPos = correctOrder[pos] === idx;
      return `<div class="order-placed-item ${isCorrectPos ? 'order-correct' : 'order-wrong'}"><span class="order-placed-num">${pos + 1}</span>${escHtml(items[idx])} ${isCorrectPos ? '\u2713' : '\u2717'}</div>`;
    }).join('');
    // After a brief pause, reorder to show the CORRECT sequence
    setTimeout(() => {
      list.innerHTML = '<div class="order-correct-label">\u2705 Correct order:</div>' +
        correctOrder.map((idx, pos) => {
          const wasCorrect = orderSequence[pos] === idx;
          return `<div class="order-placed-item order-reveal${wasCorrect ? '' : ' order-highlight'}"><span class="order-placed-num">${pos + 1}</span>${escHtml(items[idx])}</div>`;
        }).join('');
    }, 1500);
  }

  const submittedEntry = _findLogEntryFor(q);
  showExplanation(q, isRight, submittedEntry ? submittedEntry.entry : null);
}

// ══════════════════════════════════════════
// ANSWER SELECTION (MCQ)
// ══════════════════════════════════════════
function pick(chosen, q) {
  // v4.82.0: previously this guarded against re-picks via DOM state
  // (`document.querySelector('#options .option.correct, .option.wrong')`),
  // which made re-picks silently noop. Replaced with a proper revisit path:
  // if a log entry already exists for this question, UPDATE it instead of
  // pushing a new entry, then truth-up score/answered/wrong-bank.
  const isRight = chosen === q.answer;
  const existing = _findLogEntryFor(q);

  if (existing) {
    // ── Re-pick path: update existing log entry, recompute counters, truth-up wrong-bank ──
    const wasRight = existing.entry.isRight === true;
    log[existing.idx] = { q, chosen, correct: q.answer, isRight, flagged: quizFlags[current] };
    // Wrong-bank truth-up: reflect current answer truth, not first-attempt
    if (!isRight && wasRight) addToWrongBank(q, chosen);
    else if (isRight && !wasRight) graduateFromBank(q.question);
    // Recompute score + answered from log; streak intentionally untouched
    _recomputeQuizCounters();
  } else {
    // ── First-pick path (existing behavior) ──
    answered++;
    updateTypeStat(q.type || 'mcq', isRight);
    if (isRight) { score++; streak++; if (streak > bestStreak) bestStreak = streak; }
    else { streak = 0; }
    log.push({ q, chosen, correct: q.answer, isRight, flagged: quizFlags[current] });
    if (!isRight) addToWrongBank(q, chosen);
    else if (wrongDrillMode) graduateFromBank(q.question);
    document.getElementById('live-score').textContent = `${score} / ${answered}`;
    const streakEl = document.getElementById('live-streak');
    streakEl.textContent = `Streak ${streak}`;
    streakEl.classList.remove('streak-pop');
    void streakEl.offsetWidth;
    if (isRight && streak > 1) streakEl.classList.add('streak-pop');
  }

  // Walk option buttons: apply markers WITHOUT disabling so re-picks remain possible.
  document.querySelectorAll('#options .option').forEach((btn, i) => {
    const l = ['A','B','C','D'][i];
    btn.classList.remove('correct', 'wrong', 'reveal-correct', 'dimmed');
    if (l === q.answer && l === chosen)      btn.classList.add('correct');
    else if (l === chosen && !isRight)       btn.classList.add('wrong');
    else if (l === q.answer)                 btn.classList.add('reveal-correct');
    else                                     btn.classList.add('dimmed');
  });

  // v4.82.0: keep the options container tagged for the revisit affordance
  // so future re-picks render with the right cursor/hover styling.
  const optionsBox = document.getElementById('options');
  if (optionsBox) optionsBox.classList.add('is-revisiting');

  // Refresh dot strip + nav arrow state since the log changed.
  _renderQuizProgressDots();
  _renderQuizNavArrows();

  // Pass the current entry to showExplanation so the wrong-explain block
  // reads the right chosen-letter (not log[log.length-1] which could be a
  // different question if user is revisiting).
  const currentEntry = _findLogEntryFor(q);
  showExplanation(q, isRight, currentEntry ? currentEntry.entry : null);
}

function showExplanation(q, isRight, entryOverride) {
  const expBox = document.getElementById('exp-box');
  const qType = getQType(q);
  let label;
  if (qType === 'multi-select') {
    label = isRight ? 'Correct!' : `Wrong \u2014 correct answers: ${(q.answers || []).join(', ')}`;
  } else if (qType === 'order') {
    label = isRight ? 'Correct order!' : 'Wrong order \u2014 see correct positions above';
  } else {
    label = isRight ? 'Correct!' : `Wrong \u2014 correct answer: ${q.answer}`;
  }
  document.getElementById('exp-label').textContent = label;
  document.getElementById('exp-text').textContent  = q.explanation;
  // v4.54.8: per-choice wrongExplain paragraph. If the question carries a
  // wrongExplain map keyed by option letter AND the user picked one of them,
  // surface the targeted explanation as an italic muted block.
  // v4.82.0: prefer entryOverride (passed by re-pick + restore paths) so we
  // read THIS question's chosen letter, not log[log.length-1] which could be
  // a different question's entry when user is revisiting.
  const wrongExplainEl = document.getElementById('exp-wrong-explain');
  if (wrongExplainEl) {
    const sourceEntry = entryOverride || ((Array.isArray(log) && log.length > 0) ? log[log.length - 1] : null);
    const chosenLetter = sourceEntry ? sourceEntry.chosen : null;
    const pickExplain = (q.wrongExplain && typeof q.wrongExplain === 'object') ? q.wrongExplain[chosenLetter] : null;
    if (!isRight && pickExplain && typeof pickExplain === 'string') {
      wrongExplainEl.textContent = `On your choice (${chosenLetter}): ${pickExplain}`;
      wrongExplainEl.classList.remove('is-hidden');
    } else {
      wrongExplainEl.textContent = '';
      wrongExplainEl.classList.add('is-hidden');
    }
  }

  // Resource link — opens in-app Topic Deep Dive
  const qTopic = q.topic || activeQuizTopic;
  const res = topicResources[qTopic];
  let extraHtml = '';
  if (res) {
    extraHtml += '<div class="resource-link"><button class="resource-dive-btn" onclick="showTopicDeepDive(\'' + escHtml(qTopic).replace(/'/g, "\\'") + '\')">Study: ' + escHtml(res.title) + ' (Obj ' + res.obj + ')</button></div>';
  }

  // Explain Further button (Enhancement 5)
  extraHtml += '<button class="explain-btn" onclick="explainFurther()">Explain Further</button>';
  // v4.54.17: on wrong answers, offer a "Drill this concept" button that
  // injects 2 follow-up questions into the current session immediately
  // after the current question.
  if (!isRight && typeof followUpOnMistake === 'function') {
    extraHtml += '<button class="explain-btn explain-btn-followup" onclick="followUpOnMistake()">Drill this concept</button>';
  }

  // Report button
  const reportCount = getReportCount(q.question);
  if (reportCount > 0) {
    extraHtml += '<button class="report-btn reported" disabled>Reported (' + reportCount + ')</button>';
  } else {
    extraHtml += '<button class="report-btn" onclick="reportIssue()">Report Issue</button>';
  }

  // Clean up previous extra HTML (resource links, buttons) before inserting new
  const expTextEl = document.getElementById('exp-text');
  while (expTextEl.nextSibling) expTextEl.parentNode.removeChild(expTextEl.nextSibling);
  const deepEl = document.getElementById('deep-explain');
  if (deepEl) deepEl.remove();
  expTextEl.insertAdjacentHTML('afterend', extraHtml);

  expBox.className   = 'explanation-box show ' + (isRight ? 'correct' : 'wrong');
  expBox.classList.remove('is-hidden');
  const nextBtn = document.getElementById('btn-next');
  nextBtn.classList.add('show');
  // Focus the Next button for keyboard users
  setTimeout(() => nextBtn.focus(), 100);
}

function advance() { current++; render(); window.scrollTo(0,0); }

function toggleFlag() {
  quizFlags[current] = !quizFlags[current];
  const flagBtn = document.getElementById('quiz-flag-btn');
  flagBtn.className = 'flag-btn' + (quizFlags[current] ? ' flagged' : '');
  flagBtn.textContent = quizFlags[current] ? 'Flagged' : 'Flag';
}

// ══════════════════════════════════════════
// REGULAR QUIZ RESULTS
// ══════════════════════════════════════════
// Build the per-difficulty score breakdown shown on the results page.
// Extracted from finish() (#18) so the parent function fits the long-function budget.
function renderResultsDifficultyBreakdown() {
  const byDiff = {};
  log.forEach(entry => {
    const d = (entry.q.difficulty || DEFAULT_DIFF).trim();
    if (!byDiff[d]) byDiff[d] = { right: 0, total: 0 };
    byDiff[d].total++;
    if (entry.isRight) byDiff[d].right++;
  });
  const diffOrder = ['Foundational', 'Exam Level', 'Hard / Tricky', 'Hard', 'Mixed'];
  const diffColors = { 'Foundational': 'var(--blue)', 'Exam Level': 'var(--yellow)', 'Hard / Tricky': 'var(--red)', 'Hard': 'var(--red)', 'Mixed': 'var(--accent-light)' };
  const diffEl = document.getElementById('diff-breakdown');
  const diffKeys = diffOrder.filter(d => byDiff[d]);
  diffEl.innerHTML = diffKeys.length > 1 ? diffKeys.map(d => {
    const { right, total: t } = byDiff[d];
    const col = diffColors[d] || 'var(--text)';
    const shortLabel = d.replace(' / Tricky', '').replace('Foundational', 'Basic');
    return `<div class="dstat"><div class="dv" style="color:${col}">${right}/${t}</div><div class="dl">${shortLabel}</div></div>`;
  }).join('') : '';
}

function finish() {
  // v4.42.0: snapshot streak BEFORE updateStreak so we can detect an
  // increment and flag a pulse animation for the next goSetup() render.
  const _prevStreakBefore = (function(){ try { return getStreak().current || 0; } catch (_) { return 0; } })();
  const total = questions.length;
  const pct   = total > 0 ? Math.round((score / total) * 100) : 0;
  const grade = pct >= 90 ? 'A' : pct >= 80 ? 'B' : pct >= 70 ? 'C' : pct >= 60 ? 'D' : 'F';
  const gradeColor = { A:'#22c55e', B:'#60a5fa', C:'#fbbf24', D:'#fb923c', F:'#f87171' }[grade];

  // v4.54.3: legacy grade-ring retired from HTML. Keep the writes guarded so
  // if any consumer DOM gets reintroduced elsewhere (e.g. exam results) it still
  // works, but the absence here is a no-op instead of a TypeError.
  const ringFill = document.getElementById('grade-fill');
  if (ringFill) {
    ringFill.style.stroke = gradeColor;
    ringFill.style.strokeDashoffset = '326.73';
    const targetOffset = 326.73 - (326.73 * pct / 100);
    requestAnimationFrame(() => { ringFill.style.strokeDashoffset = targetOffset; });
  }
  const gradeLetterEl = document.getElementById('grade-letter');
  if (gradeLetterEl) {
    gradeLetterEl.textContent = grade;
    gradeLetterEl.style.color = gradeColor;
  }
  const gradePctEl = document.getElementById('grade-pct');
  if (gradePctEl) gradePctEl.textContent = pct + '%';

  // Animated score count-up
  animateCount('r-correct', 0, score, 800);
  animateCount('r-wrong', 0, total - score, 800);
  animateCount('r-streak', 0, bestStreak, 600);

  // v4.54.3: editorial display headings with italic-accent em for the key word.
  // Each row: [headline with <em> accent (innerHTML), lede paragraph].
  // Italic em uses the app-wide accent-light colour via CSS.
  const headlines = {
    A: ['Crushing <em>it.</em>',       "You're exam-ready on this topic."],
    B: ['Solid <em>session.</em>',     'A few gaps \u2014 keep at it.'],
    C: ['Getting <em>there.</em>',     'Review your weak spots and retry.'],
    D: ['Keep <em>studying.</em>',     'Go back to the notes then come back.'],
    F: ['More <em>work needed.</em>',  'Rewatch the Messer videos on this topic.']
  };
  const headlineEl = document.getElementById('result-headline');
  if (headlineEl) headlineEl.innerHTML = headlines[grade][0];
  document.getElementById('result-sub').textContent = headlines[grade][1];
  document.getElementById('r-correct').textContent = score;
  document.getElementById('r-wrong').textContent   = total - score;
  document.getElementById('r-streak').textContent  = bestStreak;

  // v4.54.3 results-v2 additions: scaled score (100-900), verdict line, raw pct.
  // Scaled-score formula matches CompTIA N10-009 convention from the exam-
  // results screen: 100 + (raw / 100) * 800, rounded.
  const scaled = Math.max(100, Math.min(900, Math.round(100 + (pct / 100) * 800)));
  const passed = scaled >= EXAM_PASS_SCORE;
  const scoreEl = document.getElementById('r-v2-score');
  const verdictEl = document.getElementById('r-v2-verdict');
  const rawPctEl = document.getElementById('r-v2-pct');
  if (scoreEl) {
    // Animated count-up from current (or 0) to scaled
    const cur = parseInt(scoreEl.textContent, 10);
    if (typeof animateCount === 'function') {
      animateCount('r-v2-score', isNaN(cur) ? 0 : cur, scaled, 1100);
    } else {
      scoreEl.textContent = scaled;
    }
  }
  if (verdictEl) {
    if (passed) {
      verdictEl.innerHTML = '\u2191 Pass mark cleared \u00b7 ' + EXAM_PASS_SCORE;
      verdictEl.classList.remove('results-v2-verdict-fail');
      verdictEl.classList.add('results-v2-verdict-pass');
    } else {
      const gap = EXAM_PASS_SCORE - scaled;
      verdictEl.innerHTML = `\u2193 ${gap} below pass \u00b7 keep going`;
      verdictEl.classList.remove('results-v2-verdict-pass');
      verdictEl.classList.add('results-v2-verdict-fail');
    }
  }
  if (rawPctEl) rawPctEl.textContent = pct + '%';

  // v4.54.8: elapsed-time row
  const elapsedEl = document.getElementById('r-elapsed');
  if (elapsedEl) {
    const elapsedMs = _sessionStartTs ? (Date.now() - _sessionStartTs) : 0;
    elapsedEl.textContent = _formatElapsed(elapsedMs);
  }

  // v4.54.8: inline "Review \u00b7 Every answer" list + "Drill my mistakes" CTA
  if (typeof _renderResultsReviewList === 'function') _renderResultsReviewList();
  const drillBtn = document.getElementById('btn-drill-mistakes');
  if (drillBtn) {
    const wrongCount = total - score;
    drillBtn.style.display = wrongCount > 0 ? '' : 'none';
    drillBtn.innerHTML = `Drill my ${wrongCount} mistake${wrongCount === 1 ? '' : 's'}`;
  }

  document.getElementById('btn-review').classList.toggle('is-hidden', log.length === 0);

  renderResultsDifficultyBreakdown();

  updateStreak();
  renderStreakBadge();
  // v4.42.0: if the streak incremented, flag a pulse for goSetup() to replay
  // on the newly-visible streak badge. Can't animate here because #page-setup
  // is hidden while we're on the results page.
  try {
    if ((getStreak().current || 0) > _prevStreakBefore) _pendingStreakPulse = true;
  } catch (_) {}

  if (!wrongDrillMode) {
    const entryMode = dailyChallengeMode ? 'daily' : (sessionMode ? 'session' : 'quiz');
    const now = new Date().toISOString();
    // v4.57.1: Multi-topic sessions (selected via Custom Quiz with 2+ chips)
    // used to save ONE history entry under the "Multi: Topic A, Topic B, …"
    // sentinel string. Progress page's `h.filter(e => e.topic === t)` never
    // matched that sentinel against individual topic keys, so every
    // constituent topic showed as "Untouched" despite the user studying it.
    // Fix: split the session into per-topic entries using each question's
    // Haiku-assigned `q.topic` field. Weak-spot scoring, domain-mastery
    // aggregation, and readiness all become more accurate too.
    if (typeof activeQuizTopic === 'string' && activeQuizTopic.startsWith('Multi: ')) {
      const byTopic = {};
      log.forEach(entry => {
        const t = (entry.q && entry.q.topic) || 'Unknown';
        if (!byTopic[t]) byTopic[t] = { total: 0, score: 0 };
        byTopic[t].total++;
        if (entry.isRight) byTopic[t].score++;
      });
      Object.keys(byTopic).forEach(t => {
        const { total: tTotal, score: tScore } = byTopic[t];
        const tPct = tTotal > 0 ? Math.round((tScore / tTotal) * 100) : 0;
        saveToHistory({ date: now, topic: t, difficulty: diff, score: tScore, total: tTotal, pct: tPct, mode: entryMode, multi: true });
      });
    } else if (activeQuizTopic === MIXED_TOPIC) {
      // v4.85.15: Mixed-mode per-topic split — pre-fix, Mixed quizzes (Deep
      // Scan, Marathon 30/45, Warmup, Diagnostic) saved a single summary
      // entry with topic = MIXED_TOPIC. getReadinessScore filters those out
      // → 326+ questions of practice were invisible to coverage/recency/
      // volume. Now we save BOTH the summary (for chronological history +
      // anything that filters on MIXED_TOPIC explicitly) AND a per-topic
      // split row per Haiku-assigned q.topic so readiness sees the actual
      // topics studied. Same pattern as the v4.81.13 exam-split. Marker
      // `via: 'mixed-split'` distinguishes from Multi: splits.
      saveToHistory({ date: now, topic: activeQuizTopic, difficulty: diff, score, total, pct, mode: entryMode });
      const byTopicMixed = {};
      log.forEach(entry => {
        const t = (entry.q && entry.q.topic) || null;
        if (!t || t === MIXED_TOPIC) return;
        if (!byTopicMixed[t]) byTopicMixed[t] = { total: 0, score: 0 };
        byTopicMixed[t].total++;
        if (entry.isRight) byTopicMixed[t].score++;
      });
      Object.keys(byTopicMixed).forEach(t => {
        const { total: tTotal, score: tScore } = byTopicMixed[t];
        const tPct = tTotal > 0 ? Math.round((tScore / tTotal) * 100) : 0;
        saveToHistory({ date: now, topic: t, difficulty: diff, score: tScore, total: tTotal, pct: tPct, mode: entryMode, via: 'mixed-split' });
      });
    } else {
      saveToHistory({ date: now, topic: activeQuizTopic, difficulty: diff, score, total, pct, mode: entryMode });
    }
  }
  // v4.54.17: if this quiz pushed the user past their daily goal for the
  // first time today, show an end-of-day recap card.
  try { if (typeof _maybeShowDailyRecap === 'function') _maybeShowDailyRecap(); } catch (_) {}
  // v4.42.0: refresh the homepage cards that depend on history state, so
  // re-entering goSetup() renders them fresh. renderReadinessCard rolls the
  // score from its previous value to the new one via animateCount. The
  // renderTodaysFocus call that used to live here has moved — goSetup() is
  // the only caller now, which lets the FLIP rerank animation capture real
  // old positions instead of re-rendering to an already-updated DOM.
  try { renderStatsCard(); } catch (_) {}
  try { renderReadinessCard(); } catch (_) {}
  try { if (typeof renderSrReviewCard === 'function') renderSrReviewCard(); } catch (_) {}
  // v4.42.0: fire milestone celebration toasts for anything we just unlocked.
  // Pre-v4.42 evaluateMilestones was never called from finish() — milestones
  // only unlocked lazily when the user opened Analytics. We now capture the
  // newly-unlocked list and stagger celebration toasts + mini confetti.
  try {
    const _newlyUnlocked = evaluateMilestones();
    if (_newlyUnlocked && _newlyUnlocked.length) {
      _newlyUnlocked.forEach((id, i) => setTimeout(() => showMilestoneCelebration(id), 500 + i * 900));
    }
  } catch (_) {}

  // v4.99.0: snapshot readiness for cross-cert analytics (Phase A.5).
  // Writes per-cert score to STORAGE.READINESS_SNAPSHOTS and cloud-flushes
  // so landing's /analytics page can render the live gauge for this cert.
  _writeReadinessSnapshot();

  // Daily challenge completion hook — count any finished daily-challenge run
  if (dailyChallengeMode) {
    completeDailyChallenge();
    dailyChallengeMode = false;
  }

  if (sessionMode) {
    sessionResults.push({ topic: activeQuizTopic, score, total, pct });
    sessionStep++;
    if (sessionStep >= sessionPlan.length) {
      sessionMode = false;
      renderSessionComplete();
    } else {
      renderSessionTransition();
    }
    return;
  }

  showPage('results');
}

// ══════════════════════════════════════════
// RETRY
// ══════════════════════════════════════════
async function retryQuiz() {
  if (wrongDrillMode) { startWrongDrill(); return; }

  const key = apiKey || document.getElementById('api-key').value.trim();
  if (!key) {
    showPage('setup');
    const err = document.getElementById('setup-err');
    err.textContent = '\u26a0\ufe0f Please enter your API key to retry.';
    err.classList.remove('is-hidden');
    return;
  }
  apiKey = key;

  activeQuizTopic = topic.includes('Smart') ? getSpacedRepTopic() : topic;

  document.getElementById('load-progress').classList.add('is-hidden');
  showPage('loading');
  document.getElementById('loading-msg').textContent = 'Generating ' + qCount + ' fresh ' + diff + ' questions on ' + activeQuizTopic + '\u2026';

  showCacheNotice(false);
  try {
    questions = await fetchQuestions(key, activeQuizTopic, diff, qCount);
    document.getElementById('loading-msg').textContent = 'Verifying question accuracy\u2026';
    questions = await aiValidateQuestions(key, questions);
    questions = validateQuestions(questions);
    if (questions.length === 0) throw new Error('All generated questions failed validation. Try again.');
  } catch(e) {
    const cached = getCachedQuestions(activeQuizTopic, diff, qCount);
    if (cached) {
      questions = cached;
      showCacheNotice(true);
    } else {
      showPage('setup');
      const err = document.getElementById('setup-err');
      err.textContent = '\u26a0\ufe0f ' + e.message;
      err.classList.remove('is-hidden');
      return;
    }
  }
  // Inject PBQs on retry too
  const retryPbqCount = qCount >= 10 ? 1 : 0;
  if (retryPbqCount > 0) {
    questions = injectPBQs(questions, activeQuizTopic, retryPbqCount);
  }
  current = 0; score = 0; streak = 0; bestStreak = 0; answered = 0; log = [];
  quizFlags = new Array(questions.length).fill(false);
  showPage('quiz');
  render();
}

// ══════════════════════════════════════════
// EXAM TIMER
// ══════════════════════════════════════════
// v4.99.49 Phase 10: Wake Lock keeps the phone screen on during the 90-min
// exam (default lock-screen is 30s on iOS, 60-120s on Android). Acquired
// when startExamTimer fires, released on submitExam/timeout. Auto-releases
// when the tab loses visibility (browser behaviour); _examOnVisibilityChange
// re-acquires when the tab regains visibility. Browser support ~85%
// (Chrome, Edge, Safari 16.4+, Firefox 126+); gracefully no-ops elsewhere.
let _examWakeLock = null;

async function _acquireExamWakeLock() {
  try {
    if (typeof navigator !== 'undefined' && 'wakeLock' in navigator) {
      _examWakeLock = await navigator.wakeLock.request('screen');
      // Auto-released by browser on tab hide — re-acquire on visible
      _examWakeLock.addEventListener('release', () => { _examWakeLock = null; });
    }
  } catch (_) {
    // Permission denied, battery saver, unsupported — silent no-op
    _examWakeLock = null;
  }
}

async function _releaseExamWakeLock() {
  try {
    if (_examWakeLock) {
      await _examWakeLock.release();
      _examWakeLock = null;
    }
  } catch (_) { _examWakeLock = null; }
}

// v4.99.49 Phase 10: pause exam timer when tab loses visibility, resume on
// regain. Tracks "time hidden" so examEndTime is extended by the same
// amount — student doesn't lose seconds to a notification interrupt.
let _examHiddenAt = null;

function _examOnVisibilityChange() {
  if (!examMode || !examTimer) return;  // only act during an exam
  if (document.visibilityState === 'hidden') {
    _examHiddenAt = Date.now();
  } else if (document.visibilityState === 'visible' && _examHiddenAt) {
    const hiddenMs = Date.now() - _examHiddenAt;
    _examHiddenAt = null;
    if (hiddenMs > 250) {  // ignore quick focus/blur glitches
      examEndTime += hiddenMs;  // extend deadline by hidden duration
    }
    // Wake Lock auto-released on hide — re-acquire
    _acquireExamWakeLock();
  }
}
if (typeof document !== 'undefined') {
  document.addEventListener('visibilitychange', _examOnVisibilityChange);
}

function startExamTimer() {
  if (examTimer) clearInterval(examTimer);
  examEndTime = Date.now() + examTimeLeft * 1000;
  _acquireExamWakeLock();  // Phase 10: keep phone screen on for 90 min
  examTimer = setInterval(() => {
    examTimeLeft = Math.max(0, Math.round((examEndTime - Date.now()) / 1000));
    updateTimerDisplay();
    if (examTimeLeft <= 0) { clearInterval(examTimer); examTimer = null; _releaseExamWakeLock(); submitExam(); }
  }, 1000);
  updateTimerDisplay();
}

function updateTimerDisplay() {
  const el = document.getElementById('exam-timer');
  if (!el) return;
  const m = Math.floor(examTimeLeft / 60), s = examTimeLeft % 60;
  el.textContent = `${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
  el.className = 'exam-timer' + (examTimeLeft <= 300 ? ' danger' : examTimeLeft <= 600 ? ' warning' : '');
}

// ══════════════════════════════════════════
// EXAM RENDER (with PBQ support)
// ══════════════════════════════════════════
function renderExam() {
  const q     = examQuestions[examCurrent];
  const ans   = examAnswers[examCurrent];
  const total = examQuestions.length;
  const qType = getQType(q);

  document.getElementById('exam-q-num').textContent = `Q${examCurrent + 1} / ${total}`;
  document.getElementById('exam-q-label').textContent = `Q${examCurrent + 1}`;
  document.getElementById('exam-topic-lbl').textContent = q.topic || '';

  const answeredCount = examAnswers.filter(a => a.chosen !== null || a.msChosen.length > 0 || a.orderSeq.length > 0 || Object.keys(a.topoState || {}).length > 0).length;
  document.getElementById('exam-answered-lbl').textContent = `${answeredCount} / ${total} answered`;
  document.getElementById('exam-prog-fill').style.width = ((examCurrent / total) * 100) + '%';
  // v4.54.9: segmented per-question progress dots (exam parity with quiz)
  if (typeof _renderExamProgressDots === 'function') _renderExamProgressDots();

  const flagBtn = document.getElementById('exam-flag-btn');
  flagBtn.className = 'exam-flag-btn' + (ans.flagged ? ' flagged' : '');
  flagBtn.textContent = ans.flagged ? '\u2691 Flagged' : '\u2691 Flag';
  flagBtn.setAttribute('aria-pressed', ans.flagged ? 'true' : 'false');

  setQuestionText(document.getElementById('exam-q-text'), q.question);

  // v4.56.0 — optional scenario context block (exam parity with quiz). Skipped for
  // cli-sim / topology which render their own scenario inside the options box.
  _renderScenarioBlock('exam-q-scenario', q, qType);

  const box = document.getElementById('exam-options');
  box.innerHTML = '';

  if (qType === 'multi-select') {
    renderMultiSelect(q, box, ans);
  } else if (qType === 'order') {
    renderOrder(q, box, ans);
  } else if (qType === 'cli-sim') {
    renderCliSim(q, box, ans);
  } else if (qType === 'topology') {
    renderTopology(q, box, ans);
  } else {
    renderMCQ(q, box, ans);
  }

  document.getElementById('exam-prev-btn').disabled = examCurrent === 0;
  const isLast = examCurrent === total - 1;
  const nextBtn = document.getElementById('exam-next-btn');
  nextBtn.textContent = isLast ? 'Submit Exam' : 'Next \u2192';
  nextBtn.onclick = isLast ? showExamModal : examNext;

  if (navOpen) renderNavGrid();
  updateTimerDisplay();
}

function examNext() { if (examCurrent < examQuestions.length - 1) { examCurrent++; renderExam(); window.scrollTo(0,0); } }
function examPrev() {
  // Hardcore mode locks question order — no going back (#48)
  if (examHardcore) return;
  if (examCurrent > 0) { examCurrent--; renderExam(); window.scrollTo(0,0); }
}

function examToggleFlag() {
  // Flagging is disabled in hardcore mode (#48)
  if (examHardcore) return;
  examAnswers[examCurrent].flagged = !examAnswers[examCurrent].flagged;
  renderExam();
}

// ══════════════════════════════════════════
// QUESTION NAVIGATOR
// ══════════════════════════════════════════
function toggleNav() {
  // Question navigator is disabled in hardcore mode (#48)
  if (examHardcore) return;
  navOpen = !navOpen;
  const grid = document.getElementById('qnav-grid');
  document.getElementById('qnav-arrow').textContent = navOpen ? '\u25b2' : '\u25bc';
  grid.classList.toggle('open', navOpen);
  const toggleBtn = document.getElementById('qnav-toggle');
  if (toggleBtn) toggleBtn.setAttribute('aria-expanded', navOpen ? 'true' : 'false');
  if (navOpen) renderNavGrid();
}

function renderNavGrid() {
  const grid = document.getElementById('qnav-grid');
  grid.innerHTML = '';
  grid.setAttribute('role', 'list');
  examAnswers.forEach((a, i) => {
    const sq = document.createElement('button');
    const hasAnswer = a.chosen !== null || a.msChosen.length > 0 || a.orderSeq.length > 0 || Object.keys(a.topoState || {}).length > 0;
    let cls = 'qnav-sq';
    let stateLbl = 'unanswered';
    if (i === examCurrent)    { cls += ' current';  stateLbl = 'current'; }
    else if (a.flagged)       { cls += ' flagged';  stateLbl = 'flagged'; }
    else if (hasAnswer)       { cls += ' answered'; stateLbl = 'answered'; }
    sq.className   = cls;
    sq.textContent = i + 1;
    sq.setAttribute('aria-label', `Question ${i + 1}, ${stateLbl}`);
    sq.setAttribute('aria-current', i === examCurrent ? 'true' : 'false');
    sq.onclick     = () => { examCurrent = i; renderExam(); window.scrollTo(0,0); };
    grid.appendChild(sq);
  });
}

// ══════════════════════════════════════════
// EXAM MODAL
// ══════════════════════════════════════════
function showExamModal() {
  const answeredCount = examAnswers.filter(a => a.chosen !== null || a.msChosen.length > 0 || a.orderSeq.length > 0 || Object.keys(a.topoState || {}).length > 0).length;
  const unanswered    = examAnswers.length - answeredCount;
  const flaggedCount  = examAnswers.filter(a => a.flagged).length;
  document.getElementById('modal-answered').textContent   = answeredCount;
  document.getElementById('modal-unanswered').textContent = unanswered;
  document.getElementById('modal-flagged').textContent    = flaggedCount;
  const flagBtn = document.getElementById('modal-flagged-btn');
  flagBtn.disabled = flaggedCount === 0;
  flagBtn.classList.toggle('is-dimmed', flaggedCount === 0);
  const modal = document.getElementById('exam-modal');
  modal.classList.remove('hidden');
  // Focus first button in modal for keyboard users
  setTimeout(() => {
    const firstBtn = modal.querySelector('button:not([disabled])');
    if (firstBtn) firstBtn.focus();
  }, 100);
  // Trap focus inside modal
  modal._trapHandler = (e) => {
    if (e.key !== 'Tab') return;
    const focusable = modal.querySelectorAll('button:not([disabled])');
    if (focusable.length === 0) return;
    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
    else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
  };
  modal.addEventListener('keydown', modal._trapHandler);
  // Close on Escape
  modal._escHandler = (e) => { if (e.key === 'Escape') hideExamModal(); };
  document.addEventListener('keydown', modal._escHandler);
}

function hideExamModal() {
  const modal = document.getElementById('exam-modal');
  modal.classList.add('hidden');
  if (modal._trapHandler) { modal.removeEventListener('keydown', modal._trapHandler); modal._trapHandler = null; }
  if (modal._escHandler) { document.removeEventListener('keydown', modal._escHandler); modal._escHandler = null; }
  // Return focus to the End Exam button
  const endBtn = document.querySelector('.end-exam-btn');
  if (endBtn) endBtn.focus();
}

function goToFirstFlagged() {
  hideExamModal();
  const idx = examAnswers.findIndex(a => a.flagged);
  if (idx >= 0) { examCurrent = idx; renderExam(); window.scrollTo(0,0); }
}

function abandonExam() {
  if (confirm('Abandon this exam and return to the menu? All progress will be lost.')) {
    clearInterval(examTimer); examTimer = null; examMode = false;
    hideExamModal();
    renderHistoryPanel();
    showPage('setup');
  }
}

// ══════════════════════════════════════════
// EXAM SUBMIT & RESULTS (with PBQ scoring)
// ══════════════════════════════════════════
function submitExam() {
  // v4.42.0: snapshot streak BEFORE updateStreak so we can flag a pulse for
  // goSetup() on increment.
  const _prevStreakBefore = (function(){ try { return getStreak().current || 0; } catch (_) { return 0; } })();
  if (examTimer) { clearInterval(examTimer); examTimer = null; }
  _releaseExamWakeLock();  // Phase 10: phone can sleep now
  hideExamModal();

  const total = examQuestions.length;
  let correct = 0;
  let wrong = 0;
  let skipped = 0;

  examAnswers.forEach((a, i) => {
    const q = examQuestions[i];
    const qType = getQType(q);
    let qCorrect = false, qSkipped = false;

    if (qType === 'multi-select') {
      const correctAns = (q.answers || []).sort();
      const chosen = [...(a.msChosen || [])].sort();
      if (chosen.length === 0) { skipped++; qSkipped = true; }
      else if (JSON.stringify(chosen) === JSON.stringify(correctAns)) { correct++; qCorrect = true; }
      else wrong++;
    } else if (qType === 'order') {
      const correctOrd = q.correctOrder || [];
      if (a.orderSeq.length === 0) { skipped++; qSkipped = true; }
      else if (JSON.stringify(a.orderSeq) === JSON.stringify(correctOrd)) { correct++; qCorrect = true; }
      else wrong++;
    } else if (qType === 'topology') {
      const correctP = q.correctPlacements || {};
      const state = a.topoState || {};
      if (Object.keys(state).length === 0) { skipped++; qSkipped = true; }
      else {
        let allRight = true;
        Object.entries(correctP).forEach(([dev, zone]) => {
          const placed = Object.entries(state).find(([z, devs]) => devs.includes(dev));
          if (!placed || placed[0] !== zone) allRight = false;
        });
        if (allRight) { correct++; qCorrect = true; }
        else wrong++;
      }
    } else {
      // mcq and cli-sim both use chosen + answer
      if (a.chosen === null) { skipped++; qSkipped = true; }
      else if (a.chosen === q.answer) { correct++; qCorrect = true; }
      else wrong++;
    }
    // Type stats (skipped answers don't count toward accuracy denominator)
    if (!qSkipped) updateTypeStat(qType, qCorrect);
  });

  const pct = Math.round((correct / total) * 100);
  const scaledScore = Math.round(100 + (correct / total) * 800);
  const passed      = scaledScore >= EXAM_PASS_SCORE;

  // Build log for review
  log = examQuestions.map((q, i) => {
    const a = examAnswers[i];
    const qType = getQType(q);
    let isRight, chosen, correctVal, isSkipped;

    if (qType === 'multi-select') {
      const correctAns = (q.answers || []).sort();
      chosen = (a.msChosen || []).sort().join(',');
      correctVal = correctAns.join(',');
      isSkipped = a.msChosen.length === 0;
      isRight = JSON.stringify((a.msChosen || []).sort()) === JSON.stringify(correctAns);
    } else if (qType === 'order') {
      chosen = (a.orderSeq || []).join(',');
      correctVal = (q.correctOrder || []).join(',');
      isSkipped = a.orderSeq.length === 0;
      isRight = JSON.stringify(a.orderSeq) === JSON.stringify(q.correctOrder || []);
    } else if (qType === 'topology') {
      chosen = JSON.stringify(a.topoState || {});
      correctVal = JSON.stringify(q.correctPlacements || {});
      isSkipped = Object.keys(a.topoState || {}).length === 0;
      isRight = !isSkipped;
      if (!isSkipped) {
        Object.entries(q.correctPlacements || {}).forEach(([dev, zone]) => {
          const placed = Object.entries(a.topoState || {}).find(([z, devs]) => devs.includes(dev));
          if (!placed || placed[0] !== zone) isRight = false;
        });
      }
    } else {
      // mcq and cli-sim
      chosen = a.chosen;
      correctVal = q.answer;
      isSkipped = a.chosen === null;
      isRight = a.chosen === q.answer;
    }

    // Track wrong for bank
    if (!isRight && !isSkipped) addToWrongBank(q, chosen);

    return { q, chosen, correct: correctVal, isRight, flagged: a.flagged, skipped: isSkipped };
  });

  updateStreak();
  // v4.42.0: flag streak-pulse for goSetup() if the exam finish incremented
  // the streak counter.
  try {
    if ((getStreak().current || 0) > _prevStreakBefore) _pendingStreakPulse = true;
  } catch (_) {}
  saveToHistory({ date: new Date().toISOString(), topic: EXAM_TOPIC, difficulty: 'Mixed', score: correct, total, pct, mode: 'exam', hardcore: examHardcore });
  // v4.81.13 (Codex r∞ user request): also write per-topic split rows so the
  // exam contributes to readiness / progress / weak-spots / what-if /
  // domain mastery — pre-fix the rolled-up EXAM_TOPIC sentinel was filtered
  // OUT by getReadinessScore (and every other surface that reads history
  // per-topic), so a 90-question exam was a "standalone entity" with zero
  // signal contribution beyond the wrong-bank + SR seed.
  try { _saveExamPerTopicSplit(log, examHardcore); } catch (e) { console.warn('[exam-split]', e); }
  // v4.81.13 (C): render the per-domain breakdown card on the exam-results
  // page so the user sees their domain split immediately after submit.
  try { if (typeof renderExamDomainBreakdown === 'function') renderExamDomainBreakdown(log); } catch (e) { console.warn('[exam-domain]', e); }
  // v4.54.17: end-of-day recap check after exam too
  try { if (typeof _maybeShowDailyRecap === 'function') _maybeShowDailyRecap(); } catch (_) {}
  // v4.42.0: refresh the homepage cards that depend on history state so
  // returning to setup renders them fresh with the new signal. The
  // renderTodaysFocus call that used to live here has moved — goSetup() is
  // the only caller now, which lets the FLIP rerank animation capture real
  // old positions instead of re-rendering against an already-updated DOM.
  try { renderStatsCard(); } catch (_) {}
  try { renderReadinessCard(); } catch (_) {}
  try { if (typeof renderSrReviewCard === 'function') renderSrReviewCard(); } catch (_) {}

  const scoreEl = document.getElementById('exam-scaled-score');
  scoreEl.style.color  = passed ? 'var(--green)' : 'var(--red)';
  animateCount('exam-scaled-score', 0, scaledScore, 1200);

  const badge = document.getElementById('exam-pass-badge');
  badge.textContent = passed ? 'PASS' : 'FAIL';
  badge.className   = 'pass-badge ' + (passed ? 'badge-pass' : 'badge-fail');
  // v4.54.9: editorial headline mirrors the pass/fail verdict with italic-accent em
  const headlineEl = document.getElementById('exam-result-headline');
  if (headlineEl) {
    headlineEl.innerHTML = passed
      ? 'Pass mark <em>cleared.</em>'
      : 'More <em>work needed.</em>';
  }
  // Hardcore badge on results hero (#48)
  const hcBadge = document.getElementById('exam-hardcore-badge');
  if (hcBadge) hcBadge.classList.toggle('is-hidden', !examHardcore);

  document.getElementById('exam-result-msg').textContent = passed
    ? `Score ${scaledScore}/900 \u2014 above the ${EXAM_PASS_SCORE} pass mark. Exam-ready!`
    : `Score ${scaledScore}/900 \u2014 need ${EXAM_PASS_SCORE - scaledScore} more points. Keep drilling!`;

  animateCount('exam-r-correct', 0, correct, 800);
  animateCount('exam-r-wrong', 0, wrong, 800);
  animateCount('exam-r-skipped', 0, skipped, 600);
  document.getElementById('exam-r-pct').textContent     = pct + '%';

  showPage('exam-results');
  if (passed) setTimeout(() => launchConfetti(), 400);
  // v4.42.0: evaluate + celebrate unlocked milestones. Delayed 900ms so it
  // doesn't collide with the exam-pass confetti burst; staggered by 900ms
  // between individual milestones so each celebration is readable.
  try {
    const _newlyUnlocked = evaluateMilestones();
    if (_newlyUnlocked && _newlyUnlocked.length) {
      _newlyUnlocked.forEach((id, i) => setTimeout(() => showMilestoneCelebration(id), 900 + i * 900));
    }
  } catch (_) {}

  // v4.99.0: snapshot readiness for cross-cert analytics (Phase A.5).
  // Mirror finish() — exam completion is a major readiness moment.
  _writeReadinessSnapshot();
}

// ══════════════════════════════════════════
// ANIMATED SCORE COUNTER
// ══════════════════════════════════════════
function animateCount(elId, from, to, duration, suffix) {
  const el = document.getElementById(elId);
  const sfx = suffix || '';
  if (!el || from === to) { if (el) el.textContent = to + sfx; return; }
  const start = performance.now();
  function step(now) {
    const t = Math.min((now - start) / duration, 1);
    const ease = 1 - Math.pow(1 - t, 3); // ease-out cubic
    el.textContent = Math.round(from + (to - from) * ease) + sfx;
    if (t < 1) requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}

// ══════════════════════════════════════════
// CONFETTI
// ══════════════════════════════════════════
function launchConfetti() {
  let canvas = document.getElementById('confetti-canvas');
  if (!canvas) {
    canvas = document.createElement('canvas');
    canvas.id = 'confetti-canvas';
    document.body.appendChild(canvas);
  }
  const ctx = canvas.getContext('2d');
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  canvas.classList.remove('is-hidden');

  const PARTICLE_COUNT = 150;
  const COLORS = ['#22c55e','#d4a574','#f59e0b','#ef4444','#3b82f6','#ec4899','#14b8a6','#f97316'];
  const particles = [];

  for (let i = 0; i < PARTICLE_COUNT; i++) {
    particles.push({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height * -1,
      w: Math.random() * 8 + 4,
      h: Math.random() * 6 + 3,
      color: COLORS[Math.floor(Math.random() * COLORS.length)],
      vx: (Math.random() - 0.5) * 4,
      vy: Math.random() * 3 + 2,
      rot: Math.random() * 360,
      rotSpeed: (Math.random() - 0.5) * 10,
      opacity: 1,
      shape: Math.random() > 0.5 ? 'rect' : 'circle'
    });
  }

  let frame = 0;
  const MAX_FRAMES = 200;

  function animate() {
    frame++;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    let alive = 0;
    particles.forEach(p => {
      if (p.opacity <= 0) return;
      alive++;

      p.x += p.vx;
      p.vy += 0.05;
      p.y += p.vy;
      p.rot += p.rotSpeed;

      if (frame > MAX_FRAMES * 0.6) {
        p.opacity -= 0.015;
      }

      ctx.save();
      ctx.translate(p.x, p.y);
      ctx.rotate((p.rot * Math.PI) / 180);
      ctx.globalAlpha = Math.max(0, p.opacity);
      ctx.fillStyle = p.color;

      if (p.shape === 'rect') {
        ctx.fillRect(-p.w / 2, -p.h / 2, p.w, p.h);
      } else {
        ctx.beginPath();
        ctx.arc(0, 0, p.w / 2, 0, Math.PI * 2);
        ctx.fill();
      }

      ctx.restore();
    });

    if (alive > 0 && frame < MAX_FRAMES) {
      requestAnimationFrame(animate);
    } else {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      canvas.classList.add('is-hidden');
    }
  }

  requestAnimationFrame(animate);
}

// ══════════════════════════════════════════
// v4.42.0 — MILESTONE CELEBRATION (toast + mini confetti)
// ══════════════════════════════════════════
// Fires a subtle celebration burst when a milestone unlocks during a quiz or
// exam finish. Separate from the exam-pass launchConfetti so the two can
// co-exist (pass confetti fills the screen; mini confetti bursts around the
// toast). Gated by prefers-reduced-motion via CSS: the keyframes become
// zero-duration under that media query so the toast still appears but the
// slide/burst is suppressed.
function showMilestoneCelebration(milestoneId) {
  try {
    const def = (MILESTONE_DEFS || []).find(m => m.id === milestoneId);
    if (!def) return;
    showCelebrationToast(def.label, def.desc);
    launchMiniConfetti();
  } catch (_) { /* celebration is best-effort */ }
}

function showCelebrationToast(titleText, subText) {
  try {
    const toast = document.createElement('div');
    toast.className = 'celebration-toast';
    const title = document.createElement('div');
    title.className = 'celebration-toast-title';
    title.textContent = titleText || 'Milestone unlocked';
    toast.appendChild(title);
    if (subText) {
      const sub = document.createElement('div');
      sub.className = 'celebration-toast-sub';
      sub.textContent = subText;
      toast.appendChild(sub);
    }
    document.body.appendChild(toast);
    setTimeout(() => toast.classList.add('show'), 10);
    setTimeout(() => {
      toast.classList.remove('show');
      setTimeout(() => { try { toast.remove(); } catch (_) {} }, 400);
    }, 3800);
  } catch (_) { /* best-effort */ }
}

// Mini confetti burst — subtler than launchConfetti (fewer particles, shorter
// duration, gold/accent palette, origin point at top-center so it lands near
// the celebration toast instead of covering the page).
function launchMiniConfetti() {
  try {
    let canvas = document.getElementById('confetti-canvas');
    if (!canvas) {
      canvas = document.createElement('canvas');
      canvas.id = 'confetti-canvas';
      document.body.appendChild(canvas);
    }
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    canvas.classList.remove('is-hidden');

    const PARTICLE_COUNT = 40;
    const COLORS = ['#fbbf24','#f59e0b','#fde047','#d4a574','#22c55e'];
    const originX = canvas.width / 2;
    const originY = 80; // near the top where the toast lives
    const particles = [];

    for (let i = 0; i < PARTICLE_COUNT; i++) {
      const angle = (Math.PI * 2 * i) / PARTICLE_COUNT + (Math.random() - 0.5) * 0.5;
      const speed = Math.random() * 4 + 3;
      particles.push({
        x: originX,
        y: originY,
        w: Math.random() * 6 + 3,
        h: Math.random() * 4 + 2,
        color: COLORS[Math.floor(Math.random() * COLORS.length)],
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed - 1,
        rot: Math.random() * 360,
        rotSpeed: (Math.random() - 0.5) * 12,
        opacity: 1,
        shape: Math.random() > 0.5 ? 'rect' : 'circle'
      });
    }

    let frame = 0;
    const MAX_FRAMES = 80;

    function animate() {
      frame++;
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      let alive = 0;
      particles.forEach(p => {
        if (p.opacity <= 0) return;
        alive++;
        p.x += p.vx;
        p.vy += 0.15;
        p.y += p.vy;
        p.rot += p.rotSpeed;
        if (frame > MAX_FRAMES * 0.5) p.opacity -= 0.03;
        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate((p.rot * Math.PI) / 180);
        ctx.globalAlpha = Math.max(0, p.opacity);
        ctx.fillStyle = p.color;
        if (p.shape === 'rect') {
          ctx.fillRect(-p.w / 2, -p.h / 2, p.w, p.h);
        } else {
          ctx.beginPath();
          ctx.arc(0, 0, p.w / 2, 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.restore();
      });
      if (alive > 0 && frame < MAX_FRAMES) {
        requestAnimationFrame(animate);
      } else {
        // Only hide the canvas if launchConfetti isn't also running (defensive).
        if (!canvas.dataset.fullConfettiActive) {
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          canvas.classList.add('is-hidden');
        }
      }
    }
    requestAnimationFrame(animate);
  } catch (_) { /* best-effort */ }
}

// ══════════════════════════════════════════
// REVIEW
// ══════════════════════════════════════════
// v4.85.17: filter state for the exam-review screen. One of:
//   'all' | 'correct' | 'incorrect' | 'flagged' | 'skipped'
// Module-level so chip clicks can re-render against the same log[].
let _reviewFilter = 'all';

function showReview(fromExam) {
  document.getElementById('review-back-btn').onclick = () => showPage(fromExam ? 'exam-results' : 'results');
  // Reset filter when entering a fresh review (don't leak state from a previous session)
  _reviewFilter = 'all';
  _renderReviewList();
  showPage('review');
}

// v4.85.17: extracted from showReview() so chip clicks can re-render the
// list without leaving + re-entering the page. Reads `log[]` (the global
// session log, populated by finish() / submitExam()) and `_reviewFilter`.
// Computes counts once + renders the filter chip row + filtered item list
// (or empty state when count = 0).
function _renderReviewList() {
  const host = document.getElementById('review-list');
  if (!host || !Array.isArray(log)) return;

  // Count each filter category
  const counts = { all: log.length, correct: 0, incorrect: 0, flagged: 0, skipped: 0 };
  log.forEach(entry => {
    if (entry.skipped) counts.skipped++;
    else if (entry.isRight) counts.correct++;
    else counts.incorrect++;
    if (entry.flagged) counts.flagged++;
  });

  // If active filter has 0 results (defensive), fall back to 'all'.
  if (_reviewFilter !== 'all' && counts[_reviewFilter] === 0) _reviewFilter = 'all';

  // Apply current filter
  const filtered = log.filter(entry => {
    if (_reviewFilter === 'all') return true;
    if (_reviewFilter === 'correct') return entry.isRight && !entry.skipped;
    if (_reviewFilter === 'incorrect') return !entry.isRight && !entry.skipped;
    if (_reviewFilter === 'flagged') return !!entry.flagged;
    if (_reviewFilter === 'skipped') return !!entry.skipped;
    return true;
  });

  // Filter chip row
  const chipDef = [
    { key: 'all',       label: 'All',         icon: '' },
    { key: 'correct',   label: 'Correct',     icon: '\u2713 ' },
    { key: 'incorrect', label: 'Incorrect',   icon: '\u2717 ' },
    { key: 'flagged',   label: 'Flagged',     icon: '\u2691 ' },
    { key: 'skipped',   label: 'Skipped',     icon: '\u21B7 ' }
  ];
  const filterRowHtml = `<div class="review-filter-row">
    <span class="review-filter-eyebrow">Filter</span>
    ${chipDef.map(c => {
      const isActive = _reviewFilter === c.key;
      const isDisabled = c.key !== 'all' && counts[c.key] === 0;
      const cls = ['review-filter-chip', 'is-' + c.key, isActive ? 'is-active' : '', isDisabled ? 'is-disabled' : ''].filter(Boolean).join(' ');
      const onclick = isDisabled ? '' : `onclick="_setReviewFilter('${c.key}')"`;
      const aria = isDisabled ? 'aria-disabled="true"' : (isActive ? 'aria-pressed="true"' : 'aria-pressed="false"');
      return `<button type="button" class="${cls}" ${aria} ${onclick}>${c.icon}${c.label} <span class="chip-count">${counts[c.key]}</span></button>`;
    }).join('')}
    <span class="review-filter-meta">Showing <strong>${filtered.length}</strong> of <strong>${log.length}</strong></span>
  </div>`;

  // Empty state when filter returns 0
  if (filtered.length === 0) {
    const activeChip = chipDef.find(c => c.key === _reviewFilter);
    const label = activeChip ? activeChip.label.toLowerCase() : '';
    host.innerHTML = filterRowHtml + `
      <div class="review-filter-empty">
        <span class="review-filter-empty-ico"></span>
        <div class="review-filter-empty-title">Nothing here \u2014 no ${escHtml(label)} answers</div>
        <div class="review-filter-empty-body">Try a different filter to review your answers.</div>
        <button type="button" class="review-filter-empty-cta" onclick="_setReviewFilter('all')">Show all ${log.length} \u2192</button>
      </div>`;
    return;
  }

  // Build all item HTML up front (avoids per-item DOM cost)
  const itemsHtml = filtered.map(entry => _buildReviewItemHtml(entry, log.indexOf(entry), log.length)).join('');
  host.innerHTML = filterRowHtml + itemsHtml;
}

// v4.85.17: chip click handler. Sets filter state then re-renders.
function _setReviewFilter(key) {
  _reviewFilter = key;
  _renderReviewList();
  // Scroll the host into view so the user lands at the top of the filtered list
  try {
    const host = document.getElementById('review-list');
    if (host) host.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } catch (_) { /* defensive */ }
}

// v4.85.17: per-question item builder, extracted so the renderer can rebuild
// items in different filter states without duplicating markup. `i` is the
// 0-based original question index; `total` is full log length so the
// "Q N of M" badge stays accurate even after filtering.
function _buildReviewItemHtml(entry, i, total) {
  const { q, chosen, isRight, flagged, skipped } = entry;
  const qType = getQType(q);

  let cls = 'review-item ';
  if (skipped)      cls += 'skipped';
  else if (isRight) cls += 'correct';
  else              cls += 'missed';
  if (flagged) cls += ' flagged-item';

  let optsHtml;
  if (qType === 'order') {
    const items = q.items || [];
    const correctOrd = q.correctOrder || [];
    optsHtml = '<div class="review-options">' +
      correctOrd.map((idx, pos) => `<div class="review-opt is-correct"><span class="r-letter">${pos+1})</span><span>${escHtml(items[idx])}</span></div>`).join('') +
      '</div>';
  } else if (qType === 'topology') {
    const cp = q.correctPlacements || {};
    optsHtml = '<div class="review-options">' +
      Object.entries(cp).map(([dev, zone]) => `<div class="review-opt is-correct"><span class="r-letter">\u2192</span><span>${escHtml(dev)} \u2192 ${escHtml(zone)}</span></div>`).join('') +
      '</div>';
  } else {
    const letters = Object.keys(q.options || {}).sort();
    const correctArr = qType === 'multi-select' ? (q.answers || []) : [q.answer];
    const chosenArr = typeof chosen === 'string' ? chosen.split(',') : [];
    optsHtml = '<div class="review-options">' + letters.map(l => {
      let optCls = '';
      if (correctArr.includes(l)) optCls = 'is-correct';
      else if (chosenArr.includes(l) && !isRight) optCls = 'was-chosen';
      return `<div class="review-opt ${optCls}"><span class="r-letter">${l})</span><span>${escHtml(q.options[l])}</span></div>`;
    }).join('') + '</div>';
  }

  // Meta-tag row above question stem - status + flag + domain
  const statusTag = skipped
    ? '<span class="q-tag tag-skipped">\u21B7 Skipped</span>'
    : (isRight
      ? '<span class="q-tag tag-correct">\u2713 Correct</span>'
      : '<span class="q-tag tag-incorrect">\u2717 Incorrect</span>');
  const flagTag = flagged ? '<span class="q-tag tag-flagged">\u2691 Flagged</span>' : '';
  const reviewTopic = q.topic || activeQuizTopic;
  const reviewRes = topicResources[reviewTopic];
  const domainTag = reviewTopic && reviewTopic !== MIXED_TOPIC && reviewTopic !== EXAM_TOPIC
    ? '<span class="q-tag tag-domain">' + escHtml(reviewTopic) + '</span>'
    : '';

  const typeLabels = { 'multi-select': 'Multi-Select', 'order': 'Ordering', 'cli-sim': 'CLI Sim', 'topology': 'Topology' };
  const typeBadge = qType !== 'mcq' ? `<span class="pbq-badge" style="margin-left:6px">${typeLabels[qType] || qType}</span>` : '';

  const resLink = reviewRes ? `<div class="resource-link" style="margin-top:8px"><button class="resource-dive-btn" onclick="showTopicDeepDive('${escHtml(reviewTopic).replace(/'/g, "\\'")}')">Study: ${escHtml(reviewRes.title)} (Obj ${reviewRes.obj})</button></div>` : '';

  return `<div class="${cls}">
    <div class="review-q-meta-row">
      <span class="q-num-pill">Q ${i+1} of ${total}</span>
      ${statusTag}
      ${flagTag}
      ${domainTag}
      ${typeBadge}
    </div>
    <div class="review-q">${i+1}. ${highlightExamKeywords(escHtml(q.question))}</div>
    ${optsHtml}
    <div class="review-exp">${escHtml(q.explanation)}${resLink}</div>
  </div>`;
}

// ══════════════════════════════════════════
// KEYBOARD SHORTCUTS
// ══════════════════════════════════════════
document.addEventListener('keydown', e => {
  if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
  if (e.metaKey || e.ctrlKey || e.altKey) return;

  const key     = e.key.toUpperCase();
  const onQuiz  = document.getElementById('page-quiz').classList.contains('active');
  const onExam  = document.getElementById('page-exam').classList.contains('active');

  if (['A','B','C','D','E'].includes(key)) {
    if (onQuiz) {
      const q = questions[current];
      const qType = getQType(q);
      if (qType === 'mcq' && key !== 'E') pick(key, q);
      else if (qType === 'multi-select' && q.options && q.options[key]) {
        // Toggle multi-select option via keyboard
        const optBtn = document.querySelector(`#options .option[data-letter="${key}"]`);
        if (optBtn) optBtn.click();
      }
    } else if (onExam) {
      const q = examQuestions[examCurrent];
      const qType = getQType(q);
      if (qType === 'mcq' && key !== 'E') {
        examAnswers[examCurrent].chosen = key;
        renderExam();
      } else if (qType === 'multi-select' && q.options && q.options[key]) {
        const ms = examAnswers[examCurrent].msChosen || [];
        const idx = ms.indexOf(key);
        if (idx >= 0) ms.splice(idx, 1); else ms.push(key);
        examAnswers[examCurrent].msChosen = ms;
        renderExam();
      }
    }
    return;
  }

  if (e.key === 'Enter') {
    if (onQuiz) {
      const btn = document.getElementById('btn-next');
      if (btn.classList.contains('show')) btn.click();
    } else if (onExam) {
      document.getElementById('exam-next-btn').click();
    }
    return;
  }

  if (key === 'F') {
    if (onQuiz)  toggleFlag();
    if (onExam)  examToggleFlag();
    return;
  }

  if (e.key === 'ArrowRight' && onExam) { examNext(); return; }
  if (e.key === 'ArrowLeft'  && onExam) { examPrev(); return; }
  // v4.82.0: quiz prev/next via arrow keys for revisit nav.
  if (e.key === 'ArrowRight' && onQuiz) { nextQuestion(); return; }
  if (e.key === 'ArrowLeft'  && onQuiz) { prevQuestion(); return; }
});

// ══════════════════════════════════════════
// EXAM READINESS SCORE
// ══════════════════════════════════════════
// CompTIA N10-009 official domain weights
// v4.86.1: DOMAIN_WEIGHTS moved to certs/<cert>.js. App reads via CERT_PACK
// with Network+ defaults (CompTIA N10-009 blueprint) preserved as fallback.
const DOMAIN_WEIGHTS = (CERT_PACK && CERT_PACK.domainWeights) || {
  concepts: 0.23, implementation: 0.20, operations: 0.19, security: 0.14, troubleshooting: 0.24
};
const DOMAIN_LABELS = (CERT_PACK && CERT_PACK.domainLabels) || {
  concepts: 'Networking Concepts', implementation: 'Network Implementation',
  operations: 'Network Operations', security: 'Network Security', troubleshooting: 'Network Troubleshooting'
};
// v4.85.8: Mixed mode topic lottery — randomly samples distinct topics from each
// domain's pool so Haiku can't default to its 4-5 favorite topics (subnetting,
// OSI, DNS, ping, troubleshooting methodology). Returns
// { concepts: [topicA, topicB, ...], implementation: [...], ... } where each
// array contains exactly dist[domain] topic names. Topics are unique within a
// domain unless dist[domain] exceeds pool size (then sampling-with-replacement).
// User: *"increase the randomization of the topics so it's genuinely like a lottery."*
function _sampleTopicsForMixedBatch(dist) {
  const byDomain = { concepts: [], implementation: [], operations: [], security: [], troubleshooting: [] };
  Object.keys(TOPIC_DOMAINS).forEach(t => {
    const d = TOPIC_DOMAINS[t];
    if (byDomain[d]) byDomain[d].push(t);
  });
  const shuffle = (arr) => {
    const a = arr.slice();
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  };
  const result = { concepts: [], implementation: [], operations: [], security: [], troubleshooting: [] };
  Object.keys(byDomain).forEach(d => {
    const need = dist[d] || 0;
    if (need <= 0) return;
    const pool = byDomain[d];
    if (need <= pool.length) {
      result[d] = shuffle(pool).slice(0, need);
    } else {
      // Need more than available — fill from shuffled pool, repeat as needed
      const out = [];
      while (out.length < need) out.push(...shuffle(pool));
      result[d] = out.slice(0, need);
    }
  });
  return result;
}

// Largest-remainder allocation of n questions across the 5 CompTIA domains per official weights
function computeDomainDistribution(n) {
  // v4.88.2: cert-aware. Network+ used hardcoded keys here; Security+ has
  // different domain keys (threats / architecture / governance), so reading
  // DOMAIN_WEIGHTS[k] for Network+ keys returned undefined → NaN → broken
  // generation. Pull the keys from DOMAIN_WEIGHTS (blueprint order) so the
  // distribution is always correct for the active cert.
  const order = (typeof DOMAIN_WEIGHTS === 'object' && DOMAIN_WEIGHTS)
    ? Object.keys(DOMAIN_WEIGHTS)
    : ['concepts','implementation','operations','security','troubleshooting'];
  const raw = order.map(k => ({ k, exact: n * DOMAIN_WEIGHTS[k] }));
  const floors = raw.map(r => ({ k: r.k, count: Math.floor(r.exact), rem: r.exact - Math.floor(r.exact) }));
  let assigned = floors.reduce((s, r) => s + r.count, 0);
  let leftover = n - assigned;
  // Distribute leftover to the largest remainders
  floors.sort((a, b) => b.rem - a.rem);
  for (let i = 0; i < leftover; i++) floors[i % floors.length].count++;
  const result = {};
  floors.forEach(r => { result[r.k] = r.count; });
  return result;
}
// Map each topic to its primary CompTIA domain
// v4.86.1: TOPIC_DOMAINS moved to certs/<cert>.js. App reads via CERT_PACK.
// Empty fallback {} = catalog routing falls through to defaults (no topic
// matched any domain). In production CERT_PACK is always populated.
const TOPIC_DOMAINS = (CERT_PACK && CERT_PACK.topicDomains) || {};

// v4.81.19: comma-safe Multi: topic sentinel parser.
// 3 topic names contain literal commas:
//   - 'NTP, ICMP & Traffic Types'      (concepts)
//   - 'SDN, NFV & Automation'          (implementation)
//   - 'Firewalls, DMZ & Security Zones' (security)
// A naive `.split(',')` on a Multi: sentinel like
//   "Multi: IPv6, NTP, ICMP & Traffic Types, BGP"
// mis-segments those topics — "NTP" + "ICMP & Traffic Types" instead of
// the canonical "NTP, ICMP & Traffic Types". Surfaces in 4 sites:
//   - _pickExemplarsForTopic       (first-topic extraction)
//   - loadHistory filter           (multi-list .includes(topic))
//   - _multiCount counting         (display counts)
//   - fetchQuestions Multi: parse  (worst impact: feeds Haiku a mis-split list)
// Bug got more visible with v4.81.17 Domain Drill (3 of 5 domain presets
// contain a comma-named topic).
//
// This helper does greedy longest-match against the TOPIC_DOMAINS catalog
// (sorted by length desc) so multi-word topic names with commas are
// preserved verbatim. Falls back to a naive split when TOPIC_DOMAINS isn't
// defined (defensive — should never happen in practice).
//
// Returns an array of topic names. Accepts either the full sentinel
// ("Multi: A, B, C") or the body alone ("A, B, C").
function _parseMultiTopicSentinel(qTopic) {
  if (typeof qTopic !== 'string') return [];
  const body = qTopic.startsWith('Multi: ') ? qTopic.slice(7) : qTopic;
  if (typeof TOPIC_DOMAINS === 'undefined' || !TOPIC_DOMAINS) {
    return body.split(',').map(s => s.trim()).filter(Boolean);
  }
  const allTopics = Object.keys(TOPIC_DOMAINS).sort((a, b) => b.length - a.length);
  const found = [];
  let remaining = body.trim();
  while (remaining.length > 0) {
    let matched = null;
    for (const t of allTopics) {
      if (remaining.startsWith(t)) { matched = t; break; }
    }
    if (matched) {
      found.push(matched);
      remaining = remaining.slice(matched.length).replace(/^[,\s]+/, '');
    } else {
      // Fallback: skip to next comma. Shouldn't happen if catalog is up
      // to date, but keeps the parser non-blocking on unknown strings.
      const idx = remaining.indexOf(',');
      if (idx === -1) break;
      remaining = remaining.slice(idx + 1).replace(/^\s+/, '');
    }
  }
  return found;
}

function diffWeight(d) {
  if (!d) return 1.5;
  const s = d.toLowerCase();
  if (s.includes('hard'))  return 2.0;
  if (s.includes('exam'))  return 1.5;
  if (s.includes('found')) return 1.0;
  return 1.3;
}

// Build a per-topic weighted-accuracy map from history entries.
// Weights: difficulty × exam-mode boost (1.3 for exam mode) × recency boost
// (2.0 for sessions in the last 7 days). Extracted from getReadinessScore (#18).
function buildWeightedTopicMap(historyEntries, now) {
  const SEVEN_DAYS_MS = 7 * 86400000;
  const topicMap = {};
  historyEntries.forEach(e => {
    if (!topicMap[e.topic]) topicMap[e.topic] = { wCorrect: 0, wTotal: 0, lastDate: 0 };
    const sessionTime = new Date(e.date).getTime();
    const isRecent = (now - sessionTime) <= SEVEN_DAYS_MS;
    const examBoost = (e.mode === 'exam') ? 1.3 : 1.0;
    const recencyBoost = isRecent ? 2.0 : 1.0;
    const w = diffWeight(e.difficulty) * examBoost * recencyBoost;
    topicMap[e.topic].wCorrect += e.score * w;
    topicMap[e.topic].wTotal   += e.total * w;
    if (sessionTime > topicMap[e.topic].lastDate) topicMap[e.topic].lastDate = sessionTime;
  });
  return topicMap;
}

function getReadinessScore() {
  const allTopics = Array.from(document.querySelectorAll('#topic-group .chip'))
    .map(c => c.dataset.v)
    .filter(v => !v.includes('Mixed') && !v.includes('Smart'));
  const totalTopics = allTopics.length;

  // v4.85.15: dropped the `e.total >= 3` filter. v4.85.8's TOPIC LOTTERY +
  // v4.85.15's mixed-split now produce 1-Q-per-topic split rows; the >=3
  // filter was throwing those away, so a 20-Q Mixed quiz contributed 0
  // topics to coverage. Aggregation in buildWeightedTopicMap sums across
  // sessions per topic, so noise control still works at the topic level.
  // MIXED + EXAM summary rows still filtered explicitly to avoid double-
  // counting (the per-topic splits cover them).
  const h = loadHistory().filter(e =>
    e.topic !== MIXED_TOPIC && e.topic !== EXAM_TOPIC
  );
  if (h.length === 0) return null;

  const now = Date.now();
  const topicMap = buildWeightedTopicMap(h, now);

  const studiedTopics = Object.keys(topicMap);
  const studiedCount  = studiedTopics.length;

  // Domain-weighted accuracy — each CompTIA domain contributes its official weight.
  // Unstudied domains contribute 0, which drags the score down and incentivizes coverage.
  //
  // v4.42.4: Within-domain aggregation fix. Previously this computed the simple
  // average of per-topic accuracies (`pctSum / count`), which gave equal weight
  // to a topic with 2 questions and one with 200. The real CompTIA exam weights
  // every question equally — so if you're 95% on OSPF (20 Q's) and 50% on BGP
  // (4 Q's), your real-exam-equivalent implementation accuracy is (19+2)/(20+4)
  // = 87.5%, not the simple average of 72.5%. The v4.42.3 catalog expansion
  // made this flaw more visible because new child topics start with 0 questions
  // while parent umbrellas have lots. Now aggregates weighted-correct /
  // weighted-total across all topics in the domain, so question count properly
  // influences domain-level accuracy.
  const domainBuckets = {};
  Object.keys(DOMAIN_WEIGHTS).forEach(d => { domainBuckets[d] = { wCorrect: 0, wTotal: 0 }; });
  studiedTopics.forEach(t => {
    const domain = TOPIC_DOMAINS[t];
    if (!domain) return; // topics not in map (e.g. Mixed) are excluded
    domainBuckets[domain].wCorrect += topicMap[t].wCorrect;
    domainBuckets[domain].wTotal   += topicMap[t].wTotal;
  });
  const domainAccuracy = {};
  let accuracyScore = 0;
  Object.keys(DOMAIN_WEIGHTS).forEach(d => {
    const bucket = domainBuckets[d];
    const avg = bucket.wTotal > 0 ? (bucket.wCorrect / bucket.wTotal) * 100 : 0;
    domainAccuracy[d] = avg;
    accuracyScore += avg * DOMAIN_WEIGHTS[d];
  });

  const coverageRaw = (studiedCount / totalTopics) * 100;
  const coverageScore = studiedCount < 5 ? coverageRaw * 0.5 : coverageRaw;

  const recencyScore = studiedTopics.reduce((sum, t) => {
    const daysSince = (now - topicMap[t].lastDate) / 86400000;
    return sum + Math.max(0, 1 - daysSince / 14) * 100;
  }, 0) / totalTopics;

  const totalQs    = h.reduce((sum, e) => sum + e.total, 0);
  const volumeScore = Math.min(totalQs / 500, 1) * 100;

  const raw = (accuracyScore * 0.40) + (coverageScore * 0.25) + (recencyScore * 0.20) + (volumeScore * 0.15);
  const predicted = Math.round(420 + (raw / 100) * 450);

  let worstTopic = null, worstPct = 101;
  allTopics.forEach(t => {
    if (!topicMap[t]) {
      if (worstTopic === null) { worstTopic = t; worstPct = -1; }
    } else {
      const pct = Math.round((topicMap[t].wCorrect / topicMap[t].wTotal) * 100);
      if (worstPct === -1) return;
      if (pct < worstPct) { worstPct = pct; worstTopic = t; }
    }
  });

  // ── v4.73.0: Pass-rate prediction extras ──
  // Confidence interval, pass probability, what-if attribution, trajectory.
  // The data quality (sample size + coverage + recency) drives the CI width.
  // The wider the CI, the less confidently we can predict the real exam score.
  const sampleWidth = 60 / Math.sqrt(1 + totalQs / 50);
  const coverageFactor = totalTopics > 0 ? studiedCount / totalTopics : 0;
  const recencyFactor = recencyScore / 100;
  const coverageWidth = 30 * (1 - coverageFactor);
  const recencyWidth = 15 * (1 - recencyFactor);
  let ciHalfWidth = sampleWidth + coverageWidth + recencyWidth;
  ciHalfWidth = Math.max(15, Math.min(100, Math.round(ciHalfWidth)));
  const lowerBound = Math.max(420, predicted - ciHalfWidth);
  const upperBound = Math.min(870, predicted + ciHalfWidth);

  // Pass probability via logistic centered on the pass line. Sigma derived
  // from CI half-width (90% CI ≈ ±1.645σ). Result is 0-1.
  const sigma = ciHalfWidth / 1.645;
  const z = (predicted - EXAM_PASS_SCORE) / sigma;
  const passProbability = 1 / (1 + Math.exp(-z));

  // What-if attribution: for each studied topic, compute the predicted-score
  // delta if that topic improved to 80% accuracy. Surfaces the highest-leverage
  // topics — not just the lowest-mastery, but the ones whose mastery would
  // most move the final score (factors in domain weight + question count).
  const TARGET_ACC = 0.80;
  const whatIfsRaw = [];
  studiedTopics.forEach(t => {
    const tData = topicMap[t];
    const domain = TOPIC_DOMAINS[t];
    if (!domain) return;
    const bucket = domainBuckets[domain];
    if (!bucket || bucket.wTotal === 0) return;

    const currentAcc = tData.wTotal > 0 ? tData.wCorrect / tData.wTotal : 0;
    const currentPct = Math.round(currentAcc * 100);
    if (currentAcc >= TARGET_ACC) return;

    const newWCorrect = TARGET_ACC * tData.wTotal;
    const deltaWCorrect = newWCorrect - tData.wCorrect;
    // New domain accuracy if THIS topic improved to TARGET_ACC
    const newDomainAcc = ((bucket.wCorrect + deltaWCorrect) / bucket.wTotal) * 100;
    const oldDomainAcc = (bucket.wCorrect / bucket.wTotal) * 100;
    const deltaDomainAccPts = newDomainAcc - oldDomainAcc;
    // Score delta: deltaDomainAcc * domain weight * accuracy weight (0.40) * scale (4.5)
    const deltaAccScore = deltaDomainAccPts * DOMAIN_WEIGHTS[domain];
    const deltaPredicted = Math.round(deltaAccScore * 0.40 * 4.5);

    if (deltaPredicted >= 1) {
      whatIfsRaw.push({ topic: t, domain, currentPct, targetPct: 80, deltaPredicted });
    }
  });
  whatIfsRaw.sort((a, b) => b.deltaPredicted - a.deltaPredicted);
  const whatIf = whatIfsRaw.slice(0, 3);

  // Days to exam + the gap to a confident pass (lower CI bound above 720).
  const daysToExam = (typeof getDaysToExam === 'function') ? getDaysToExam() : null;
  const targetGap = Math.max(0, EXAM_PASS_SCORE - lowerBound);

  // v4.85.14: stale-topic list for the "Why your score?" breakdown card.
  // Sorted oldest-first so the renderer can take the top N stalest topics
  // and seed a refresh quiz to lift the recency component back up. Topics
  // not yet studied (no entry in topicMap) are not included — they're a
  // coverage problem, not a recency problem.
  const staleTopics = studiedTopics
    .map(t => ({ topic: t, daysSince: Math.round((now - topicMap[t].lastDate) / 86400000) }))
    .sort((a, b) => b.daysSince - a.daysSince);

  return {
    predicted, raw,
    accuracyScore, coverageScore, recencyScore, volumeScore,
    domainAccuracy,
    worstTopic,
    worstPct: worstPct === -1 ? null : worstPct,
    studiedCount,
    totalTopics,
    totalQs,
    // v4.73.0 prediction extras
    ciHalfWidth,
    lowerBound,
    upperBound,
    passProbability,
    whatIf,
    daysToExam,
    targetGap,
    // v4.85.14 — stale-topic list for the score-breakdown card
    staleTopics
  };
}

// v4.99.0 — readiness snapshot writer (cross-cert analytics Phase A.5).
// v4.99.1 — enriched with weak_topic + weak_pct + weak_domain + days_to_exam
//           + total_qs so landing's Panel 3 ranker (Phase C) can produce
//           specific recommendations rather than generic "continue studying."
//
// Computes the user's current readiness for the active cert and writes a
// per-cert snapshot under a single STORAGE.READINESS_SNAPSHOTS key shaped
// like { netplus: {score, computed_at, weak_topic, ...}, secplus: {...} }.
// Triggered from finish() (quiz complete) and submitExam() (exam complete)
// — natural moments where readiness changes meaningfully.
//
// Cloud-flushed via existing Phase C′ pattern so landing's /analytics page
// reads it from profile.metadata.nplus_readiness_snapshots and renders
// live readiness gauges + actionable next-up recommendations across the
// user's whole portfolio.
//
// Defensive: silently no-ops on any failure so a snapshot write never
// blocks a quiz/exam from finishing. The score will get rewritten on the
// next quiz finish anyway.
function _writeReadinessSnapshot() {
  try {
    var readiness = getReadinessScore();
    if (!readiness || typeof readiness.predicted !== 'number') return;
    var raw = localStorage.getItem(STORAGE.READINESS_SNAPSHOTS);
    var snapshots = {};
    if (raw) {
      try { snapshots = JSON.parse(raw) || {}; } catch (_) { snapshots = {}; }
    }
    // Resolve the weak topic's domain via the existing TOPIC_DOMAINS map
    // (cert-app source of truth for topic → domain). null if unmapped.
    var weakDomain = null;
    if (readiness.worstTopic && typeof TOPIC_DOMAINS !== 'undefined') {
      weakDomain = TOPIC_DOMAINS[readiness.worstTopic] || null;
    }
    snapshots[CURRENT_CERT] = {
      score: readiness.predicted,
      computed_at: new Date().toISOString(),
      // v4.99.1: ranker signals for Panel 3
      weak_topic: readiness.worstTopic || null,
      weak_pct: typeof readiness.worstPct === 'number' ? readiness.worstPct : null,
      weak_domain: weakDomain,
      days_to_exam: typeof readiness.daysToExam === 'number' ? readiness.daysToExam : null,
      total_qs: typeof readiness.totalQs === 'number' ? readiness.totalQs : null
    };
    localStorage.setItem(STORAGE.READINESS_SNAPSHOTS, JSON.stringify(snapshots));
    if (typeof _cloudFlush === 'function') _cloudFlush(STORAGE.READINESS_SNAPSHOTS);
  } catch (_) { /* non-fatal — never block quiz finish */ }
}

// ── Exam date storage + forecast ──
function getExamDate() {
  const raw = localStorage.getItem(STORAGE.EXAM_DATE);
  return raw || null;
}
function setExamDate(isoDate) {
  if (!isoDate) { localStorage.removeItem(STORAGE.EXAM_DATE); _cloudFlush(STORAGE.EXAM_DATE); return; }
  localStorage.setItem(STORAGE.EXAM_DATE, isoDate);
  _cloudFlush(STORAGE.EXAM_DATE);
}
function getDaysToExam() {
  const raw = getExamDate();
  if (!raw) return null;
  const examMs = new Date(raw).getTime();
  if (isNaN(examMs)) return null;
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
  return Math.ceil((examMs - today) / 86400000);
}
function getReadinessForecast() {
  // Linear regression on raw score over the last N sessions to project when we
  // hit the pass threshold. Returns null if insufficient data or flat/negative trend.
  const h = loadHistory().filter(e =>
    e.topic !== MIXED_TOPIC && e.topic !== EXAM_TOPIC && e.total >= 3
  );
  if (h.length < 5) return null;
  // Use the last 14 sessions (history is newest-first, so take .slice(0, 14).reverse())
  const recent = h.slice(0, 14).reverse();
  // Compute cumulative raw-score trajectory: for each session endpoint, what was raw?
  // Approximation: use per-session pct as the proxy (avoids re-running full getReadinessScore per session)
  const points = recent.map((e, i) => ({ x: i, y: e.pct }));
  const n = points.length;
  const sumX  = points.reduce((a, p) => a + p.x, 0);
  const sumY  = points.reduce((a, p) => a + p.y, 0);
  const sumXY = points.reduce((a, p) => a + p.x * p.y, 0);
  const sumXX = points.reduce((a, p) => a + p.x * p.x, 0);
  const denom = n * sumXX - sumX * sumX;
  if (denom === 0) return null;
  const slope     = (n * sumXY - sumX * sumY) / denom;
  const intercept = (sumY - slope * sumX) / n;
  const currentProj = slope * (n - 1) + intercept;

  // Target: 75% avg pct → roughly correlates with a 720 pass score when coverage is decent
  const TARGET_PCT = 75;
  if (slope <= 0.1) {
    return { slope, currentProj, sessionsToTarget: null, trendFlat: true };
  }
  const sessionsNeeded = Math.max(0, Math.ceil((TARGET_PCT - currentProj) / slope));
  // Convert sessions to days using observed session cadence
  const firstDate = new Date(recent[0].date).getTime();
  const lastDate  = new Date(recent[recent.length - 1].date).getTime();
  const daySpan   = Math.max(1, (lastDate - firstDate) / 86400000);
  const sessionsPerDay = n / daySpan; // sessions per calendar day in the window
  const daysToTarget = sessionsPerDay > 0 ? Math.ceil(sessionsNeeded / sessionsPerDay) : null;
  return { slope, currentProj, sessionsToTarget: sessionsNeeded, daysToTarget, trendFlat: false };
}

// ── Per-question-type accuracy tracking (MCQ vs PBQ) ──
function getTypeStats() {
  try { return JSON.parse(localStorage.getItem(STORAGE.TYPE_STATS) || '{}'); } catch { return {}; }
}
function updateTypeStat(type, wasCorrect) {
  if (!type) type = 'mcq';
  try {
    const stats = getTypeStats();
    if (!stats[type]) stats[type] = { seen: 0, correct: 0 };
    stats[type].seen++;
    if (wasCorrect) stats[type].correct++;
    localStorage.setItem(STORAGE.TYPE_STATS, JSON.stringify(stats));
    _cloudFlush(STORAGE.TYPE_STATS);
  } catch {}
}

// ── Milestones tracking ──
function getMilestones() {
  try { return JSON.parse(localStorage.getItem(STORAGE.MILESTONES) || '{}'); } catch { return {}; }
}
function unlockMilestone(key) {
  const m = getMilestones();
  if (m[key]) return false;
  m[key] = new Date().toISOString();
  try { localStorage.setItem(STORAGE.MILESTONES, JSON.stringify(m)); _cloudFlush(STORAGE.MILESTONES); } catch {}
  return true;
}

