// ── Milestone evaluation — table-driven (v4.42.5) ───────────────────────
// Previously `evaluateMilestones` was a 151-line function with 29 `maybe(id, cond)`
// calls interleaved with context-building logic (fetching history, computing
// weekMap, reading localStorage, defensive try/catch around optional drill APIs).
// Refactored into three pieces:
//   1. `_buildMilestoneCtx()` — gathers ALL the data once into one context object
//   2. `MILESTONE_CHECKS` — declarative table of { id, check(ctx) } predicates
//   3. `evaluateMilestones()` — tight loop, under 10 lines
// Same 47 milestones, same behavior, same return shape. Table form makes it
// trivial to add a new milestone (one entry) and keeps the function under the
// 80-line threshold (#141).

function _buildMilestoneCtx() {
  const h = loadHistory();
  const totalQs = h.reduce((a, e) => a + e.total, 0);
  const studied = new Set(h.filter(e => e.topic !== MIXED_TOPIC && e.topic !== EXAM_TOPIC).map(e => e.topic));
  // v4.85.20: count actual exam SUMMARY entries only (one per exam, topic === EXAM_TOPIC).
  // Without this filter, the per-topic splits (~50 per 90-Q exam) inflate milestone
  // counts like "10 exams completed" — a single exam would unlock it.
  const exams = h.filter(e => e.mode === 'exam' && e.topic === EXAM_TOPIC);
  const readiness = (typeof document !== 'undefined' && document.querySelector('#topic-group')) ? getReadinessScore() : null;
  const streak = getStreakData();
  const allDomainsHit = new Set(Array.from(studied).map(t => TOPIC_DOMAINS[t]).filter(Boolean));
  const allTopicCount = Object.keys(TOPIC_DOMAINS).length;
  const subStats = (typeof getSubnetStats === 'function') ? getSubnetStats() : { seen: 0 };
  const portBest = parseInt(localStorage.getItem(STORAGE.PORT_BEST) || '0');
  const portStreakBest = parseInt(localStorage.getItem(STORAGE.PORT_STREAK_BEST) || '0');
  const portStats = (typeof getPortStatsSummary === 'function') ? getPortStatsSummary() : { uniqueSeen: 0, totalPorts: 0 };
  const ddUses = parseInt(localStorage.getItem(STORAGE.DEEP_DIVE_USES) || '0');
  const dc = getDailyChallenge();

  // Time-of-day + weekend + diversity computations
  const nightOwl = h.some(e => { const hr = new Date(e.date).getHours(); return hr >= 0 && hr < 5; });
  const earlyBird = h.some(e => new Date(e.date).getHours() < 7);
  const weekMap = {};
  h.forEach(e => {
    const d = new Date(e.date), dow = d.getDay();
    if (dow !== 0 && dow !== 6) return;
    const yr = d.getFullYear();
    const start = new Date(yr, 0, 1);
    const key = yr + '-' + Math.floor((d - start) / (7 * 86400000));
    weekMap[key] = weekMap[key] || { sat: false, sun: false };
    if (dow === 6) weekMap[key].sat = true;
    if (dow === 0) weekMap[key].sun = true;
  });
  const weekendWarrior = Object.values(weekMap).some(w => w.sat && w.sun);
  const dayTopics = {};
  h.forEach(e => {
    if (e.topic === MIXED_TOPIC || e.topic === EXAM_TOPIC) return;
    const day = new Date(e.date).toISOString().slice(0, 10);
    dayTopics[day] = dayTopics[day] || new Set();
    dayTopics[day].add(e.topic);
  });
  const diversity5 = Object.values(dayTopics).some(s => s.size >= 5);

  const drill = _buildMilestoneDrillCtx();

  return {
    h, totalQs, studied, exams, readiness, streak, allDomainsHit, allTopicCount,
    subStats, portBest, portStreakBest, portStats, ddUses, dc,
    nightOwl, earlyBird, weekendWarrior, diversity5,
    ...drill,
  };
}

// v4.85.7: extracted from _buildMilestoneCtx() — defensive reads for the
// per-drill mastery counters (labs, A/B drills, OSI drills, cable/connector,
// fix-it). Each block is wrapped in try/catch so a missing optional API or
// stored payload can't break the whole milestone evaluation.
function _buildMilestoneDrillCtx() {
  let labsDone = 0, totalLabs = 22;
  try {
    labsDone = Object.keys(JSON.parse(localStorage.getItem(STORAGE.LAB_COMPLETIONS) || '{}')).length;
    totalLabs = (typeof TB_LABS !== 'undefined') ? TB_LABS.length : 22;
  } catch (_) {}
  let abM = { totalAnswered: 0, perItem: {} }, abSeenCount = 0, abTotalItems = 0;
  try {
    abM = (typeof getAbMastery === 'function') ? getAbMastery() : abM;
    abSeenCount = Object.values(abM.perItem).filter(p => p.seen > 0).length;
    abTotalItems = (typeof AB_DATA !== 'undefined') ? AB_DATA.length : 120;
  } catch (_) {}
  let osM = { totalAnswered: 0, perItem: {} }, osSeenCount = 0, osTotalItems = 0;
  try {
    osM = (typeof getOsMastery === 'function') ? getOsMastery() : osM;
    osSeenCount = Object.values(osM.perItem).filter(p => p.seen > 0).length;
    osTotalItems = (typeof OS_DATA !== 'undefined') ? OS_DATA.length : 50;
  } catch (_) {}
  let cbM = { totalAnswered: 0, perItem: {} }, cbSeenCount = 0, cbTotalItems = 0;
  try {
    cbM = (typeof getCbMastery === 'function') ? getCbMastery() : cbM;
    cbSeenCount = Object.values(cbM.perItem).filter(p => p.seen > 0).length;
    cbTotalItems = ((typeof CB_CABLES !== 'undefined') ? CB_CABLES.length : 15) + ((typeof CB_CONNECTORS !== 'undefined') ? CB_CONNECTORS.length : 13);
  } catch (_) {}
  let fixDone = 0, fixAllEasy = false;
  try {
    const fixSaved = JSON.parse(localStorage.getItem(STORAGE.FIX_CHALLENGES) || '{}');
    fixDone = Object.keys(fixSaved).length;
    if (typeof TB_FIX_CHALLENGES !== 'undefined') {
      const easyIds = TB_FIX_CHALLENGES.filter(c => c.difficulty === 'Easy').map(c => c.id);
      fixAllEasy = easyIds.length > 0 && easyIds.every(id => fixSaved[id]);
    }
  } catch (_) {}
  return {
    labsDone, totalLabs,
    abM, abSeenCount, abTotalItems,
    osM, osSeenCount, osTotalItems,
    cbM, cbSeenCount, cbTotalItems,
    fixDone, fixAllEasy,
  };
}

// Helper: scaled exam score per CompTIA's 100-900 scale (used by exam_pass + hardcore_pass)
function _scaledExamScore(e) { return Math.round(100 + (e.score / e.total) * 800); }

// v4.81.13: per-topic exam split (Codex r∞ user request). Pre-fix the
// exam summary row tagged `topic: EXAM_TOPIC` was filtered out by every
// per-topic surface (readiness, progress, analytics, weak-spots,
// what-if attribution). The wrong-bank + SR queue seeded fine but
// the headline metrics ignored the exam entirely. Fix: after the
// summary row is saved, group log[] by q.topic and write one history
// row per topic with `mode: 'exam'` (so the existing 1.3× exam boost
// in buildWeightedTopicMap applies) and `via: 'exam-split'` (marker
// so we can distinguish these from regular exam summary rows).
//
// No double-counting: getReadinessScore filters EXAM_TOPIC (the
// summary) explicitly, so only the per-topic splits contribute.
function _saveExamPerTopicSplit(log, hardcore) {
  if (!Array.isArray(log) || log.length === 0) return 0;
  const byTopic = {};
  log.forEach(entry => {
    const q = entry && entry.q;
    if (!q) return;
    const t = q.topic;
    if (!t || t === MIXED_TOPIC || t === EXAM_TOPIC) return;
    if (!byTopic[t]) byTopic[t] = { correct: 0, total: 0 };
    byTopic[t].total++;
    if (entry.isRight && !entry.isSkipped) byTopic[t].correct++;
  });
  const date = new Date().toISOString();
  let written = 0;
  Object.keys(byTopic).forEach(topic => {
    const b = byTopic[topic];
    if (b.total < 1) return;
    const pct = Math.round((b.correct / b.total) * 100);
    saveToHistory({
      date, topic, difficulty: 'Mixed',
      score: b.correct, total: b.total, pct,
      mode: 'exam', hardcore: !!hardcore,
      via: 'exam-split'
    });
    written++;
  });
  return written;
}

// v4.81.13: per-domain breakdown for the exam-results page. Same input
// (log[]) as _saveExamPerTopicSplit. Returns { domainKey: {correct,
// total, pct} } for all 5 N10-009 domains. Domains with zero questions
// contribute an empty bucket so the rendered grid stays consistent
// (renders as "—" rather than missing entirely).
function _buildExamDomainBreakdown(log) {
  const buckets = {};
  Object.keys(DOMAIN_WEIGHTS).forEach(d => {
    buckets[d] = { key: d, label: DOMAIN_LABELS[d], correct: 0, total: 0 };
  });
  if (!Array.isArray(log)) return buckets;
  log.forEach(entry => {
    const q = entry && entry.q;
    if (!q || !q.topic) return;
    const domain = (typeof TOPIC_DOMAINS !== 'undefined') ? TOPIC_DOMAINS[q.topic] : null;
    if (!domain || !buckets[domain]) return;
    buckets[domain].total++;
    if (entry.isRight && !entry.isSkipped) buckets[domain].correct++;
  });
  Object.keys(buckets).forEach(d => {
    const b = buckets[d];
    b.pct = b.total > 0 ? Math.round((b.correct / b.total) * 100) : null;
    // tier mirrors the v4.85.11 anchored thresholds (55/70/80; lowered from 85)
    if (b.pct === null) b.tier = 'empty';
    else if (b.pct >= 80) b.tier = 'mastered';
    else if (b.pct >= 70) b.tier = 'proficient';
    else if (b.pct >= 55) b.tier = 'developing';
    else b.tier = 'novice';
  });
  return buckets;
}

function renderExamDomainBreakdown(log) {
  const host = document.getElementById('exam-domain-breakdown');
  const grid = document.getElementById('exam-domain-breakdown-grid');
  if (!host || !grid) return;
  const buckets = _buildExamDomainBreakdown(log);
  // Show domains in CompTIA blueprint order (concepts → troubleshooting for
  // Network+, concepts → governance for Security+).
  // v4.88.2: cert-aware ordering so the post-exam breakdown shows the right
  // 5 domains for the active cert.
  const order = (typeof DOMAIN_WEIGHTS === 'object' && DOMAIN_WEIGHTS)
    ? Object.keys(DOMAIN_WEIGHTS)
    : ['concepts', 'implementation', 'operations', 'security', 'troubleshooting'];
  const html = order.map(d => {
    const b = buckets[d];
    const pctStr = b.pct === null ? '—' : (b.pct + '%');
    const detail = b.total > 0 ? (b.correct + ' of ' + b.total + ' correct') : 'No questions in this exam';
    return '<div class="exam-domain-row exam-domain-' + b.tier + '">' +
      '<div class="exam-domain-row-meta">' +
      '<div class="exam-domain-row-name">' + escHtml(b.label) + '</div>' +
      '<div class="exam-domain-row-detail">' + escHtml(detail) + '</div>' +
      '</div>' +
      '<div class="exam-domain-row-pct">' + pctStr + '</div>' +
      '</div>';
  }).join('');
  grid.innerHTML = html;
  host.hidden = false;
}

