function evaluateMilestones() {
  const ctx = _buildMilestoneCtx();
  const newlyUnlocked = [];
  MILESTONE_CHECKS.forEach(m => {
    try {
      if (m.check(ctx) && unlockMilestone(m.id)) newlyUnlocked.push(m.id);
    } catch (_) { /* individual check failures shouldn't break the whole eval */ }
  });
  return newlyUnlocked;
}

// ── Streak tracking (consecutive study days) ──
function getStreakData() {
  const h = loadHistory();
  if (h.length === 0) return { currentStreak: 0, longestStreak: 0, lastStudyDate: null };
  // Collect unique study days (YYYY-MM-DD)
  const daySet = new Set(h.map(e => new Date(e.date).toISOString().slice(0, 10)));
  const days = Array.from(daySet).sort((a, b) => b.localeCompare(a)); // newest first

  // Current streak: count back from today (or yesterday, if today has no activity)
  const today = new Date();
  const todayKey = today.toISOString().slice(0, 10);
  const yestKey  = new Date(today.getTime() - 86400000).toISOString().slice(0, 10);
  let currentStreak = 0;
  let cursor = daySet.has(todayKey) ? new Date(today) : (daySet.has(yestKey) ? new Date(today.getTime() - 86400000) : null);
  while (cursor) {
    const key = cursor.toISOString().slice(0, 10);
    if (daySet.has(key)) {
      currentStreak++;
      cursor = new Date(cursor.getTime() - 86400000);
    } else {
      break;
    }
  }
  // Longest streak: scan all days for the longest consecutive run
  const sortedAsc = [...daySet].sort();
  let longestStreak = 0, run = 0, prev = null;
  sortedAsc.forEach(d => {
    if (prev === null) { run = 1; }
    else {
      const gap = (new Date(d).getTime() - new Date(prev).getTime()) / 86400000;
      run = (gap === 1) ? run + 1 : 1;
    }
    if (run > longestStreak) longestStreak = run;
    prev = d;
  });
  return { currentStreak, longestStreak, lastStudyDate: days[0] };
}

// ── Subtopic weak-spot mining from wrong bank (keyword frequency) ──
const SUBTOPIC_KEYWORDS = [
  // Routing
  'OSPF', 'BGP', 'EIGRP', 'RIP', 'LSA', 'route summarization', 'autonomous system',
  // Subnetting
  'subnet mask', 'CIDR', 'VLSM', 'supernet', 'broadcast address', 'usable hosts',
  // Switching
  'VLAN', 'trunk', 'spanning tree', 'STP', 'RSTP', 'port-channel', 'EtherChannel', 'native VLAN',
  // IPv6
  'EUI-64', 'SLAAC', 'link-local', 'anycast', 'IPv6 header',
  // Wireless
  'WPA3', 'WPA2', 'EAP', 'PSK', '802.11', 'roaming', 'channel bonding',
  // Security
  'IPsec', 'IKE', 'ESP', 'AH', 'tunnel mode', 'transport mode', 'RADIUS', 'TACACS', 'Kerberos',
  // DNS / DHCP
  'DHCP relay', 'scope', 'reservation', 'DNS record', 'PTR', 'MX', 'SRV', 'CNAME', 'DNSSEC',
  // Tools
  'ping', 'traceroute', 'nmap', 'netstat', 'Wireshark', 'tcpdump', 'SNMP', 'syslog',
  // NAT
  'PAT', 'static NAT', 'port forwarding', 'NAT overload', 'inside local',
  // PBQ-specific
  'topology', 'firewall zone', 'DMZ'
];
function mineSubtopicWeakSpots(limit = 8) {
  const bank = loadWrongBank();
  if (bank.length === 0) return [];
  const counts = {};
  bank.forEach(b => {
    const text = ((b.question || '') + ' ' + (b.explanation || '')).toLowerCase();
    SUBTOPIC_KEYWORDS.forEach(kw => {
      if (text.includes(kw.toLowerCase())) {
        counts[kw] = (counts[kw] || 0) + 1;
      }
    });
  });
  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, limit)
    .map(([keyword, count]) => ({ keyword, count }));
}

// ══════════════════════════════════════════
// v4.10 FRONT PAGE FEATURES
// ══════════════════════════════════════════

// ── Daily Challenge ──
function getDailyChallenge() {
  try {
    const raw = localStorage.getItem(STORAGE.DAILY_CHALLENGE);
    if (!raw) return { lastCompletedDate: null, currentStreak: 0, bestStreak: 0, totalDone: 0 };
    const obj = JSON.parse(raw);
    return {
      lastCompletedDate: obj.lastCompletedDate || null,
      currentStreak: obj.currentStreak || 0,
      bestStreak: obj.bestStreak || 0,
      totalDone: obj.totalDone || 0,
    };
  } catch { return { lastCompletedDate: null, currentStreak: 0, bestStreak: 0, totalDone: 0 }; }
}
function saveDailyChallenge(data) {
  try { localStorage.setItem(STORAGE.DAILY_CHALLENGE, JSON.stringify(data)); _cloudFlush(STORAGE.DAILY_CHALLENGE); } catch {}
}
function isDailyChallengeDoneToday() {
  const today = new Date().toISOString().slice(0, 10);
  return getDailyChallenge().lastCompletedDate === today;
}
function completeDailyChallenge() {
  const today = new Date().toISOString().slice(0, 10);
  const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
  const dc = getDailyChallenge();
  if (dc.lastCompletedDate === today) return dc; // already counted
  dc.currentStreak = (dc.lastCompletedDate === yesterday) ? dc.currentStreak + 1 : 1;
  dc.bestStreak = Math.max(dc.bestStreak, dc.currentStreak);
  dc.lastCompletedDate = today;
  dc.totalDone = (dc.totalDone || 0) + 1;
  saveDailyChallenge(dc);
  return dc;
}
// Deterministic topic for the day: hash YYYY-MM-DD into the topic list
function getDailyChallengeTopic() {
  const today = new Date().toISOString().slice(0, 10);
  let hash = 0;
  for (let i = 0; i < today.length; i++) hash = ((hash << 5) - hash + today.charCodeAt(i)) | 0;
  const topics = Object.keys(TOPIC_DOMAINS);
  return topics[Math.abs(hash) % topics.length];
}

// v5.5.5 — Continue anchor. The right rail's ALWAYS-present bottom: on a
// low-data account #hero-v2-cta (NBM) + #sr-review-card collapse and the
// tall left column leaves dead space below Daily Challenge. This card is
// always rendered (never is-hidden) so the rail can't collapse, and it is
// always prescriptive — re-entry + proof of motion (the one job nothing
// else on Home has: NBM = what's optimal, SR = cards due, Daily Challenge
// = the 1-Q habit, Today's Plan = the 5-topic route; this = pick your
// thread back up). Reads existing signals only; zero new storage.
function renderContinueCard() {
  const card = document.getElementById('continue-card');
  if (!card) return;
  let hist = [];
  // v5.5.7: cert-scope. Quiz history + wrong bank are global per user but
  // topics belong to a specific cert (the v4.99.26 cross-cert pattern).
  // Filtering to the current cert means a cert with no own history correctly
  // falls to the "fresh" first-action state instead of leaking the OTHER
  // cert's last session (was showing N10-009 "Cable Issues" in Security+).
  try { hist = (loadHistory() || []).filter(e => e && _isCurrentCertTopic(e.topic)); } catch (_) {}
  const last = (hist && hist.length) ? hist[0] : null;
  const totalQ = (hist || []).reduce((s, e) => s + (parseInt(e && e.total, 10) || 0), 0);
  const hasHistory = !!last && totalQ > 0;

  const setTxt  = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
  const setHtml = (id, v) => { const el = document.getElementById(id); if (el) el.innerHTML = v; };
  const btn = document.getElementById('cc-action');

  // Zero/low: no real history -> one confident first move (never an empty
  // card; this is what makes the rail un-collapsible).
  if (!hasHistory) {
    card.setAttribute('data-state', 'fresh');
    setTxt('cc-eyebrow-t', 'Start here');
    setTxt('cc-headline', 'You have not built a streak yet');
    setTxt('cc-context', 'A five-minute warm-up sets your first readiness score and starts the chain.');
    setTxt('cc-action-t', 'Take the 5-min Warmup');
    if (btn) btn.onclick = function () { try { applyPreset('warmup'); } catch (_) {} };
    return;
  }

  card.setAttribute('data-state', 'returning');
  let streak = 0;
  try { streak = getStreak().current || 0; } catch (_) {}
  const todayN = (typeof getTodayQuestionCount === 'function') ? (getTodayQuestionCount() || 0) : 0;
  setTxt('cc-m1n', streak);
  setTxt('cc-m2n', todayN);
  setTxt('cc-m3n', totalQ);

  let daysAgo = 0;
  try {
    const t = new Date(last.date).getTime();
    if (!isNaN(t)) daysAgo = Math.max(0, Math.floor((Date.now() - t) / 86400000));
  } catch (_) {}
  const whenStr = daysAgo === 0 ? 'today' : daysAgo === 1 ? 'yesterday' : daysAgo + ' days ago';
  const lastScore = (parseInt(last.score, 10) || 0) + ' / ' + (parseInt(last.total, 10) || 0);
  const lastTopic = String(last.topic || 'your last topic');

  let wrongN = 0;
  // v5.5.7: cert-scope the wrong-bank count too (entries carry .topic) so
  // "N still in your wrong bank" / "Drill the N you missed" reflect only the
  // current cert. If the current cert has 0 wrongs the wrong-path is skipped
  // (gated on wrongN > 0) and the cert-filtered weak path takes over.
  try { wrongN = (loadWrongBank() || []).filter(w => w && _isCurrentCertTopic(w.topic)).length; } catch (_) {}

  setTxt('cc-eyebrow-t', 'Pick up where you left off');

  if (wrongN > 0) {
    // Highest-leverage re-entry: re-test the misses.
    setTxt('cc-headline', lastTopic);
    setHtml('cc-context', 'Last session <b>' + escHtml(lastScore) + '</b> · ' + escHtml(whenStr) + ' · ' + wrongN + ' still in your wrong bank.');
    setTxt('cc-action-t', wrongN === 1 ? 'Drill the 1 you missed' : 'Drill the ' + wrongN + ' you missed');
    if (btn) btn.onclick = function () { try { startWrongDrill(); } catch (_) {} };
    return;
  }

  // No pending misses -> resume the weakest topic from the same plan
  // signals Today's Plan uses.
  let weakTopic = null;
  try {
    const plan = (typeof buildSessionPlan === 'function') ? buildSessionPlan(SESSION_TOPICS) : null;
    if (plan && plan.length) { const w = plan.find(i => i && i.signal === 'weak') || plan[0]; weakTopic = w && w.topic; }
  } catch (_) {}

  if (weakTopic) {
    setTxt('cc-headline', String(weakTopic));
    setHtml('cc-context', 'Last session <b>' + escHtml(lastScore) + '</b> on ' + escHtml(lastTopic) + ' · ' + escHtml(whenStr) + '. This is your weakest area now.');
    setTxt('cc-action-t', 'Resume weak spots');
    if (btn) btn.onclick = function () { try { focusTopic(weakTopic); } catch (_) {} };
  } else {
    setTxt('cc-headline', lastTopic);
    setHtml('cc-context', 'Last session <b>' + escHtml(lastScore) + '</b> · ' + escHtml(whenStr) + '. Keep the chain going.');
    setTxt('cc-action-t', 'Continue weak spots');
    if (btn) btn.onclick = function () { try { applyPreset('focused'); } catch (_) {} };
  }
}

function renderDailyChallengeCard() {
  const card = document.getElementById('daily-challenge-card');
  if (!card) return;
  // Once today's challenge is done, hide the card entirely until tomorrow.
  if (isDailyChallengeDoneToday()) {
    card.classList.add('is-hidden');
    card.classList.remove('dc-done', 'dc-pending');
    return;
  }
  const dc = getDailyChallenge();
  const topicToday = getDailyChallengeTopic();
  const streakText = dc.currentStreak > 0
    ? `${dc.currentStreak}-day streak${dc.bestStreak > dc.currentStreak ? ' · Best ' + dc.bestStreak : ''}`
    : 'Start your streak today';
  card.innerHTML = `
    <div class="dc-icon">🎯</div>
    <div class="dc-body">
      <div class="dc-title">DAILY CHALLENGE</div>
      <div class="dc-sub">One question · Topic: <strong>${escHtml(topicToday)}</strong> · ${escHtml(streakText)}</div>
    </div>
    <button class="dc-btn" onclick="startDailyChallenge()">Play →</button>
  `;
  card.classList.add('dc-pending');
  card.classList.remove('dc-done');
  card.classList.remove('is-hidden');
}
async function startDailyChallenge() {
  const key = (document.getElementById('api-key').value || localStorage.getItem(STORAGE.KEY) || '').trim();
  const errBox = document.getElementById('setup-err');
  if (errBox) errBox.classList.add('is-hidden');
  const keyErr = validateApiKey(key);
  if (keyErr) {
    if (errBox) { errBox.textContent = keyErr; errBox.classList.remove('is-hidden'); }
    return;
  }
  // Configure the quiz: 1 question, Exam Level, date-seeded topic
  const dcTopic = getDailyChallengeTopic();
  topic = dcTopic;
  diff = DEFAULT_DIFF;
  qCount = 1;
  dailyChallengeMode = true;
  document.querySelectorAll('#topic-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === dcTopic));
  document.querySelectorAll('#diff-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === DEFAULT_DIFF));
  document.querySelectorAll('#count-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === '1' || c.dataset.v === '5'));
  syncChipAriaPressed('#topic-group');
  syncChipAriaPressed('#diff-group');
  syncChipAriaPressed('#count-group');
  startQuiz();
}

// ── Weak Spots v2 (v4.38.7) — robust, real-time ranking ──
// Previous heuristic was +2 per wrong-bank entry and a flat +pct gap for
// topics under 75% — no recency, no confidence interval, no difficulty
// weighting, no domain importance. This rewrite scores every topic with a
// real model so the front-page "🎯 Weak spots" chips actually point at the
// topic most worth drilling *right now*. The four signals combined:
//
//   1. Recent wrongs (half-life 7d)        — exponential decay over wrong-bank
//      entries, difficulty-weighted via diffWeight(), half-credit for entries
//      that have already been re-answered correctly once (rightCount >= 1).
//   2. Accuracy gap (Bayesian posterior)    — recency-decayed weighted
//      correct/total from history (14-day half-life, exam boost 1.3x,
//      difficulty-weighted), smoothed with a Beta(2,2) prior so fresh topics
//      don't instantly flag on one bad run. Gap = max(0, 0.85 - posterior).
//   3. Staleness                           — topics untouched >14 days start
//      accruing up to a 2.0 multiplier so a topic you studied once and never
//      revisited doesn't fade off the radar.
//   4. Domain importance                   — multiplied by DOMAIN_WEIGHTS /
//      average (0.2), so a weak Troubleshooting topic (24%) outranks a weak
//      Security topic (14%) at equal raw badness — matches the real N10-009
//      domain distribution.
//
// Topics with zero signal (no wrong-bank, no history) are *excluded* — they
// are "untouched", not "weak". This keeps the chip row pointing at what you
// studied badly, not what you haven't studied yet (that's what Study Plan is
// for). Real-time: the calculation reads localStorage fresh every render and
// is called from finish(), submitExam(), and goSetup() so any quiz or exam
// completion updates the front-page chips immediately.
const WEAK_HALF_LIFE_WRONGS_MS = 7  * 86400000; // 7d recency half-life for wrong bank
const WEAK_HALF_LIFE_HIST_MS   = 14 * 86400000; // 14d half-life for history accuracy
const WEAK_TARGET_ACC          = 0.80;          // mastery threshold (Bayesian gap = 0.80 - posterior; v4.85.11: lowered from 0.85)
const WEAK_STALENESS_DAYS      = 14;            // untouched grace period
const WEAK_STALENESS_CAP       = 2.0;           // max staleness multiplier
const WEAK_AVG_DOMAIN_WEIGHT   = 0.2;           // avg of the 5 DOMAIN_WEIGHTS values

function _weakDecay(ageMs, halfLifeMs) {
  if (ageMs <= 0) return 1;
  return Math.pow(0.5, ageMs / halfLifeMs);
}
function _weakDomainMultiplier(topicName) {
  const dom = TOPIC_DOMAINS[topicName];
  if (!dom) return 1.0;
  const w = DOMAIN_WEIGHTS[dom] || WEAK_AVG_DOMAIN_WEIGHT;
  return w / WEAK_AVG_DOMAIN_WEIGHT; // range ~0.7 (security) to ~1.2 (troubleshooting)
}
function computeWeakSpotScores() {
  const bank = loadWrongBank();
  // v4.59.7: expand pre-v4.57.1 multi-topic sentinel rows into per-topic
  // rows so the history loop below credits the real topics rather than a
  // nonsense sentinel key. See _expandHistoryForWeakSpots for details.
  const rawHist = loadHistory().filter(e =>
    e.topic && e.topic !== MIXED_TOPIC && e.topic !== EXAM_TOPIC
  );
  const hist = _expandHistoryForWeakSpots(rawHist);
  const now = Date.now();
  const topicData = {};
  const touch = t => {
    if (!topicData[t]) topicData[t] = {
      topic: t,
      wrongsRecent: 0,    // decayed, difficulty-weighted wrong-bank count
      wrongsRaw: 0,       // untouched count for display
      wCorrect: 0,        // weighted correct answers (history)
      wTotal: 0,          // weighted question volume (history)
      lastTouch: 0,       // max of history & wrong-bank timestamps
      totalQuestions: 0   // raw total across history (for display)
    };
    return topicData[t];
  };

  bank.forEach(w => {
    if (!w.topic || w.topic === MIXED_TOPIC || w.topic === EXAM_TOPIC) return;
    const d = touch(w.topic);
    const ts = w.addedDate ? new Date(w.addedDate).getTime() : now;
    const age = Math.max(0, now - ts);
    const decay = _weakDecay(age, WEAK_HALF_LIFE_WRONGS_MS);
    const dw = diffWeight(w.difficulty);
    // Half-credit once an entry has been re-answered correctly once (one more
    // right answer and it graduates out of the bank entirely — don't keep
    // punishing the topic for a nearly-learned mistake).
    const graduationDiscount = (w.rightCount || 0) >= 1 ? 0.5 : 1.0;
    d.wrongsRecent += decay * dw * graduationDiscount;
    d.wrongsRaw += 1;
    if (ts > d.lastTouch) d.lastTouch = ts;
  });

  hist.forEach(e => {
    const d = touch(e.topic);
    const ts = new Date(e.date).getTime();
    const age = Math.max(0, now - ts);
    const decay = _weakDecay(age, WEAK_HALF_LIFE_HIST_MS);
    const dw = diffWeight(e.difficulty);
    const modeBoost = (e.mode === 'exam') ? 1.3 : 1.0;
    const w = decay * dw * modeBoost;
    d.wCorrect += (e.score || 0) * w;
    d.wTotal   += (e.total || 0) * w;
    d.totalQuestions += (e.total || 0);
    if (ts > d.lastTouch) d.lastTouch = ts;
  });

  const rows = [];
  Object.values(topicData).forEach(d => {
    // Require at least *some* signal — a single fading wrong-bank entry or a
    // thin history footprint. Everything below this is indistinguishable
    // from untouched.
    if (d.wTotal < 1 && d.wrongsRecent < 0.5) return;
    // Bayesian posterior mean with Beta(2,2) prior. Prior acts like 2 correct
    // and 2 wrong "ghost" answers, smoothing tiny samples toward 0.5 so a
    // single bad 5-Q run doesn't instantly dominate the ranking.
    const posterior = (d.wCorrect + 2) / (d.wTotal + 4);
    const accGap = Math.max(0, WEAK_TARGET_ACC - posterior);
    // Staleness: days past the untouched grace period, normalized.
    const daysSince = d.lastTouch ? (now - d.lastTouch) / 86400000 : 9999;
    const stalenessRaw = Math.max(0, (daysSince - WEAK_STALENESS_DAYS) / WEAK_STALENESS_DAYS);
    const staleness = Math.min(WEAK_STALENESS_CAP, stalenessRaw);
    const domainMul = _weakDomainMultiplier(d.topic);
    // Combined score. Weights chosen so recent wrongs dominate when fresh,
    // accuracy gap dominates when you've built real volume, and staleness
    // keeps slowly-decaying topics on the radar.
    const base =
      d.wrongsRecent * 3.0 +
      accGap         * 25.0 +
      staleness      * 2.0;
    const score = base * domainMul;
    if (score <= 0) return;
    rows.push({
      topic: d.topic,
      score,
      posterior,
      accuracyGap: accGap,
      wrongsRecent: d.wrongsRecent,
      wrongsRaw: d.wrongsRaw,
      staleness,
      daysSince: Math.round(daysSince),
      domainMul,
      totalQuestions: d.totalQuestions
    });
  });
  rows.sort((a, b) => b.score - a.score);
  return rows;
}
// Backward-compat shim — existing callers (Focused preset, etc.) still expect
// just the top N topic names. New detail-view code uses computeWeakSpotScores
// directly.
function getTodaysFocusTopics(limit = 2) {
  return computeWeakSpotScores().slice(0, limit).map(r => r.topic);
}

// ── v4.81.15: Stale-topic surfacing (rotation algorithm) ─────────────
// Identifies topics the student hasn't practised in WEAK_STALENESS_DAYS+
// AND surfaces them with a *compound* priority weight: priority =
// daysSince × (1 + accuracyGap). A topic last seen 21d ago at 50% accuracy
// outranks one last seen 28d ago at 90% accuracy — the second is more
// stale by raw days, but the first has more learning value to reclaim.
// Reuses computeWeakSpotScores for posterior accuracy + decayed staleness;
// supplements with raw history scan so single-attempt topics (which the
// weak-spot scorer's low-signal filter excludes) still show up here.
//
// Includes never-studied topics — they're infinitely stale by definition.
// Caller can pass sliceIdx + sliceSize to rotate through the stale set
// across multiple batches in the same exam (per-batch rotation amplifier).
//
// Returns [{ topic, daysSince, posterior, accGap, neverStudied, priority }].
const STALE_PROMPT_TOPIC_COUNT = 10;        // injected into Haiku prompt
const STALE_PROMPT_SLICE_SIZE  = 10;        // rotation window
const STALE_CHIP_TOPIC_COUNT   = 5;         // surfaced in homepage chip row
const STALE_CHIP_MIN_HISTORY   = 5;         // min history rows before chip row appears
function _computeStaleTopics(historyRows, n, sliceIdx, sliceSize) {
  if (typeof TOPIC_DOMAINS === 'undefined') return [];
  if (typeof n !== 'number' || n <= 0) return [];

  const now = Date.now();
  const lastSeen = {};
  const accSignal = {};

  // Pull posterior accuracy + recent last-seen from computeWeakSpotScores
  // (it has the Bayesian Beta(2,2) prior + recency-decayed accuracy that
  // we want for the accuracy gap factor).
  let scored = [];
  try {
    if (typeof computeWeakSpotScores === 'function') scored = computeWeakSpotScores();
  } catch (_) { scored = []; }
  scored.forEach(r => {
    if (!r || !r.topic) return;
    accSignal[r.topic] = r.posterior;
    if (typeof r.daysSince === 'number' && r.daysSince < 9000) {
      lastSeen[r.topic] = now - (r.daysSince * 86400000);
    }
  });

  // Walk raw history for topics computeWeakSpotScores filtered out (single
  // attempt under wTotal<1 && wrongsRecent<0.5). Even one attempt is
  // enough to track last-seen-ness for the staleness signal.
  const hist = (Array.isArray(historyRows) ? historyRows : [])
    .filter(e => e && e.topic && e.topic !== MIXED_TOPIC && e.topic !== EXAM_TOPIC);
  hist.forEach(e => {
    const ts = new Date(e.date).getTime();
    if (!isFinite(ts)) return;
    if (!lastSeen[e.topic] || ts > lastSeen[e.topic]) {
      lastSeen[e.topic] = ts;
    }
  });

  // Score every topic in TOPIC_DOMAINS — including never-touched ones.
  const rows = [];
  Object.keys(TOPIC_DOMAINS).forEach(t => {
    const lastTs = lastSeen[t];
    const daysSince = (typeof lastTs === 'number' && lastTs > 0)
      ? Math.max(0, (now - lastTs) / 86400000)
      : 9999;
    if (daysSince < WEAK_STALENESS_DAYS) return; // not stale yet — skip
    const posterior = (typeof accSignal[t] === 'number') ? accSignal[t] : 0.5;
    const accGap = Math.max(0, WEAK_TARGET_ACC - posterior);
    // Compound priority: stale AND weak ranks above stale-but-mastered.
    // accGap is in [0, 0.85]; (1 + accGap) is in [1, 1.85]. A topic at
    // 50% accuracy (gap 0.35) gets ~1.35× the weight of a same-stale topic
    // at 85% (gap 0). Untouched topics use 0.5 posterior — neutral midpoint
    // so they don't dominate over genuinely-weak studied topics.
    const priority = daysSince * (1 + accGap);
    rows.push({
      topic: t,
      daysSince: Math.round(daysSince),
      posterior,
      accGap,
      neverStudied: !lastTs,
      priority
    });
  });
  rows.sort((a, b) => b.priority - a.priority);

  // Slice rotation: each call with a different sliceIdx returns an
  // overlapping but rotated window of n topics. step = floor(size/2)
  // so consecutive slices overlap by ~50% → coverage continuity stays
  // intact even when the stale pool is small. No slicing → top n.
  if (typeof sliceIdx !== 'number' || typeof sliceSize !== 'number' || sliceSize <= 0 || rows.length === 0) {
    return rows.slice(0, n);
  }
  const step = Math.max(1, Math.floor(sliceSize / 2));
  const start = (sliceIdx * step) % rows.length;
  const sliced = [];
  for (let i = 0; i < n && sliced.length < n; i++) {
    sliced.push(rows[(start + i) % rows.length]);
  }
  return sliced;
}

function _formatStaleTopicsForPrompt(staleTopics) {
  if (!Array.isArray(staleTopics) || staleTopics.length === 0) return '';
  const lines = staleTopics.map(s => {
    const accNote = s.neverStudied
      ? 'never studied'
      : `last seen ${s.daysSince}d ago, ~${Math.round(s.posterior * 100)}% accuracy`;
    return `- "${s.topic}" (${accNote})`;
  }).join('\n');
  return `\n\nROTATION PRIORITY: the student hasn't practised these ${staleTopics.length} topics in a while AND/OR has historically struggled with them. If any of these topics appears in the TOPIC LOTTERY above, dig deeper — pick the trickier exam edge cases for that topic, not the easy recall question. Do NOT add or substitute topics; the lottery is fixed:\n${lines}`;
}

// ── v4.43.1: Weak-spots → Subnet Trainer bridge ───────────────────────
// The main-page weak-spots chip row historically only offered "drill this
// topic in a quiz." For subnetting / IP-math topics though, the Subnet
// Trainer with its step-by-step binary breakdowns is a far better surface
// than a 10-Q MCQ drill. This map routes weak subnetting topics to the
// Subnet Trainer.
//
// Deliberately scoped to Subnet Trainer only. Topology Builder is kept as
// a standalone activity — not factored into weak-spots routing, because
// topology labs are self-directed exploration rather than reactive drilling.
const WEAK_SPOT_DRILL_BRIDGES = {
  'Subnetting & IP Addressing': { kind: 'subnet', label: 'Drill in Subnet Trainer', icon: '🧮' },
  'IPv6':                       { kind: 'subnet', label: 'Practice IPv6 math',       icon: '🧮' },
  'NAT & IP Services':          { kind: 'subnet', label: 'Drill NAT / IP math',      icon: '🧮' },
};

// v4.43.1: Click handler for the weak-spot → Subnet Trainer bridge.
function openWeakSpotBridge(kind) {
  if (kind === 'subnet') {
    showPage('subnet');
    if (typeof startSubnetTrainer === 'function') startSubnetTrainer();
  }
}
// v4.81.23: legacy renderTodaysFocus + renderRotationChips removed. Both
// were thin shims that delegated to renderTodayPlan. All callers now invoke
// renderTodayPlan directly. The signals these functions used to surface
// (computeWeakSpotScores for weak-spot chips, _computeStaleTopics for
// rotation chips) still drive the consolidated card via buildSessionPlan.
function focusTopic(t) {
  topic = t;
  diff = DEFAULT_DIFF;
  qCount = 10;
  document.querySelectorAll('#topic-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === t));
  document.querySelectorAll('#diff-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === DEFAULT_DIFF));
  document.querySelectorAll('#count-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === '10'));
  syncChipAriaPressed('#topic-group');
  syncChipAriaPressed('#diff-group');
  syncChipAriaPressed('#count-group');
  startQuiz();
}

// ── Streak Defender (amber warning if streak at risk) ──
function renderStreakDefender() {
  const card = document.getElementById('streak-defender');
  if (!card) return;
  const s = getStreak();
  const today = new Date().toISOString().slice(0, 10);
  // Active threat: current streak ≥ 3 AND no activity today yet
  if (s.current >= 3 && s.last !== today) {
    card.innerHTML = `
      <div class="sd-icon">🔥</div>
      <div class="sd-body">
        <div class="sd-title">Don't break your ${s.current}-day streak!</div>
        <div class="sd-sub">One question is all it takes to keep it alive.</div>
      </div>
      <button class="sd-btn" onclick="startStreakSave()">Save streak →</button>
    `;
    card.classList.remove('is-hidden');
  } else {
    card.classList.add('is-hidden');
  }
}
function startStreakSave() {
  // Configure a minimum quiz: 5 questions, mixed, exam level
  topic = MIXED_TOPIC;
  diff = DEFAULT_DIFF;
  qCount = 5;
  document.querySelectorAll('#topic-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === MIXED_TOPIC));
  document.querySelectorAll('#diff-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === DEFAULT_DIFF));
  document.querySelectorAll('#count-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === '5'));
  syncChipAriaPressed('#topic-group');
  syncChipAriaPressed('#diff-group');
  syncChipAriaPressed('#count-group');
  startQuiz();
}

// ── Quiz Presets (3 one-click starting configs) ──
function applyPreset(name) {
  // Bulk Mixed presets — large counts that exceed the single-call ceiling are
  // batched via startBulkQuiz so the AI never gets asked for >20 Qs at once.
  const bulkSizes = { bulk30: 30, bulk45: 45, bulk60: 60 };
  if (bulkSizes[name]) {
    topic = MIXED_TOPIC; diff = 'Exam Level'; qCount = bulkSizes[name];
    document.querySelectorAll('#topic-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === topic));
    document.querySelectorAll('#diff-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === diff));
    document.querySelectorAll('#count-group .chip').forEach(c => c.classList.remove('on'));
    syncChipAriaPressed('#topic-group');
    syncChipAriaPressed('#diff-group');
    syncChipAriaPressed('#count-group');
    startBulkQuiz(qCount);
    return;
  }
  if (name === 'warmup') {
    topic = MIXED_TOPIC; diff = 'Foundational'; qCount = 5;
  } else if (name === 'focused') {
    // Focused: use weakest topic if known, otherwise Smart spaced-rep
    const weakest = (getTodaysFocusTopics(1)[0]) || getSpacedRepTopic() || MIXED_TOPIC;
    topic = weakest; diff = 'Exam Level'; qCount = 10;
  } else if (name === 'grind') {
    topic = MIXED_TOPIC; diff = 'Exam Level'; qCount = 20;
  } else { return; }
  document.querySelectorAll('#topic-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === topic));
  document.querySelectorAll('#diff-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === diff));
  document.querySelectorAll('#count-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === String(qCount)));
  syncChipAriaPressed('#topic-group');
  syncChipAriaPressed('#diff-group');
  syncChipAriaPressed('#count-group');
  startQuiz();
}

// ══════════════════════════════════════════
// v4.81.17: DOMAIN DRILL — fast-path quizzing on all topics in one of the 5
// N10-009 domains. Two surfaces:
//   1. Mode Ladder tile  → applyDomainPreset(key) — fires a 10-Q Exam Level
//      quiz on that domain immediately (one-click flow).
//   2. Custom Quiz pill  → prefillDomainTopics(key) — selects all topic
//      chips in that domain so the user can then customise diff + count
//      and hit Generate (deep-config flow).
// Both reuse the existing multi-topic Custom Quiz infrastructure (chip
// selection state + 'Multi: ...' topic sentinel + startQuiz pipeline) —
// no new fetch path, no new validation surface.
// ══════════════════════════════════════════
let _DOMAIN_TOPICS_CACHE = null;
function _topicsInDomain(domainKey) {
  if (!_DOMAIN_TOPICS_CACHE) {
    _DOMAIN_TOPICS_CACHE = {};
    Object.keys(TOPIC_DOMAINS).forEach(t => {
      const d = TOPIC_DOMAINS[t];
      if (!_DOMAIN_TOPICS_CACHE[d]) _DOMAIN_TOPICS_CACHE[d] = [];
      _DOMAIN_TOPICS_CACHE[d].push(t);
    });
  }
  return _DOMAIN_TOPICS_CACHE[domainKey] || [];
}

// v4.87.1: cert-aware domain index. Network+ has 5 domains:
//   concepts(1), implementation(2), operations(3), security(4), troubleshooting(5)
// Security+ has 5 different domains:
//   concepts(1), threats(2), architecture(3), operations(4), governance(5)
// The 1-5 numeric index is a UI affordance (matches data-domain-idx CSS color
// coding); the actual domain key strings differ per cert. Built from
// CERT_PACK.domainWeights insertion order — JS object key order is preserved
// so this matches the order topics were declared per-domain.
const _DOMAIN_IDX = (() => {
  const idx = {};
  if (CERT_PACK && CERT_PACK.domainWeights) {
    Object.keys(CERT_PACK.domainWeights).forEach((k, i) => { idx[k] = i + 1; });
  } else {
    // Network+ fallback if CERT_PACK failed to load
    idx.concepts = 1; idx.implementation = 2; idx.operations = 3; idx.security = 4; idx.troubleshooting = 5;
  }
  return idx;
})();

// v4.88.0: substitute cert-specific copy in user-visible HTML elements.
// Static HTML ships with Network+ wording (correct for the customer-facing
// deploy). When CURRENT_CERT === 'secplus' this function rewrites strings
// to the active cert's name + code + pass mark. Network+ mode is no-op.
//
// Why post-load substitution: the static HTML stays human-readable (no
// template syntax), Network+ has zero flash, Security+ accepts a tiny
// flash on initial load — acceptable since secplus is the private builder URL.
//
// Targets — the user-visible Network+/N10-009 hardcodes that swap:
//   - .diagnostic-cta-title       "🧪 Where do you stand on N10-009?"
//   - #pass-plan-sub              "...all 5 N10-009 domains"
//   - .results-v2-big-label       "Scaled Score · CompTIA N10-009"
//   - .exam-results-v2-big-label  same
//   - .exam-results-v2-threshold  "Pass mark: 720 / 900 · CompTIA N10-009"
//   - .exam-domain-breakdown-sub  "...each N10-009 domain"
//   - .ed-pagehead-lede (drills)  "Drills for the rote parts of Network+..."
//   - .ed-section-meta            "N10-009 exam weighting"
//   - .hero.is-hidden h1          "Network+ AI Quiz" (legacy hero)
function _renderCertAwareCopy() {
  if (!CERT_PACK || !CERT_PACK.meta) return;
  if (CURRENT_CERT === 'netplus') return; // static HTML correct for Network+
  try {
    const code = CERT_PACK.meta.code; // e.g., 'SY0-701'
    const name = CERT_PACK.meta.name.replace('CompTIA ', ''); // e.g., 'Security+'
    const passMark = CERT_PACK.meta.examPassScore;
    const maxScore = CERT_PACK.meta.examMaxScore;

    // 1. Diagnostic CTA title
    const diagTitle = document.querySelector('.diagnostic-cta-title');
    if (diagTitle && diagTitle.textContent.indexOf('N10-009') !== -1) {
      diagTitle.innerHTML = diagTitle.innerHTML.replace(/N10-009/g, code);
    }

    // 2. Pass plan sub
    const passPlanSub = document.getElementById('pass-plan-sub');
    if (passPlanSub && passPlanSub.textContent.indexOf('N10-009') !== -1) {
      passPlanSub.textContent = passPlanSub.textContent.replace(/N10-009/g, code);
    }

    // 3 + 4. Scaled Score · CompTIA N10-009 labels (results + exam-results)
    document.querySelectorAll('.results-v2-big-label, .exam-results-v2-big-label').forEach(function(el) {
      if (el.innerHTML.indexOf('N10-009') !== -1) {
        el.innerHTML = el.innerHTML.replace(/N10-009/g, code);
      }
    });

    // 5. Pass mark text — also swap the score (Network+ 720 → Security+ 750)
    const threshold = document.querySelector('.exam-results-v2-threshold');
    if (threshold) {
      threshold.innerHTML = 'Pass mark: ' + passMark + ' / ' + maxScore + ' &middot; CompTIA ' + code + ' scaled score';
    }

    // 6. Domain breakdown sub
    const domainSub = document.querySelector('.exam-domain-breakdown-sub');
    if (domainSub && domainSub.textContent.indexOf('N10-009') !== -1) {
      domainSub.textContent = domainSub.textContent.replace(/N10-009/g, code);
    }

    // 7. Drills pagehead lede
    document.querySelectorAll('.ed-pagehead-lede').forEach(function(el) {
      if (el.textContent.indexOf('Network+') !== -1) {
        el.innerHTML = el.innerHTML.replace(/Network\+/g, name);
      }
    });

    // 8. Section meta "N10-009 exam weighting" (anywhere)
    document.querySelectorAll('.ed-section-meta').forEach(function(el) {
      if (el.textContent.indexOf('N10-009') !== -1) {
        el.textContent = el.textContent.replace(/N10-009/g, code);
      }
    });

    // 9. Legacy hero h1 (hidden via .is-hidden, kept for regression-guards)
    const legacyHeroH1 = document.querySelector('.hero.is-hidden h1');
    if (legacyHeroH1 && legacyHeroH1.textContent === 'Network+ AI Quiz') {
      legacyHeroH1.textContent = name + ' AI Quiz';
    }
  } catch (e) {
    if (typeof console !== 'undefined') console.warn('[cert] _renderCertAwareCopy failed:', e.message);
  }
}

// v4.87.1: re-render topic chips + domain pills + Mode Ladder tiles for the
// active cert. Static HTML in index.html is hardcoded for Network+ topics
// (50 chips across 5 N+ domains). When CURRENT_CERT === 'secplus' this
// function rebuilds:
//   1. The 5 <details class="topic-domain-group"> accordions (chip lists)
//   2. The 5 .tdp-pill domain-prefill buttons (label + onclick handler)
//   3. The 5 .dgh-db domain-preset buttons (label + onclick + title)
// Network+ mode is no-op — static HTML is correct for it.
//
// Why re-render at runtime instead of dynamic HTML from scratch: keeps the
// Network+ static HTML untouched (zero behavioral risk for the customer-
// facing deploy) while letting Security+ override at boot. The data-cert
// attribute on <html> set by the inline <head> script controls visibility
// of the per-cert banner; this function controls the chip content.
function _renderTopicChipsForActiveCert() {
  if (!CERT_PACK || !CERT_PACK.topicDomains || !CERT_PACK.domainLabels) return;
  if (CURRENT_CERT === 'netplus') return; // static HTML is correct
  try {
    const domainKeys = Object.keys(CERT_PACK.domainWeights || {});
    if (domainKeys.length !== 5) return; // unexpected blueprint shape

    // Build per-domain topic lists from CERT_PACK.topicDomains
    const topicsByDomain = {};
    Object.keys(CERT_PACK.topicDomains).forEach(t => {
      const d = CERT_PACK.topicDomains[t];
      if (!topicsByDomain[d]) topicsByDomain[d] = [];
      topicsByDomain[d].push(t);
    });

    const escHtml = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');

    // 1. Update the 5 topic-domain-group accordions
    domainKeys.forEach((dKey, i) => {
      const idx = i + 1;
      const accordion = document.querySelector('details.topic-domain-group[data-domain-idx="' + idx + '"]');
      if (!accordion) return;
      const summary = accordion.querySelector('summary');
      const grid = accordion.querySelector('.chip-grid');
      const label = CERT_PACK.domainLabels[dKey] || dKey;
      const weight = CERT_PACK.domainWeights[dKey];
      const weightStr = weight ? Math.round(weight * 100) + '%' : '';
      if (summary) {
        summary.innerHTML = '<span class="dom-name">' + idx + '.0 ' + escHtml(label) + '</span><span class="dom-weight">' + weightStr + '</span>';
      }
      if (grid) {
        const topics = topicsByDomain[dKey] || [];
        grid.innerHTML = topics.map(t => '<button class="chip" data-v="' + escHtml(t) + '">' + escHtml(t) + '</button>').join('');
      }
    });

    // 2. Update the 5 .tdp-pill domain-prefill buttons
    document.querySelectorAll('.tdp-pill').forEach((pill) => {
      const idx = parseInt(pill.dataset.domainIdx, 10);
      const dKey = domainKeys[idx - 1];
      if (!dKey) return;
      const label = CERT_PACK.domainLabels[dKey] || dKey;
      const count = (topicsByDomain[dKey] || []).length;
      pill.textContent = idx + '.0 ' + label;
      pill.setAttribute('onclick', "prefillDomainTopics('" + dKey + "')");
      pill.setAttribute('title', 'Select all ' + count + ' ' + label + ' topics');
    });

    // 3. Update the 5 .dgh-db domain-preset buttons. Inner structure:
    //   <span class="dbk">1.0 · 23%</span>
    //   <span class="dbn">Networking Concepts</span>
    //   <span class="dbm">10 Qs</span>
    document.querySelectorAll('.dgh-db').forEach((btn) => {
      const idx = parseInt(btn.dataset.domainIdx, 10);
      const dKey = domainKeys[idx - 1];
      if (!dKey) return;
      const label = CERT_PACK.domainLabels[dKey] || dKey;
      const weight = CERT_PACK.domainWeights[dKey];
      const count = (topicsByDomain[dKey] || []).length;
      btn.setAttribute('onclick', "applyDomainPreset('" + dKey + "')");
      btn.setAttribute('title', '10 Qs · Exam Level · all ' + count + ' ' + label + ' topics');
      var kSpan = btn.querySelector('.dbk');
      var nSpan = btn.querySelector('.dbn');
      var mSpan = btn.querySelector('.dbm');
      if (kSpan) kSpan.textContent = idx + '.0 · ' + (weight ? Math.round(weight * 100) + '%' : '');
      if (nSpan) nSpan.textContent = label;
      if (mSpan) mSpan.textContent = '10 Qs';
    });
  } catch (e) {
    if (typeof console !== 'undefined') console.warn('[chips] _renderTopicChipsForActiveCert failed:', e.message);
  }
}

function applyDomainPreset(domainKey) {
  const topics = _topicsInDomain(domainKey);
  if (!topics.length) return;
  topic = 'Multi: ' + topics.join(', ');
  diff = 'Exam Level';
  qCount = 10;
  // Sync chip state so the Custom Quiz section reflects what's running.
  const g = document.getElementById('topic-group');
  if (g) {
    g.querySelectorAll('.chip.cq-mode-card').forEach(c => {
      c.classList.remove('on');
      c.setAttribute('aria-pressed', 'false');
    });
    g.querySelectorAll('.chip:not(.cq-mode-card)').forEach(c => {
      const isInDomain = topics.includes(c.dataset.v);
      c.classList.toggle('on', isInDomain);
      c.setAttribute('aria-pressed', isInDomain ? 'true' : 'false');
    });
  }
  document.querySelectorAll('#diff-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === diff));
  document.querySelectorAll('#count-group .chip').forEach(c => c.classList.toggle('on', c.dataset.v === String(qCount)));
  syncChipAriaPressed('#topic-group');
  syncChipAriaPressed('#diff-group');
  syncChipAriaPressed('#count-group');
  startQuiz();
}

function prefillDomainTopics(domainKey) {
  const topics = _topicsInDomain(domainKey);
  if (!topics.length) return;
  const g = document.getElementById('topic-group');
  if (!g) return;
  // Mode cards (Smart / Mixed) contradict explicit domain selection — clear them
  g.querySelectorAll('.chip.cq-mode-card').forEach(c => {
    c.classList.remove('on');
    c.setAttribute('aria-pressed', 'false');
  });
  g.querySelectorAll('.chip:not(.cq-mode-card)').forEach(c => {
    const isInDomain = topics.includes(c.dataset.v);
    c.classList.toggle('on', isInDomain);
    c.setAttribute('aria-pressed', isInDomain ? 'true' : 'false');
  });
  // Update the topic state via the same computer the multi-select handler uses
  if (typeof _computeTopicFromChips === 'function') {
    topic = _computeTopicFromChips();
  }
  // Auto-open the corresponding accordion so the user sees the selection
  const idx = _DOMAIN_IDX[domainKey];
  if (idx) {
    const accordion = g.querySelector('details[data-domain-idx="' + idx + '"]');
    if (accordion) accordion.setAttribute('open', '');
  }
  // Refresh the Custom Quiz summary bar + jump into view
  if (typeof updateCqSummaryBar === 'function') updateCqSummaryBar();
  if (typeof _jumpToCustomQuiz === 'function') _jumpToCustomQuiz();
}

// ══════════════════════════════════════════
// START BULK MIXED QUIZ (batched, for 30/60/100 presets)
// ══════════════════════════════════════════
// Batched mixed quiz for the large preset tiles. The single fetchQuestions
// call is unreliable above ~20 Qs, so we mirror the exam-mode batching: chunk
// the request into 18-Q calls, show a progress bar, and concatenate. The flow
// after assembly is identical to startQuiz() (validation pipeline + render).
async function startBulkQuiz(count) {
  const key = document.getElementById('api-key').value.trim();
  const errBox = document.getElementById('setup-err');
  errBox.classList.add('is-hidden');
  const keyErr = validateApiKey(key);
  if (keyErr) { errBox.textContent = keyErr; errBox.classList.remove('is-hidden'); showSetupError(); return; }
  apiKey = key;
  localStorage.setItem(STORAGE.KEY, key);
  examMode = false;
  wrongDrillMode = false;

  activeQuizTopic = MIXED_TOPIC;
  topic = MIXED_TOPIC;
  diff = 'Exam Level';
  qCount = count;

  showPage('loading');
  document.getElementById('loading-msg').textContent = `Generating ${count} mixed Exam Level questions\u2026`;
  const tb = document.getElementById('topic-brief');
  if (tb) tb.classList.add('is-hidden');

  // v4.82.1: smooth loading bar across marathon mode too.
  _loadingProgressBegin('Generating questions\u2026');
  const lbl = document.getElementById('load-progress-label'); // legacy textContent writes for retry banner

  const BATCH_SIZE = 18, MAX_RETRIES = 2;
  const batches = Math.ceil(count / BATCH_SIZE);
  let collected = [];
  try {
    for (let i = 0; i < batches; i++) {
      const remaining = count - collected.length;
      const thisBatch = Math.min(BATCH_SIZE, remaining);
      _loadingProgressUpdate(`Batch ${i + 1} / ${batches}\u2026`, (i / batches) * 100);
      document.getElementById('loading-msg').textContent = `Generating questions (${collected.length + thisBatch} / ${count})\u2026`;
      let batch = null;
      for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
          // v4.81.15: pass batch index as staleSliceIdx so each marathon
          // batch sees a different rotating window of stale topics \u2014
          // same rotation amplifier as the exam simulator's 5 batches.
          batch = await fetchQuestions(key, MIXED_TOPIC, 'Exam Level', thisBatch, i);
          break;
        } catch(retryErr) {
          if (attempt === MAX_RETRIES) throw retryErr;
          if (lbl) lbl.textContent = `Batch ${i + 1} failed, retrying (${attempt + 1}/${MAX_RETRIES})\u2026`;
          await new Promise(r => setTimeout(r, 1500));
        }
      }
      collected = collected.concat(batch);
    }
    _loadingProgressUpdate('Verifying quality\u2026', 88);
    document.getElementById('loading-msg').textContent = 'Verifying question accuracy\u2026';
    collected = await aiValidateQuestions(key, collected);
    collected = validateQuestions(collected);
    if (collected.length === 0) throw new Error('All generated questions failed validation. Try again.');
    _loadingProgressUpdate('Finalizing…', 95);
    // Enforce target count — truncate extras from AI
    if (collected.length > count) collected = collected.slice(0, count);
  } catch(e) {
    _loadingProgressFinish();
    showPage('setup');
    errBox.textContent = '\u26a0\ufe0f ' + (e.message || 'Failed. Check your API key.');
    errBox.classList.remove('is-hidden');
    return;
  }
  questions = injectPBQs(collected, MIXED_TOPIC, 2);
  current = 0; score = 0; streak = 0; bestStreak = 0; answered = 0; log = [];
  quizFlags = new Array(questions.length).fill(false);
  // v4.82.1: hide loading bar before swapping to the quiz page.
  _loadingProgressFinish();
  showPage('quiz');
  render();
}

function renderReadinessCard() {
  const data     = getReadinessScore();
  const numEl    = document.getElementById('readiness-num');
  const badgeEl  = document.getElementById('readiness-badge');
  const barEl    = document.getElementById('readiness-bar-fill');
  const actionEl = document.getElementById('readiness-action');
  if (!numEl) return;

  if (!data) {
    numEl.textContent    = '\u2014';
    numEl.style.color    = 'var(--text-dim)';
    badgeEl.textContent  = 'Not started';
    badgeEl.style.background = 'var(--surface3)';
    badgeEl.style.color  = 'var(--text-dim)';
    barEl.style.width    = '0%';
    actionEl.innerHTML   = 'Complete your first quiz to activate your readiness score.';
    return;
  }

  const { predicted, raw, worstTopic, worstPct } = data;

  let tierLabel, tierColor, tierBg;
  if (predicted >= EXAM_PASS_SCORE) {
    tierLabel = '\ud83d\udfe2 Exam Ready'; tierColor = 'var(--green)'; tierBg = 'rgba(34,197,94,.15)';
  } else if (predicted >= 650) {
    tierLabel = '\ud83d\udfe0 Getting Close'; tierColor = 'var(--orange)'; tierBg = 'rgba(251,146,60,.15)';
  } else if (predicted >= 500) {
    tierLabel = '\ud83d\udfe1 Building'; tierColor = 'var(--yellow)'; tierBg = 'rgba(251,191,36,.15)';
  } else {
    tierLabel = '\ud83d\udd34 Not Ready'; tierColor = 'var(--red)'; tierBg = 'rgba(248,113,113,.15)';
  }

  const barPct = Math.max(0, Math.min(100, ((predicted - 420) / 450) * 100));

  // v4.42.1: first-render-per-session intro. Number counts from 0 → predicted
  // over 1.4s, bar fills from empty using a slower 1.1s cubic-bezier reveal,
  // then default transitions restore so subsequent updates (quiz return
  // roll-ups from v4.42.0) stay snappy. The flag is consumed on first call
  // with live data so returning from a quiz doesn't replay the intro.
  if (_readinessIntroArmed) {
    _readinessIntroArmed = false;
    animateCount('readiness-num', 0, predicted, 1400);
    barEl.style.transition = 'none';
    barEl.style.width = '0%';
    void barEl.offsetWidth; // force reflow so the next assignment animates
    setTimeout(() => {
      barEl.style.transition = 'width 1.1s cubic-bezier(0.2, 0.8, 0.2, 1)';
      barEl.style.width = barPct + '%';
      setTimeout(() => { barEl.style.transition = ''; }, 1200);
    }, 100);
  } else {
    // v4.42.0: animated roll-up of the readiness score so users see the
    // number climb after a quiz instead of a silent hot-swap. animateCount
    // already no-ops when the value is unchanged or NaN.
    const oldReadinessVal = parseInt(numEl.textContent, 10);
    if (!isNaN(oldReadinessVal) && oldReadinessVal !== predicted) {
      animateCount('readiness-num', oldReadinessVal, predicted, 900);
    } else {
      numEl.textContent = predicted;
    }
    barEl.style.width = barPct + '%';
  }
  numEl.style.color    = tierColor;
  badgeEl.textContent  = tierLabel;
  badgeEl.style.background = tierBg;
  badgeEl.style.color  = tierColor;
  barEl.style.background = tierColor;

  if (worstTopic) {
    const gapText = worstPct === null
      ? '<strong>' + escHtml(worstTopic) + '</strong> \u2014 never studied'
      : '<strong>' + escHtml(worstTopic) + '</strong> \u2014 ' + worstPct + '% avg';
    actionEl.innerHTML = '\u25b2 Biggest gap: ' + gapText + '. Drill it to move the score.';
  } else {
    actionEl.innerHTML = '\u2728 All topics covered. Keep your scores up!';
  }

  // v4.46.1: Exam-date chip — shared builder with Analytics hero card. One
  // click target, merged date + countdown display, no more visible native
  // date input.
  const examRow = document.getElementById('readiness-exam-row');
  if (examRow) {
    const dateStr = getExamDate();
    const days = getDaysToExam();
    examRow.innerHTML = _buildExamDateChipHtml(dateStr, days, 'readiness-exam-input');
  }

  // ── v4.73.0: prediction line + what-if + trajectory ──
  // Populate the new prediction card pieces. Falls back to hidden when the
  // data isn't yet ready (early-session, no questions answered).
  const predEl = document.getElementById('readiness-prediction');
  if (predEl && data.passProbability !== undefined) {
    const probPct = Math.round(data.passProbability * 100);
    let probClass = 'high';
    if (probPct < 50) probClass = 'low';
    else if (probPct < 80) probClass = 'med';
    predEl.innerHTML = '🎯 <strong>' + predicted + '</strong> '
      + '<span class="ci">± ' + data.ciHalfWidth + '</span> '
      + '<span class="sep">·</span> '
      + '<span class="prob ' + probClass + '">' + probPct + '% pass probability</span>';
    predEl.hidden = false;
  } else if (predEl) {
    predEl.hidden = true;
  }

  // What-if chips — top 3 highest-leverage topics
  const whatIfEl = document.getElementById('readiness-whatif');
  const whatIfRow = document.getElementById('readiness-whatif-row');
  if (whatIfEl && whatIfRow && data.whatIf && data.whatIf.length > 0) {
    whatIfRow.innerHTML = data.whatIf.map(w => {
      const safeTopic = (w.topic || '').replace(/'/g, "\\'").replace(/"/g, '&quot;');
      return '<button type="button" class="readiness-whatif-chip" '
        + 'onclick="focusTopic(\'' + safeTopic + '\')" '
        + 'title="Drill ' + escHtml(w.topic) + ' to push your score up">'
        + '<span class="pts">+' + w.deltaPredicted + ' pts</span> '
        + '<span class="topic">' + escHtml(w.topic) + '</span> '
        + '<span class="delta">(' + w.currentPct + '% → 80%)</span>'
        + '</button>';
    }).join('');
    whatIfEl.hidden = false;
  } else if (whatIfEl) {
    whatIfEl.hidden = true;
  }

  // Trajectory: time-bound + confident-pass gap
  const trajEl = document.getElementById('readiness-trajectory');
  if (trajEl) {
    if (data.daysToExam !== null && data.daysToExam !== undefined) {
      if (data.targetGap > 0) {
        const cls = data.targetGap > 60 ? 'warn' : (data.targetGap > 20 ? 'mid' : 'good');
        trajEl.innerHTML = '⏰ <strong>' + data.daysToExam + ' days</strong> to exam &middot; '
          + 'need <strong>+' + data.targetGap + ' pts</strong> for confident pass '
          + '<span class="hint">(lower bound → ' + EXAM_PASS_SCORE + ')</span>';
        trajEl.className = 'readiness-trajectory ' + cls;
        trajEl.hidden = false;
      } else {
        trajEl.innerHTML = '✅ <strong>' + data.daysToExam + ' days</strong> to exam &middot; '
          + 'already confidently above pass.';
        trajEl.className = 'readiness-trajectory good';
        trajEl.hidden = false;
      }
    } else {
      trajEl.hidden = true;
    }
  }
}

// ══════════════════════════════════════════
// TODAY'S SESSION
// ══════════════════════════════════════════
// v4.81.18: rewritten to compose 2 weak + 3 stale (= 5 topics) via the same
// signals already powering the homepage Weak Spots widget and the v4.81.15
// rotation chip row. Falls back to the legacy _scoreTopicNeed ranker when
// either signal is sparse (new users with no history yet) so the plan stays
// non-empty in early-stage usage. Keeps the original return shape
// { topic, reason, color } so all existing consumers (renderTodayPlan,
// startSession, isStudyPlanDoneToday, runSessionStep) work unchanged.
// v4.99.26 — Cert-aware topic filter. Returns true if topic is in the current
// cert's TOPIC_DOMAINS catalog. Prevents cross-cert leakage (e.g., Network+
// 'Network Models & OSI' showing up in Today's Plan when user is on Sec+).
// Quiz history + wrong bank are global per user (one localStorage namespace
// across certs); the active cert filters which topics are surfaced. Defensive
// fallback: if TOPIC_DOMAINS is empty/undefined, allow through so the home
// page never goes blank when called pre-init.
function _isCurrentCertTopic(topic) {
  if (!topic) return false;
  if (typeof TOPIC_DOMAINS === 'undefined' || !TOPIC_DOMAINS) return true;
  const keys = Object.keys(TOPIC_DOMAINS);
  if (!keys.length) return true;
  return Object.prototype.hasOwnProperty.call(TOPIC_DOMAINS, topic);
}

function buildSessionPlan(n) {
  const target = (typeof n === 'number' && n > 0) ? n : SESSION_TOPICS;
  const items = [];
  const taken = new Set();

  const weakColor = '#fbbf24';   // yellow accent — matches consolidated Today card
  const staleColor = '#f59e0b';  // amber — matches v4.81.15 rotation chips

  // ── Top weak spots (recency-decayed wrong-bank + accuracy gap) ──
  // v4.99.26: filter cross-cert leakage — quiz history is global per user
  // but topics belong to a specific cert. Only surface topics in the
  // current cert's TOPIC_DOMAINS catalog.
  let weakRows = [];
  try {
    if (typeof computeWeakSpotScores === 'function') {
      weakRows = computeWeakSpotScores().filter(w => w && _isCurrentCertTopic(w.topic));
    }
  } catch (_) {}
  weakRows.slice(0, TODAY_PLAN_WEAK_COUNT).forEach(w => {
    if (!w || !w.topic || taken.has(w.topic)) return;
    const pct = Math.round((w.posterior || 0) * 100);
    items.push({
      topic: w.topic,
      reason: '~' + pct + '% accuracy',
      color: weakColor,
      signal: 'weak',
      meta: '~' + pct + '% accuracy'
    });
    taken.add(w.topic);
  });

  // ── Stale topics (not seen in WEAK_STALENESS_DAYS+, deduped against weak) ──
  // v4.99.26: same cert-aware filter as weak rows above.
  let staleRows = [];
  try {
    if (typeof _computeStaleTopics === 'function' && typeof loadHistory === 'function') {
      const hist = loadHistory();
      // Request 2× the stale slots so dedup overhead doesn't starve the plan
      staleRows = _computeStaleTopics(hist, TODAY_PLAN_STALE_COUNT * 2)
        .filter(s => s && _isCurrentCertTopic(s.topic));
    }
  } catch (_) {}
  let staleAdded = 0;
  for (const s of staleRows) {
    if (staleAdded >= TODAY_PLAN_STALE_COUNT) break;
    if (!s || !s.topic || taken.has(s.topic)) continue;
    const meta = s.neverStudied ? 'never studied' : (s.daysSince + 'd stale');
    items.push({
      topic: s.topic,
      reason: meta,
      color: staleColor,
      signal: 'stale',
      meta
    });
    taken.add(s.topic);
    staleAdded++;
  }

  // ── Top up with remaining weak spots if still short of target ──
  if (items.length < target) {
    weakRows.slice(TODAY_PLAN_WEAK_COUNT).forEach(w => {
      if (items.length >= target) return;
      if (!w || !w.topic || taken.has(w.topic)) return;
      const pct = Math.round((w.posterior || 0) * 100);
      items.push({
        topic: w.topic,
        reason: '~' + pct + '% accuracy',
        color: weakColor,
        signal: 'weak',
        meta: '~' + pct + '% accuracy'
      });
      taken.add(w.topic);
    });
  }

  // ── Final fallback for sparse-history users: legacy _scoreTopicNeed ranker ──
  // Without this, brand-new users with no weak/stale signal would see an
  // empty plan card. The fallback ensures the plan always has something
  // actionable while the user builds history.
  if (items.length < target && typeof _getAllStudyTopics === 'function' && typeof _scoreTopicNeed === 'function') {
    const allTopics = _getAllStudyTopics();
    const h = (typeof loadHistory === 'function') ? loadHistory().filter(e => e.topic !== MIXED_TOPIC && e.topic !== EXAM_TOPIC) : [];
    const now = Date.now();
    const fallback = allTopics
      .map(t => {
        const { score, reason, color } = _scoreTopicNeed(t, h, now);
        return { topic: t, score, reason, color };
      })
      .sort((a, b) => b.score - a.score);
    for (const f of fallback) {
      if (items.length >= target) break;
      if (taken.has(f.topic)) continue;
      items.push({
        topic: f.topic,
        reason: f.reason,
        color: f.color,
        signal: 'fallback',
        meta: f.reason
      });
      taken.add(f.topic);
    }
  }

  return items.slice(0, target);
}

// Study Plan is "addressed for the day" if the user completed a multi-topic
// session run today, OR they've already drilled each of today's plan topics
// individually today (covered via any non-wrong-drill history entry).
function isStudyPlanDoneToday() {
  const today = new Date().toISOString().slice(0, 10);
  const h = loadHistory();
  const todayEntries = h.filter(e => new Date(e.date).toISOString().slice(0, 10) === today);
  if (todayEntries.some(e => e.mode === 'session')) return true;
  const plan = buildSessionPlan(SESSION_TOPICS);
  if (!plan.length) return false;
  const studiedTopicsToday = new Set(todayEntries.map(e => e.topic));
  return plan.every(item => studiedTopicsToday.has(item.topic));
}

// v4.81.23: legacy renderSessionBanner removed. Was a thin shim that
// delegated to renderTodayPlan. Callers now invoke renderTodayPlan directly.

// v4.81.18 / v4.81.23: consolidated Today's Plan card — collapses what
// were 4 stacked surfaces (#todays-focus weak-spots row + #rotation-row
// stale chips + #session-banner study plan + v4.54.0 #focus-banner) into
// ONE prescriptive card. v4.81.23 removed all 4 legacy elements + their
// shim render functions. Eliminates
// topic-name repetition + "never studied" stutter + 3 competing CTAs.
// Mockup at mockups/today-consolidation-concept.html.
function renderTodayPlan() {
  const card = document.getElementById('today-plan');
  if (!card) return;
  // Hide if today's plan has already been addressed (multi-topic session
  // run today, or every plan topic individually drilled today).
  let done = false;
  try { done = (typeof isStudyPlanDoneToday === 'function') ? isStudyPlanDoneToday() : false; } catch (_) {}
  if (done) {
    card.classList.add('is-hidden');
    card.innerHTML = '';
    return;
  }
  const plan = buildSessionPlan(SESSION_TOPICS);
  if (!plan || plan.length === 0) {
    card.classList.add('is-hidden');
    card.innerHTML = '';
    return;
  }
  // Persist into module state so startSession picks up the same plan
  sessionPlan = plan;

  const weakCount = plan.filter(i => i.signal === 'weak').length;
  const staleCount = plan.filter(i => i.signal === 'stale').length;
  const fallbackCount = plan.length - weakCount - staleCount;
  // Time estimate: ~36s per question (rounded from real session telemetry)
  const totalMin = Math.max(1, Math.round((plan.length * SESSION_QUESTIONS) * 0.6));

  // Sub-line composition prose — tailored to which signals contributed
  let subProse = '';
  if (weakCount > 0 && staleCount > 0) {
    subProse = `Hits your ${weakCount === 1 ? 'weakest topic' : weakCount + ' weakest topics'} from recent quizzes plus ${staleCount === 1 ? 'a topic' : staleCount + ' topics'} you haven't touched in a while.`;
  } else if (weakCount > 0) {
    subProse = `Targets your ${weakCount === 1 ? 'weakest topic' : weakCount + ' weakest topics'} from recent quizzes.`;
  } else if (staleCount > 0) {
    subProse = `Surfaces ${staleCount === 1 ? 'a topic' : staleCount + ' topics'} you haven't touched in a while so coverage stays even.`;
  } else {
    subProse = 'A balanced starter mix while you build up history.';
  }
  subProse += ` Mixed difficulty, ${SESSION_QUESTIONS} questions per topic.`;

  // Compose the chip strip
  const chipsHtml = plan.map(item => {
    const icon = item.signal === 'weak' ? '🎯'
               : item.signal === 'stale' ? '🕒'
               : '✨';
    const safeTopic = String(item.topic).replace(/'/g, "\\'");
    const tipPrefix = item.signal === 'weak' ? 'Weak spot — '
                    : item.signal === 'stale' ? 'Stale — '
                    : 'Recommended — ';
    const title = tipPrefix + (item.meta || '');
    return '<button type="button" class="tplan-chip" data-signal="' + item.signal + '" title="' + escHtml(title) + '" onclick="focusTopic(\'' + safeTopic + '\')">'
      + '<span class="tplan-chip-icon" aria-hidden="true">' + icon + '</span>'
      + '<span class="tplan-chip-name">' + escHtml(item.topic) + '</span>'
      + '<span class="tplan-chip-arrow" aria-hidden="true">→</span>'
    + '</button>';
  }).join('');

  // Composition meta — "2 weak · 3 stale · Mixed difficulty"
  const compParts = [];
  if (weakCount > 0) compParts.push(weakCount + ' weak');
  if (staleCount > 0) compParts.push(staleCount + ' stale');
  if (fallbackCount > 0) compParts.push(fallbackCount + ' recommended');
  compParts.push('Mixed difficulty');

  // v4.81.21: Subnet Trainer bridge re-integration. Restored from v4.43.1
  // (was retired in v4.81.18 consolidation). When the plan includes a
  // subnet-heavy topic (Subnetting & IP Addressing / IPv6 / NAT & IP
  // Services), surface a small "Drill in Subnet Trainer →" bridge link
  // so users get the deeper binary-breakdown affordance instead of just
  // the regular MCQ quiz drill. Dedupe by kind+labId so we don't show
  // multiple identical buttons when 2 subnet topics are in the plan.
  let bridgesHtml = '';
  try {
    if (typeof WEAK_SPOT_DRILL_BRIDGES !== 'undefined') {
      const seenBridgeKeys = new Set();
      const bridges = [];
      plan.forEach(item => {
        const bridge = WEAK_SPOT_DRILL_BRIDGES[item.topic];
        if (!bridge) return;
        const key = bridge.kind + '::' + (bridge.labId || '');
        if (seenBridgeKeys.has(key)) return;
        seenBridgeKeys.add(key);
        bridges.push(bridge);
      });
      if (bridges.length > 0) {
        bridgesHtml = '<div class="tplan-bridges" role="group" aria-label="Specialized drill alternatives">'
          + bridges.map(b =>
              '<button type="button" class="tplan-bridge-btn" onclick="openWeakSpotBridge(\'' + b.kind + '\')" title="' + escHtml(b.label) + '">'
                + '<span class="tplan-bridge-icon" aria-hidden="true">' + b.icon + '</span>'
                + '<span class="tplan-bridge-label">' + escHtml(b.label) + '</span>'
                + '<span class="tplan-bridge-arrow" aria-hidden="true">→</span>'
              + '</button>'
            ).join('')
          + '</div>';
      }
    }
  } catch (_) { bridgesHtml = ''; }

  card.innerHTML = ''
    + '<div class="tplan-eyebrow">Today\'s plan</div>'
    + '<div class="tplan-headline">' + plan.length + ' topics · ~' + totalMin + ' min · <em>fastest</em> route to exam-ready</div>'
    + '<p class="tplan-sub">' + escHtml(subProse) + '</p>'
    + '<div class="tplan-chips">' + chipsHtml + '</div>'
    + bridgesHtml
    + '<div class="tplan-foot">'
    +   '<div class="tplan-foot-meta">' + escHtml(compParts.join(' · ')) + '</div>'
    +   '<button type="button" class="tplan-cta" onclick="startSession()">Begin plan →</button>'
    + '</div>';
  card.classList.remove('is-hidden');
}

async function startSession() {
  const key = document.getElementById('api-key').value.trim();
  const errBox = document.getElementById('setup-err');
  errBox.classList.add('is-hidden');
  const keyErr = validateApiKey(key);
  if (keyErr) { errBox.textContent = keyErr; errBox.classList.remove('is-hidden'); showSetupError(); return; }
  apiKey = key;
  localStorage.setItem(STORAGE.KEY, key);

  sessionMode    = true;
  sessionStep    = 0;
  sessionResults = [];
  sessionPlan    = buildSessionPlan(SESSION_TOPICS);
  examMode       = false;
  wrongDrillMode = false;

  runSessionStep();
}

async function runSessionStep() {
  const step  = sessionPlan[sessionStep];
  const sTopic = step.topic;
  activeQuizTopic = sTopic;
  topic = sTopic;

  document.getElementById('load-progress').classList.add('is-hidden');
  showPage('loading');
  document.getElementById('loading-msg').textContent =
    'Session ' + (sessionStep + 1) + '/' + SESSION_TOPICS + ' \u2014 ' + sTopic + '\u2026';

  showCacheNotice(false);
  try {
    questions = await fetchQuestions(apiKey, sTopic, 'Mixed', SESSION_QUESTIONS);
    document.getElementById('loading-msg').textContent = 'Verifying question accuracy\u2026';
    questions = await aiValidateQuestions(apiKey, questions);
    questions = validateQuestions(questions);
    if (questions.length === 0) throw new Error('All generated questions failed validation. Try again.');
  } catch(e) {
    const cached = getCachedQuestions(sTopic, 'Mixed', SESSION_QUESTIONS);
    if (cached) { questions = cached; showCacheNotice(true); }
    else {
      sessionMode = false;
      showPage('setup');
      const err = document.getElementById('setup-err');
      err.textContent = '\u26a0\ufe0f ' + (e.message || 'Failed. Check your API key.');
      err.classList.remove('is-hidden');
      return;
    }
  }
  current = 0; score = 0; streak = 0; bestStreak = 0; answered = 0; log = [];
  quizFlags = new Array(questions.length).fill(false);
  diff = 'Mixed';
  showPage('quiz');
  render();
}

function renderSessionTransition() {
  const prev   = sessionResults[sessionResults.length - 1];
  const next   = sessionPlan[sessionStep];
  const color  = prev.pct >= 80 ? 'var(--green)' : prev.pct >= 60 ? 'var(--blue)' : 'var(--red)';
  const emoji  = prev.pct >= 80 ? '\u2705' : prev.pct >= 60 ? '\ud83d\udcaa' : '\ud83d\udcda';

  document.getElementById('st-emoji').textContent   = emoji;
  document.getElementById('st-heading').textContent = 'Topic ' + sessionStep + ' done!';
  document.getElementById('st-sub').textContent     = prev.pct + '% on ' + prev.topic;
  document.getElementById('st-topic-done').textContent = prev.topic;
  document.getElementById('st-pct').textContent    = prev.pct + '%';
  document.getElementById('st-pct').style.color    = color;

  const fill = document.getElementById('st-bar-fill');
  fill.style.width      = prev.pct + '%';
  fill.style.background = color;

  document.getElementById('st-next-topic').textContent  = next.topic;
  document.getElementById('st-next-reason').textContent = next.reason;
  showPage('session-transition');
}

function renderSessionComplete() {
  const total    = sessionResults.length;
  const overall  = Math.round(sessionResults.reduce((a, r) => a + r.pct, 0) / total);

  document.getElementById('sc-sub').textContent =
    'Overall ' + overall + '% across ' + total + ' topics';

  const scResults = document.getElementById('sc-results');
  scResults.innerHTML = sessionResults.map(r => {
    const c = r.pct >= 80 ? 'var(--green)' : r.pct >= 60 ? 'var(--blue)' : 'var(--red)';
    return `<div class="session-result-row">
      <div>
        <div class="session-result-topic">${escHtml(r.topic)}</div>
        <div class="session-result-bar"><div class="session-result-fill" style="width:${r.pct}%;background:${c}"></div></div>
      </div>
      <div class="session-result-pct" style="color:${c}">${r.pct}%</div>
    </div>`;
  }).join('');

  showPage('session-complete');
}

function endSessionEarly() {
  sessionMode = false;
  sessionPlan = [];
  sessionStep = 0;
  sessionResults = [];
  goSetup();
}

// ══════════════════════════════════════════
// DATA EXPORT / IMPORT
// ══════════════════════════════════════════
function exportData() {
  const data = {
    version: APP_VERSION,
    exportedAt: new Date().toISOString(),
    history: loadHistory(),
    streak: getStreak(),
    wrongBank: loadWrongBank()
  };
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href = url;
  a.download = 'networkplus-quiz-backup-' + new Date().toISOString().slice(0, 10) + '.json';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function importData(event) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    try {
      const data = JSON.parse(e.target.result);
      if (!data.history || !Array.isArray(data.history)) {
        alert('Invalid backup file.');
        return;
      }
      if (!confirm(`Import ${data.history.length} history entries? This will MERGE with your existing data.`)) return;

      const existing = loadHistory();
      const existingKeys = new Set(existing.map(e => e.date + '|' + e.topic));
      const newEntries = data.history.filter(e => !existingKeys.has(e.date + '|' + e.topic));
      const merged = existing.concat(newEntries);
      merged.sort((a, b) => new Date(b.date) - new Date(a.date));
      if (merged.length > HISTORY_CAP) merged.length = HISTORY_CAP;
      localStorage.setItem(STORAGE.HISTORY, JSON.stringify(merged));

      if (data.streak) {
        const current = getStreak();
        if ((data.streak.best || 0) > (current.best || 0)) {
          current.best = data.streak.best;
          localStorage.setItem(STORAGE.STREAK, JSON.stringify(current));
        }
      }

      if (data.wrongBank && Array.isArray(data.wrongBank)) {
        const existingBank = loadWrongBank();
        const existingQs = new Set(existingBank.map(b => b.question));
        const newBank = data.wrongBank.filter(b => !existingQs.has(b.question));
        saveWrongBank(existingBank.concat(newBank));
      }

      alert(`Imported ${newEntries.length} new entries.`);
      renderHistoryPanel();
      renderStatsCard();
      renderReadinessCard();
      renderStreakBadge();
      renderWrongBankBtn();
    } catch(err) {
      alert('Failed to parse backup file: ' + err.message);
    }
  };
  reader.readAsText(file);
  event.target.value = '';
}

// ══════════════════════════════════════════
// v4.81.2: AUTO-BACKUP SAFETY NET
// ──────────────────────────────────────────
// Daily rolling snapshot of ALL nplus_* keys (excluding autobackup keys
// themselves to avoid recursion + theme-only keys we don't care about).
// Keeps the last AUTOBACKUP_KEEP_DAYS snapshots so any catastrophic
// corruption can be rolled back. Hook fires on every page load via
// DOMContentLoaded — but is rate-limited to once per day to avoid
// excess writes.
//
// Filed as the immediate response to a localStorage-corruption incident
// where test-injected state overwrote real user history. The fix:
// disciplinary boundary (no test writes to user's prod localStorage)
// PLUS this safety net so any future corruption is recoverable from
// yesterday's snapshot.
// ══════════════════════════════════════════

// Build a snapshot of every nplus_* key currently in localStorage,
// skipping autobackup-namespace keys + the cooldown anchor.
function _captureSnapshot() {
  const snap = {};
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (!k || !k.startsWith('nplus_')) continue;
    if (k.startsWith(STORAGE.AUTOBACKUP_PREFIX)) continue; // don't snapshot snapshots
    if (k === STORAGE.LAST_AUTOBACKUP_AT) continue;
    snap[k] = localStorage.getItem(k);
  }
  return snap;
}

// Today's date in YYYY-MM-DD format (local time, not UTC) — used as the
// per-day snapshot key suffix.
function _autoBackupTodayKey() {
  const d = new Date();
  const y = d.getFullYear();
  const m = (d.getMonth() + 1).toString().padStart(2, '0');
  const day = d.getDate().toString().padStart(2, '0');
  return STORAGE.AUTOBACKUP_PREFIX + y + '-' + m + '-' + day;
}

// Take today's snapshot if not yet taken. Idempotent — calling twice
// in the same day is a no-op (existing snapshot kept). Prunes older
// snapshots beyond AUTOBACKUP_KEEP_DAYS.
function _takeAutoBackup() {
  try {
    const todayKey = _autoBackupTodayKey();
    if (localStorage.getItem(todayKey)) {
      // Already snapshotted today — skip.
      return false;
    }
    const snap = _captureSnapshot();
    if (Object.keys(snap).length === 0) {
      // Empty state — no point snapshotting.
      return false;
    }
    const payload = {
      version: (typeof APP_VERSION !== 'undefined') ? APP_VERSION : 'unknown',
      capturedAt: new Date().toISOString(),
      keyCount: Object.keys(snap).length,
      snapshot: snap
    };
    localStorage.setItem(todayKey, JSON.stringify(payload));
    localStorage.setItem(STORAGE.LAST_AUTOBACKUP_AT, String(Date.now()));
    _pruneAutoBackups();
    return true;
  } catch (e) {
    // Storage quota exceeded? Try pruning + retrying once.
    try {
      _pruneAutoBackups(true); // aggressive: drop to 3 days on quota error
      const todayKey = _autoBackupTodayKey();
      const snap = _captureSnapshot();
      const payload = {
        version: (typeof APP_VERSION !== 'undefined') ? APP_VERSION : 'unknown',
        capturedAt: new Date().toISOString(),
        keyCount: Object.keys(snap).length,
        snapshot: snap
      };
      localStorage.setItem(todayKey, JSON.stringify(payload));
      localStorage.setItem(STORAGE.LAST_AUTOBACKUP_AT, String(Date.now()));
      return true;
    } catch (e2) {
      console.warn('[autobackup] failed:', e2 && e2.message);
      return false;
    }
  }
}

// Drop oldest snapshots beyond AUTOBACKUP_KEEP_DAYS. When `aggressive` is
// true, drop to 3 (used during quota-exceeded recovery).
function _pruneAutoBackups(aggressive) {
  const keep = aggressive ? 3 : AUTOBACKUP_KEEP_DAYS;
  const all = listAutoBackups();
  if (all.length <= keep) return;
  // listAutoBackups returns newest first; drop from the tail.
  all.slice(keep).forEach(b => {
    try { localStorage.removeItem(b.key); } catch (_) {}
  });
}

// List all autobackup snapshots, newest first. Each entry: { key, date, capturedAt, keyCount, version }
function listAutoBackups() {
  const out = [];
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (!k || !k.startsWith(STORAGE.AUTOBACKUP_PREFIX)) continue;
    try {
      const raw = localStorage.getItem(k);
      const parsed = JSON.parse(raw || '{}');
      out.push({
        key: k,
        date: k.slice(STORAGE.AUTOBACKUP_PREFIX.length),
        capturedAt: parsed.capturedAt || null,
        keyCount: parsed.keyCount || (parsed.snapshot ? Object.keys(parsed.snapshot).length : 0),
        version: parsed.version || 'unknown',
        bytes: raw ? raw.length : 0
      });
    } catch (_) { /* skip malformed */ }
  }
  out.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  return out;
}

// Restore from a snapshot date (e.g. '2026-04-25'). Confirms with user
// before destructive overwrite, then atomically replaces all nplus_*
// keys with the snapshot's values.
function restoreFromAutoBackup(dateOrKey) {
  const key = dateOrKey.startsWith(STORAGE.AUTOBACKUP_PREFIX) ? dateOrKey : (STORAGE.AUTOBACKUP_PREFIX + dateOrKey);
  const raw = localStorage.getItem(key);
  if (!raw) {
    showToast('Snapshot not found', 'error');
    return false;
  }
  let parsed;
  try { parsed = JSON.parse(raw); }
  catch { showToast('Snapshot is corrupted', 'error'); return false; }
  const snap = parsed.snapshot || {};
  const count = Object.keys(snap).length;
  const date = key.slice(STORAGE.AUTOBACKUP_PREFIX.length);
  // v4.81.11: enumerate what gets replaced (Codex r9 #4). Pre-fix the
  // dialog said "Your current state will be overwritten" — accurate but
  // vague. Now lists the data categories explicitly so the user knows
  // exactly what's about to change before they confirm.
  const captured = parsed.capturedAt
    ? new Date(parsed.capturedAt).toLocaleString()
    : date;
  const prettyDate = /^pre-restore-/.test(date)
    ? 'pre-restore safety snapshot from ' + new Date(parseInt(date.replace('pre-restore-', ''), 10)).toLocaleString()
    : 'snapshot of ' + captured;
  const msg = 'Restore from ' + prettyDate + '?\n\n' +
    'This will REPLACE your current:\n' +
    '  • Quiz history + streak + readiness score\n' +
    '  • Daily goal + exam date\n' +
    '  • Wrong bank + Spaced Repetition queue\n' +
    '  • All drill mastery (Subnet / Port / Acronym / OSI / Cable)\n' +
    '  • Topology saves + ACL Builder state\n' +
    '  • API key, milestones, type stats\n\n' +
    'Your CURRENT state will be auto-snapshotted first as a "pre-restore" ' +
    'safety backup, so you can roll forward again if this restore makes ' +
    'things worse.\n\n' +
    'Continue?';
  if (!confirm(msg)) {
    return false;
  }
  // Snapshot the CURRENT state under a "pre-restore" key so the user
  // can roll back if the restore makes things worse.
  try {
    const preRestoreKey = STORAGE.AUTOBACKUP_PREFIX + 'pre-restore-' + Date.now();
    const cur = _captureSnapshot();
    const curPayload = {
      version: (typeof APP_VERSION !== 'undefined') ? APP_VERSION : 'unknown',
      capturedAt: new Date().toISOString(),
      keyCount: Object.keys(cur).length,
      snapshot: cur,
      note: 'pre-restore safety snapshot'
    };
    localStorage.setItem(preRestoreKey, JSON.stringify(curPayload));
  } catch (_) { /* don't block restore on this */ }
  // Now wipe every nplus_* key (except autobackup namespace + cooldown)
  const toDelete = [];
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (!k || !k.startsWith('nplus_')) continue;
    if (k.startsWith(STORAGE.AUTOBACKUP_PREFIX)) continue;
    if (k === STORAGE.LAST_AUTOBACKUP_AT) continue;
    toDelete.push(k);
  }
  toDelete.forEach(k => localStorage.removeItem(k));
  // And write the snapshot's keys back
  Object.keys(snap).forEach(k => {
    try { localStorage.setItem(k, snap[k]); } catch (_) {}
  });
  showToast('Restored ' + count + ' keys from ' + date, 'success');
  setTimeout(() => location.reload(), 600);
  return true;
}

// Download the most recent snapshot as a JSON file. If no snapshot exists
// yet, takes one inline first.
function downloadAutoBackup(dateOrKey) {
  let key = dateOrKey;
  if (!key) {
    const all = listAutoBackups();
    if (all.length === 0) {
      _takeAutoBackup();
      const fresh = listAutoBackups();
      if (fresh.length === 0) { showToast('No backup to download', 'error'); return; }
      key = fresh[0].key;
    } else {
      key = all[0].key;
    }
  } else if (!key.startsWith(STORAGE.AUTOBACKUP_PREFIX)) {
    key = STORAGE.AUTOBACKUP_PREFIX + key;
  }
  const raw = localStorage.getItem(key);
  if (!raw) { showToast('Snapshot not found', 'error'); return; }
  const blob = new Blob([raw], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'networkplus-autobackup-' + key.slice(STORAGE.AUTOBACKUP_PREFIX.length) + '.json';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// Render the Backup History list inside the Settings page. Shows each
// snapshot as a row with date + size + Restore + Download buttons.
function renderAutoBackupList() {
  const host = document.getElementById('autobackup-list');
  if (!host) return;
  const all = listAutoBackups();
  if (all.length === 0) {
    host.innerHTML = '<div class="ab-empty">No automatic backups yet — one will be created on your next page load.</div>';
    return;
  }
  host.innerHTML = all.map(b => {
    const sizeKb = (b.bytes / 1024).toFixed(1);
    const captured = b.capturedAt ? new Date(b.capturedAt).toLocaleString() : b.date;
    const isPreRestore = /pre-restore-/.test(b.date);
    const dateLabel = isPreRestore ? 'Pre-restore safety (' + new Date(parseInt(b.date.replace('pre-restore-', ''), 10)).toLocaleString() + ')' : b.date;
    return '<div class="ab-row">' +
      '<div class="ab-row-info">' +
      '<div class="ab-row-date">' + escHtml(dateLabel) + '</div>' +
      '<div class="ab-row-meta">' + b.keyCount + ' keys · ' + sizeKb + ' KB · ' + escHtml(b.version) + ' · captured ' + escHtml(captured) + '</div>' +
      '</div>' +
      '<div class="ab-row-actions">' +
      '<button class="btn btn-sm btn-ghost" onclick="downloadAutoBackup(\'' + b.key + '\')" aria-label="Download this snapshot">Download</button>' +
      '<button class="btn btn-sm" onclick="restoreFromAutoBackup(\'' + b.key + '\')" aria-label="Restore from this snapshot">Restore</button>' +
      '</div>' +
      '</div>';
  }).join('');
}

// ══════════════════════════════════════════
// v4.81.3: DATA-SAFETY DISCIPLINE LAYER
// ──────────────────────────────────────────
// Defense-in-depth around the v4.81.0 → v4.81.1 localStorage-corruption
// incident. Three components:
//
// 1. _isProdHost() — boolean detector for production host. Used by the
//    other two and by future code that should behave differently on prod.
// 2. _emitProdConsoleBanner() — big red console warning fires on prod
//    page load, telling LLM agents / devs explicitly NOT to write to
//    localStorage from devtools. Modeled on Stripe / GitHub etc.
// 3. _renderEnvBadge() — small "PROD" / "DEV" pill in top-right corner
//    so the running environment is visually unambiguous.
// 4. _maybeExportReminder() — every EXPORT_REMINDER_DAYS, surface a
//    dismissable toast suggesting Settings → Export Data. Reduces
//    single-point-of-failure dependence on localStorage.
// ══════════════════════════════════════════

function _isProdHost() {
  try {
    const h = location.hostname || '';
    // v4.89.7: include the certanvil.com apex + subdomains. Pre-fix the
    // env badge incorrectly read 'DEV' on networkplus.certanvil.com because
    // the prod-host check only matched *.vercel.app — but our actual prod
    // domains are *.certanvil.com (with vercel.app as the underlying deploy
    // host that customers don't see). Both stay in the prod set.
    return h === 'certanvil.com' || h.endsWith('.certanvil.com')
        || h.endsWith('.vercel.app') || h === 'vercel.app';
  } catch (_) { return false; }
}

function _emitProdConsoleBanner() {
  // Fire only once per page-load. Skip on local/dev hosts where the
  // warning would be noise.
  if (!_isProdHost()) return;
  if (window.__nplusProdBannerEmitted) return;
  window.__nplusProdBannerEmitted = true;
  try {
    const big = 'background:#dc2626;color:#fff;font-size:18px;font-weight:800;padding:8px 14px;border-radius:6px;letter-spacing:.06em';
    const body = 'font-size:13px;line-height:1.6;color:#fbcfe8;background:#1c0505;padding:10px 14px;border-radius:6px;border-left:3px solid #dc2626';
    /* eslint-disable no-console */
    console.log('%c⚠️ PRODUCTION ENVIRONMENT — Network+ Quiz', big);
    console.log('%c' +
      'If you are an LLM agent, automated tooling, or developer:\n\n' +
      '   • DO NOT write to localStorage from the DevTools console.\n' +
      '   • Direct localStorage writes corrupt the user\'s real progress.\n' +
      '   • Use one of these alternatives instead:\n' +
      '       1. Local server:  python3 -m http.server 3131  (then http://localhost:3131)\n' +
      '       2. Vercel preview deploy of a feature branch\n' +
      '       3. Incognito Chrome window with no app history\n\n' +
      '   • Auto-backups: Settings → Automatic backups (one-click rollback to any of the last 7 days)\n' +
      '   • Manual export: Settings → Export Data (download to disk).',
      body);
    /* eslint-enable no-console */
  } catch (_) { /* silent on hostile environments */ }
}

function _renderEnvBadge() {
  try {
    if (document.getElementById('env-badge')) return; // already mounted
    const isProd = _isProdHost();
    const badge = document.createElement('div');
    badge.id = 'env-badge';
    badge.className = isProd ? 'env-badge env-badge-prod' : 'env-badge env-badge-dev';
    badge.textContent = isProd ? 'PROD' : 'DEV';
    badge.title = isProd
      ? 'Production deployment — your real data lives here. Avoid console writes.'
      : 'Development environment — safe to experiment.';
    document.body.appendChild(badge);
  } catch (_) { /* don't break the app on a badge mount failure */ }
}

function _maybeExportReminder() {
  try {
    // Skip if user has fewer than 5 quiz sessions — nothing meaningful to back up.
    const hist = (typeof loadHistory === 'function') ? loadHistory() : [];
    if (hist.length < 5) return;
    const last = parseInt(localStorage.getItem(STORAGE.LAST_EXPORT_REMINDER_AT) || '0', 10);
    const elapsedMs = Date.now() - last;
    if (last && elapsedMs < EXPORT_REMINDER_DAYS * 86400000) return;
    // Stamp now BEFORE showing the toast so a render error doesn't repeat.
    localStorage.setItem(STORAGE.LAST_EXPORT_REMINDER_AT, String(Date.now()));
    setTimeout(() => {
      if (typeof showToast === 'function') {
        showToast('💾 Tip: download a backup. Settings → Export Data keeps a copy outside your browser.', 'info', 8000);
      }
    }, 4000); // wait 4s after page load so the toast doesn't fight the hero render
  } catch (_) { /* silent — reminder is opportunistic */ }
}

// ══════════════════════════════════════════
// v4.81.4: API KEY AUTO-SAVE (UX fix from v4.81.3 incident follow-up)
// ──────────────────────────────────────────
// Pre-fix the API-key input only persisted when the user triggered an
// action that read it (Generate Quiz, Take Diagnostic, etc). Pasting +
// reloading lost the key silently — exactly what the user hit after
// re-creating their key post-corruption-incident. This module auto-
// saves on every input + on blur, with a small debounce so we don't
// hammer localStorage while typing. Visible "Saved ✓" status pill so
// the user gets confirmation.
// ══════════════════════════════════════════

let _apiKeyDebounceTimer = null;

// Debounced save — fires while the user is typing. Coalesces rapid
// keystrokes into a single save. The blur handler still runs a final
// save when the field loses focus.
function _apiKeyDebouncedSave() {
  if (_apiKeyDebounceTimer) clearTimeout(_apiKeyDebounceTimer);
  _apiKeyDebounceTimer = setTimeout(() => {
    autoSaveApiKey();
    _apiKeyDebounceTimer = null;
  }, API_KEY_AUTOSAVE_DEBOUNCE_MS);
}

// Save whatever's currently in the input (after trimming whitespace)
// to localStorage and update the visible status pill.
function autoSaveApiKey() {
  try {
    const input = document.getElementById('api-key');
    if (!input) return;
    const raw = input.value || '';
    const key = raw.trim();
    const status = document.getElementById('api-key-status');
    if (key.length === 0) {
      // Empty — clear the saved key + show neutral status
      try { localStorage.removeItem(STORAGE.KEY); } catch (_) {}
      if (typeof apiKey !== 'undefined') apiKey = '';
      if (status) {
        status.classList.add('is-hidden');
        status.textContent = '';
      }
      return;
    }
    // Validate format — Anthropic keys start with sk-ant-
    if (!key.startsWith('sk-ant-')) {
      if (status) {
        status.classList.remove('is-hidden');
        status.className = 'api-key-status api-key-status-warn';
        status.textContent = '⚠ Doesn\'t look like an Anthropic key (should start with sk-ant-)';
      }
      return; // don't save malformed input
    }
    // Persist + update in-memory
    localStorage.setItem(STORAGE.KEY, key);
    if (typeof apiKey !== 'undefined') apiKey = key;
    // If the input had whitespace, replace its value with the trimmed
    // version so what the user sees matches what's saved.
    if (raw !== key) input.value = key;
    if (status) {
      status.classList.remove('is-hidden');
      status.className = 'api-key-status api-key-status-ok';
      status.textContent = '✓ Saved · ' + key.slice(0, 12) + '…' + key.slice(-4);
    }
    // v4.85.16: clear any stale "invalid x-api-key" / similar API-error
    // banners now that a fresh valid key is on file. Defensive sweep —
    // the user-visible setup-err DIV could be lingering from a quiz that
    // failed before they fixed the key, and there's no other code path
    // that re-hides it once shown. Also clears any other .err-box on the
    // page in case future surfaces use the same pattern.
    if (typeof _clearStaleErrBoxes === 'function') _clearStaleErrBoxes();
  } catch (_) { /* defensive */ }
}

// v4.85.16: shared err-box cleanup helper. Sweeps the DOM for any visible
// .err-box, .setup-err, or related stale-error elements and re-hides them.
// Called from (1) successful API key save, (2) showPage navigation, so a
// banner from one flow can't leak into another. Idempotent + defensive.
function _clearStaleErrBoxes() {
  try {
    // Direct hit: the known persistent banner inside page-setup
    const setupErr = document.getElementById('setup-err');
    if (setupErr) {
      setupErr.classList.add('is-hidden');
      setupErr.textContent = '';
    }
    // Defensive sweep: any other .err-box that's been left visible
    document.querySelectorAll('.err-box:not(.is-hidden)').forEach(el => {
      el.classList.add('is-hidden');
      el.textContent = '';
    });
  } catch (_) { /* defensive — never block a page transition on a cleanup error */ }
}

// On page load, if a key is already saved, show the "Saved" pill. This
// reassures the user that the key persisted across reload.
function _renderApiKeyStatusOnLoad() {
  try {
    const status = document.getElementById('api-key-status');
    const input = document.getElementById('api-key');
    if (!status || !input) return;
    const saved = localStorage.getItem(STORAGE.KEY) || '';
    if (saved.length > 0 && saved.startsWith('sk-ant-')) {
      // Note: we deliberately DO NOT mirror the saved key back into the
      // type=password input on load — that's standard browser behaviour
      // for credentials and changing it would be confusing. The status
      // pill just confirms a key is on file.
      status.classList.remove('is-hidden');
      status.className = 'api-key-status api-key-status-ok';
      status.textContent = '✓ Key saved · ' + saved.slice(0, 12) + '…' + saved.slice(-4);
    }
  } catch (_) {}
}

