// ── OSI Sorter state ──
let osQ = null, osIdx = 0, osCorrect = 0, osTotal = 0, osStreak = 0;
let osMode = 'sort', osDifficulty = 'easy', osActiveLesson = null;
let osSortState = null, osSortSelectedItem = null;

// ── OSI Sorter engine (scaffold-backed) ──
const osScaffold = createDrillScaffold({
  prefix: 'os',
  storageKey: STORAGE.OS_MASTERY,
  lessonsKey: STORAGE.OS_LESSONS,
  lessons: OS_LESSONS,
  categoryField: 'perLayer',
  levelThresholds: [
    { min: 300, acc: 0.85, level: 'expert' },
    { min: 150, acc: 0.75, level: 'advanced' },
    { min: 40,  acc: 0.60, level: 'intermediate' },
  ],
  badgeColor: '#06b6d4',
  initMastery() {
    const m = { currentLevel: 'beginner', totalAnswered: 0, totalCorrect: 0, perLayer: {}, perItem: {} };
    for (let i = 1; i <= 7; i++) m.perLayer[i] = { seen: 0, correct: 0, box: 1, streak: 0 };
    OS_DATA.forEach(d => { m.perItem[d.name] = { seen: 0, correct: 0, box: 1, streak: 0, lastSeen: null }; });
    return m;
  },
  heatmapTitle: 'Layer Accuracy',
  heatmapIter(m) {
    return OSI_LAYERS.map(layer => {
      const d = m.perLayer[layer.num] || { seen: 0, correct: 0, box: 1 };
      const acc = d.seen > 0 ? Math.round(d.correct / d.seen * 100) : 0;
      return `<div class="os-heat-cell"><div class="os-heat-pct">${d.seen > 0 ? acc + '%' : '\u2014'}</div><div class="os-heat-label">L${layer.num}</div><div class="os-heat-box">Box ${d.box}/5</div></div>`;
    }).join('');
  },
  dashHeading: 'Layer Mastery',
  dashResetLabel: 'Reset all OSI mastery data?',
  storageKeyExpr: 'STORAGE.OS_MASTERY',
  lessonsKeyExpr: 'STORAGE.OS_LESSONS',
  nextLevelText(level) {
    if (level === 'beginner') return 'Intermediate (60% acc, 40+ Qs)';
    if (level === 'intermediate') return 'Advanced (75% acc, 150+ Qs)';
    if (level === 'advanced') return 'Expert (85% acc, 300+ Qs)';
    return 'Maximum level reached!';
  },
  dashCatIter(m) {
    return OSI_LAYERS.map(layer => {
      const d = m.perLayer[layer.num] || { seen: 0, correct: 0, box: 1, streak: 0 };
      const layerAcc = d.seen > 0 ? Math.round(d.correct / d.seen * 100) : 0;
      return `<div class="os-dash-cat-card"><div class="os-dash-cat-head">L${layer.num} ${layer.name}</div><div class="os-dash-cat-bar"><div style="width:${layerAcc}%;height:100%;border-radius:3px;transition:width .3s"></div></div><div class="os-dash-cat-stats"><span>${layerAcc}% acc</span><span>${d.seen} seen</span><span>Box ${d.box}/5</span></div></div>`;
    }).join('');
  },
  gateStateKey: '_osGateState',
  endlessContainerId: 'os-practice-area',
  endlessWrapHtml: (inner) => `<div class="subnet-card">${inner}</div>`,
  activeLesson: { get() { return osActiveLesson; }, set(id) { osActiveLesson = id; } },
  streakVar: { get() { return osStreak; } },
  modeVar: { get() { return osMode; }, set(v) { osMode = v; } },
  renderGate: (lesson) => osRenderGate(lesson),
  onPracticeTab() { osIdx = 0; osCorrect = 0; osTotal = 0; osStreak = 0; osStartPractice(); osRenderHeatmap(); },
  onModeChanged(mode) {
    osIdx = 0; osCorrect = 0; osTotal = 0; osStreak = 0;
    osStartPractice();
  },
});

// Expose scaffold functions as globals for onclick handlers
const getOsMastery = osScaffold.getMastery;
const saveOsMastery = osScaffold.saveMastery;
const osComputeLevel = osScaffold.computeLevel;
const osRenderLevelBadge = osScaffold.renderLevelBadge;
const osGetLessonProgress = osScaffold.getLessonProgress;
const osSaveLessonProgress = osScaffold.saveLessonProgress;
const osIsLessonUnlocked = osScaffold.isLessonUnlocked;
const osRenderLessonSidebar = osScaffold.renderLessonSidebar;
function osOpenLesson(id) { osScaffold.openLesson(id); }
const osRenderHeatmap = osScaffold.renderHeatmap;
const osRenderDashboard = osScaffold.renderDashboard;
const osEndEndless = osScaffold.endEndless;
function setOsTab(tabId) { osScaffold.setTab(tabId); }
function setOsMode(mode) { osScaffold.setMode(mode); }

// OS drill-specific functions (not shared)
function updateOsMastery(itemName, wasCorrect) {
  const m = getOsMastery();
  const item = OS_DATA.find(d => d.name === itemName);
  const layer = item ? item.layer : 1;
  if (!m.perItem[itemName]) m.perItem[itemName] = { seen: 0, correct: 0, box: 1, streak: 0, lastSeen: null };
  if (!m.perLayer[layer]) m.perLayer[layer] = { seen: 0, correct: 0, box: 1, streak: 0 };
  const pi = m.perItem[itemName];
  const pl = m.perLayer[layer];
  pi.seen++; pl.seen++; m.totalAnswered++;
  if (wasCorrect) { pi.correct++; pl.correct++; m.totalCorrect++; pi.streak++; pl.streak++; pi.box = Math.min(5, pi.box + 1); } else { pi.streak = 0; pl.streak = 0; pi.box = 1; }
  pi.lastSeen = Date.now();
  m.currentLevel = osComputeLevel(m);
  saveOsMastery(m);
}

function startOsiSorter() {
  if (!_gateProOnly('OSI Sorter')) return;
  setOsTab('learn');
  osRenderLevelBadge();
  // v4.81.10: Drill Mission Card (Codex r8)
  if (typeof renderOsiMission === 'function') renderOsiMission();
}

// ── Attack-to-Mitigation Match (v4.94.0, issue #301) ──────────────────────
// Standalone drill (not via createDrillScaffold) — simpler than AB. 10-question
// session, mastery weighted toward weakest categories. Visual contract locked
// to mockup State 3: attack-card → "↓ pick the right defense" → 2x2 option
// grid → reveal panel with `why` explanation.
let ammQ = null, ammIdx = 0, ammCorrect = 0, ammTotal = 0, ammStreak = 0;
let ammSessionLength = 10, ammSessionDone = false;
let ammQuestionStartTime = 0;

function getAmmMastery() {
  try {
    const raw = JSON.parse(localStorage.getItem(STORAGE.AMM_MASTERY) || 'null');
    if (raw && raw.perPair) return raw;
  } catch (_) {}
  return ammInitMastery();
}

function ammInitMastery() {
  const m = { totalAnswered: 0, totalCorrect: 0, perPair: {}, perCategory: {} };
  AMM_DATA.forEach(p => { m.perPair[p.id] = { seen: 0, correct: 0, box: 1, streak: 0, lastSeen: null }; });
  AMM_CAT_IDS.forEach(c => { m.perCategory[c] = { seen: 0, correct: 0, streak: 0 }; });
  return m;
}

function saveAmmMastery(m) {
  try { localStorage.setItem(STORAGE.AMM_MASTERY, JSON.stringify(m)); _cloudFlush(STORAGE.AMM_MASTERY); } catch (_) {}
}

function updateAmmMastery(pairId, wasCorrect) {
  const m = getAmmMastery();
  const pair = AMM_DATA.find(p => p.id === pairId);
  if (!pair) return;
  if (!m.perPair[pairId]) m.perPair[pairId] = { seen: 0, correct: 0, box: 1, streak: 0, lastSeen: null };
  if (!m.perCategory[pair.cat]) m.perCategory[pair.cat] = { seen: 0, correct: 0, streak: 0 };
  const pi = m.perPair[pairId];
  const pc = m.perCategory[pair.cat];
  pi.seen++; pc.seen++; m.totalAnswered++;
  if (wasCorrect) {
    pi.correct++; pc.correct++; m.totalCorrect++;
    pi.streak++; pc.streak++;
    pi.box = Math.min(5, pi.box + 1);
  } else {
    pi.streak = 0; pc.streak = 0;
    pi.box = Math.max(1, pi.box - 1);
  }
  pi.lastSeen = Date.now();
  saveAmmMastery(m);
}

function ammPickPair() {
  // Weight toward weakest categories + un-mastered pairs (box < 3)
  const m = getAmmMastery();
  // Compute category weights — lower mastery → higher weight
  const catScores = {};
  AMM_CAT_IDS.forEach(c => {
    const pc = m.perCategory[c] || { seen: 0, correct: 0 };
    const acc = pc.seen > 0 ? pc.correct / pc.seen : 0;
    catScores[c] = 1.5 - acc;  // 0.5 if perfect, 1.5 if untouched
  });
  // Build weighted candidate pool — un-mastered pairs first
  const unmastered = AMM_DATA.filter(p => {
    const pi = m.perPair[p.id] || { box: 1 };
    return pi.box < 3;
  });
  const pool = unmastered.length >= 5 ? unmastered : AMM_DATA;
  // Weighted random pick
  const weights = pool.map(p => catScores[p.cat] || 1);
  const total = weights.reduce((s, w) => s + w, 0);
  let r = Math.random() * total;
  for (let i = 0; i < pool.length; i++) {
    r -= weights[i];
    if (r <= 0) return pool[i];
  }
  return pool[pool.length - 1];
}

function ammNextQuestion() {
  if (ammIdx >= ammSessionLength) { ammEndSession(); return; }
  ammIdx++;
  const pair = ammPickPair();
  // Build options: correct + 3 distractors (already authored), shuffled
  const opts = [
    { ...pair.correct, isCorrect: true },
    ...pair.distractors.map(d => ({ ...d, isCorrect: false }))
  ].sort(() => Math.random() - 0.5);
  ammQ = { pair, opts };
  ammQuestionStartTime = Date.now();
  ammRenderQuestion();
}

function ammRenderQuestion() {
  const card = document.getElementById('amm-q-card');
  if (!card || !ammQ) return;
  const pair = ammQ.pair;
  const cat = AMM_CATEGORIES[pair.cat];
  const diffPips = Array.from({length: 3}, (_, i) => `<i class="amm-pip${i < (pair.diff || 1) ? ' on' : ''}"></i>`).join('');
  card.classList.remove('amm-q-revealed');
  card.innerHTML = `
    <div class="amm-q-eyebrow">Attack &rarr; Mitigation</div>
    <div class="amm-q-attack-card">
      <span class="amm-q-attack-icon"></span>
      <div>
        <div class="amm-q-attack-name">${escHtml(pair.attack)}</div>
        <div class="amm-q-attack-sub">${escHtml(cat ? cat.label : pair.cat)}</div>
        <div class="amm-q-attack-meta">SY0-701 &middot; Domain ${escHtml(pair.obj || '?')} &middot; <span class="amm-pips">${diffPips}</span></div>
      </div>
    </div>
    <div class="amm-q-arrow">&darr; pick the right defense</div>
    <div class="amm-q-grid">
      ${ammQ.opts.map((o, i) => `
        <button class="amm-q-opt" data-amm-opt="${i}" onclick="ammPickAnswer(${i})">
          <div class="amm-q-opt-name">${escHtml(o.name)}</div>
          <div class="amm-q-opt-sub">${escHtml(o.sub)}</div>
        </button>
      `).join('')}
    </div>
    <div id="amm-reveal" class="is-hidden"></div>
    <div class="amm-q-foot">
      <span class="amm-q-foot-diff">Difficulty: <span class="amm-pips">${diffPips}</span></span>
      <span class="amm-q-progress">Q ${ammIdx} / ${ammSessionLength}</span>
    </div>
  `;
  // Update stats strip
  const scoreEl = document.getElementById('amm-score');
  const streakEl = document.getElementById('amm-streak');
  const progEl = document.getElementById('amm-q-progress');
  const badgeEl = document.getElementById('amm-streak-badge');
  if (scoreEl) scoreEl.textContent = ammCorrect + ' / ' + ammTotal;
  if (streakEl) streakEl.textContent = ammStreak;
  if (progEl) progEl.textContent = 'Q ' + ammIdx + ' / ' + ammSessionLength;
  if (badgeEl) badgeEl.textContent = ammStreak;
}

function ammPickAnswer(optIdx) {
  if (!ammQ) return;
  const opt = ammQ.opts[optIdx];
  if (!opt) return;
  const pair = ammQ.pair;
  ammTotal++;
  const isCorrect = !!opt.isCorrect;
  if (isCorrect) { ammCorrect++; ammStreak++; } else { ammStreak = 0; }
  updateAmmMastery(pair.id, isCorrect);

  // Highlight options + show reveal
  document.querySelectorAll('.amm-q-opt').forEach((btn, i) => {
    btn.disabled = true;
    const o = ammQ.opts[i];
    if (o.isCorrect) btn.classList.add('is-correct');
    if (i === optIdx && !isCorrect) btn.classList.add('is-wrong');
  });
  const reveal = document.getElementById('amm-reveal');
  if (reveal) {
    const correctOpt = ammQ.opts.find(o => o.isCorrect);
    reveal.classList.remove('is-hidden');
    reveal.innerHTML = `
      <div class="amm-reveal">
        <div class="amm-reveal-head">${isCorrect ? 'Correct' : 'Why ' + escHtml(correctOpt.name) + ' beats the trap'}</div>
        <p class="amm-reveal-prose">${escHtml(pair.why)}</p>
        <div class="amm-reveal-actions">
          <button class="btn btn-primary amm-reveal-btn" onclick="ammNextQuestion()">${ammIdx >= ammSessionLength ? 'See results &rarr;' : 'Next question &rarr;'}</button>
        </div>
      </div>
    `;
  }
  // Update stats
  const scoreEl = document.getElementById('amm-score');
  const streakEl = document.getElementById('amm-streak');
  const badgeEl = document.getElementById('amm-streak-badge');
  if (scoreEl) scoreEl.textContent = ammCorrect + ' / ' + ammTotal;
  if (streakEl) streakEl.textContent = ammStreak;
  if (badgeEl) badgeEl.textContent = ammStreak;
  if (typeof evaluateMilestones === 'function') evaluateMilestones();
}

function ammEndSession() {
  ammSessionDone = true;
  const card = document.getElementById('amm-q-card');
  const endCard = document.getElementById('amm-end-card');
  if (card) card.classList.add('is-hidden');
  if (!endCard) return;
  endCard.classList.remove('is-hidden');
  // Compute weakest category
  const m = getAmmMastery();
  let weakest = null, weakestAcc = 1.1;
  AMM_CAT_IDS.forEach(c => {
    const pc = m.perCategory[c] || { seen: 0, correct: 0 };
    if (pc.seen >= 1) {
      const acc = pc.correct / pc.seen;
      if (acc < weakestAcc) { weakestAcc = acc; weakest = c; }
    }
  });
  const weakestLabel = weakest ? AMM_CATEGORIES[weakest].label : '—';
  const acc = ammTotal > 0 ? Math.round((ammCorrect / ammTotal) * 100) : 0;
  endCard.innerHTML = `
    <div class="amm-eos-card">
      <div class="amm-eos-burst"></div>
      <h2 class="amm-eos-title">Drill complete.</h2>
      <p class="amm-eos-sub">${ammCorrect}/${ammTotal} right &middot; ${ammStreak >= 5 ? ammStreak + '-question streak!' : 'Keep stacking those reps.'}</p>
      <div class="amm-eos-score-row">
        <div class="amm-eos-score-tile"><div class="amm-eos-score-num">${acc}%</div><div class="amm-eos-score-lbl">accuracy</div></div>
        <div class="amm-eos-score-tile"><div class="amm-eos-score-num">${ammCorrect}</div><div class="amm-eos-score-lbl">correct</div></div>
        <div class="amm-eos-score-tile"><div class="amm-eos-score-num">${m.totalAnswered}</div><div class="amm-eos-score-lbl">total seen</div></div>
      </div>
      ${weakest ? `<div class="amm-eos-weak"><strong>Next focus:</strong> ${escHtml(weakestLabel)} (${Math.round(weakestAcc * 100)}% mastered) — drill weighted there next.</div>` : ''}
      <div class="amm-eos-actions">
        <button class="btn btn-primary" onclick="startAttackMitigation()">Practice again →</button>
        <button class="btn btn-ghost" onclick="setAmmTab('dashboard')">Back to dashboard</button>
      </div>
    </div>
  `;
}

function ammRenderLessons() {
  const host = document.getElementById('amm-lessons-content');
  if (!host) return;
  if (!AMM_LESSONS.length) {
    host.innerHTML = '<p style="text-align:center;color:var(--text-mid);padding:32px">No lessons available for this cert.</p>';
    return;
  }
  host.innerHTML = AMM_LESSONS.map(l => {
    const cat = AMM_CATEGORIES[l.cat] || { label: l.cat, icon: '', color: 'var(--accent)' };
    return `
      <div class="amm-lesson-card">
        <div class="amm-lesson-head">
          <div class="amm-lesson-icon"></div>
          <div>
            <div class="amm-lesson-title">${escHtml(l.title)}</div>
            <div class="amm-lesson-sub">${escHtml(l.summary)}</div>
          </div>
        </div>
        <div class="amm-lesson-pair-table">
          <div class="amm-lesson-pair-h">Attack</div>
          <div class="amm-lesson-pair-h">Best mitigation</div>
          ${(l.keyPairs || []).map(([a, m]) => `
            <div class="amm-lesson-pair-cell amm-pair-attack">${escHtml(a)}</div>
            <div class="amm-lesson-pair-cell amm-pair-mit">${escHtml(m)}</div>
          `).join('')}
        </div>
      </div>
    `;
  }).join('');
}

function ammRenderDashboard() {
  const host = document.getElementById('amm-dashboard-content');
  if (!host) return;
  const m = getAmmMastery();
  const totalMastered = Object.values(m.perPair).filter(p => p.box >= 3).length;
  const totalSeen = Object.values(m.perPair).filter(p => p.seen > 0).length;
  const overallAcc = m.totalAnswered > 0 ? Math.round((m.totalCorrect / m.totalAnswered) * 100) : 0;

  // Find weakest category
  const catRows = AMM_CAT_IDS.map(c => {
    const cat = AMM_CATEGORIES[c];
    const pc = m.perCategory[c] || { seen: 0, correct: 0 };
    const total = AMM_DATA.filter(p => p.cat === c).length;
    const mastered = AMM_DATA.filter(p => p.cat === c && (m.perPair[p.id] || {}).box >= 3).length;
    const pct = total > 0 ? Math.round((mastered / total) * 100) : 0;
    return { c, cat, mastered, total, pct, seen: pc.seen, correct: pc.correct };
  });
  const weakestCat = catRows.filter(r => r.seen > 0).sort((a, b) => a.pct - b.pct)[0] || null;

  host.innerHTML = `
    <div class="amm-dash">
      <div class="amm-dash-card">
        <div class="amm-dash-card-head">Categories &middot; mastery</div>
        <div class="amm-dash-cat-list">
          ${catRows.map(r => `
            <div class="amm-dash-cat-row">
              <span class="amm-dash-cat-icon"></span>
              <div>
                <div class="amm-dash-cat-name">${escHtml(r.cat.label)}</div>
                <div class="amm-dash-cat-bar"><div class="amm-dash-cat-bar-fill" style="width:${r.pct}%"></div></div>
              </div>
              <span class="amm-dash-cat-pct">${r.mastered}/${r.total}</span>
              <span class="amm-dash-cat-count">${r.pct}%</span>
            </div>
          `).join('')}
        </div>
      </div>
      <div class="amm-dash-side">
        <div class="amm-dash-streak">
          <div class="amm-dash-streak-flame"></div>
          <div class="amm-dash-streak-num">${ammStreak}</div>
          <div class="amm-dash-streak-lbl">current streak</div>
        </div>
        ${weakestCat ? `
          <div class="amm-dash-card amm-dash-weakest">
            <div class="amm-dash-card-head">Weakest category</div>
            <div class="amm-dash-weak-name">${escHtml(weakestCat.cat.label)}</div>
            <div class="amm-dash-weak-sub">${weakestCat.total - weakestCat.mastered} pairs not mastered yet. Drill weighted there.</div>
          </div>
        ` : ''}
        <button class="amm-dash-cta" onclick="startAttackMitigation()">Start ${ammSessionLength}-question drill →</button>
        <div class="amm-dash-overall">
          <div><span class="amm-dash-overall-num">${totalMastered}</span><span class="amm-dash-overall-lbl">mastered</span></div>
          <div><span class="amm-dash-overall-num">${totalSeen}</span><span class="amm-dash-overall-lbl">seen</span></div>
          <div><span class="amm-dash-overall-num">${overallAcc}%</span><span class="amm-dash-overall-lbl">accuracy</span></div>
        </div>
      </div>
    </div>
  `;
}

function setAmmTab(tabId) {
  // Highlight tab buttons
  document.querySelectorAll('.amm-tab-btn').forEach(b => {
    const id = b.id.replace('amm-tab-btn-', '');
    const active = id === tabId;
    b.classList.toggle('amm-tab-active', active);
    b.setAttribute('aria-selected', active ? 'true' : 'false');
    b.tabIndex = active ? 0 : -1;
  });
  // Show/hide panels
  ['practice', 'lessons', 'dashboard'].forEach(p => {
    const panel = document.getElementById('amm-tab-' + p);
    if (!panel) return;
    panel.classList.toggle('is-hidden', p !== tabId);
  });
  if (tabId === 'lessons') ammRenderLessons();
  else if (tabId === 'dashboard') ammRenderDashboard();
}

function startAttackMitigation() {
  if (!_USE_SECPLUS_AMM) {
    if (typeof showToast === 'function') showToast('Attack-to-Mitigation drill is Security+ only.', 'info');
    return;
  }
  // Reset session state
  ammIdx = 0; ammCorrect = 0; ammTotal = 0; ammStreak = 0;
  ammSessionDone = false;
  // Show practice tab + render first question
  setAmmTab('practice');
  const card = document.getElementById('amm-q-card');
  const endCard = document.getElementById('amm-end-card');
  if (card) card.classList.remove('is-hidden');
  if (endCard) endCard.classList.add('is-hidden');
  ammNextQuestion();
}

// ── Control Type Sorter (v4.95.0, issue #302) ──────────────────────────────
// Dual-axis MCQ — pick TYPE (1-of-6) AND CATEGORY (1-of-4) for each control.
// Submit only enabled when both axes locked. Wrong on either axis = wrong;
// right on both = right (advance box). Visual contract locked to mockup
// State 2 (MCQ mode is v1; Sort mode deferred to v2).
let ctsQ = null, ctsIdx = 0, ctsCorrect = 0, ctsTotal = 0, ctsStreak = 0;
let ctsSessionLength = 12, ctsSessionDone = false;
let ctsPickedType = null, ctsPickedCat = null;

function getCtsMastery() {
  try {
    const raw = JSON.parse(localStorage.getItem(STORAGE.CTS_MASTERY) || 'null');
    if (raw && raw.perControl) return raw;
  } catch (_) {}
  return ctsInitMastery();
}

function ctsInitMastery() {
  const m = { totalAnswered: 0, totalCorrect: 0, perControl: {}, perType: {}, perCategory: {} };
  CTS_DATA.forEach(c => { m.perControl[c.id] = { seen: 0, correct: 0, box: 1, streak: 0, lastSeen: null }; });
  CTS_TYPE_IDS.forEach(t => { m.perType[t] = { seen: 0, correct: 0, streak: 0 }; });
  CTS_CAT_IDS.forEach(c => { m.perCategory[c] = { seen: 0, correct: 0, streak: 0 }; });
  return m;
}

function saveCtsMastery(m) {
  try { localStorage.setItem(STORAGE.CTS_MASTERY, JSON.stringify(m)); _cloudFlush(STORAGE.CTS_MASTERY); } catch (_) {}
}

function updateCtsMastery(controlId, wasCorrect) {
  const m = getCtsMastery();
  const ctrl = CTS_DATA.find(c => c.id === controlId);
  if (!ctrl) return;
  if (!m.perControl[controlId]) m.perControl[controlId] = { seen: 0, correct: 0, box: 1, streak: 0, lastSeen: null };
  if (!m.perType[ctrl.type]) m.perType[ctrl.type] = { seen: 0, correct: 0, streak: 0 };
  if (!m.perCategory[ctrl.cat]) m.perCategory[ctrl.cat] = { seen: 0, correct: 0, streak: 0 };
  const pi = m.perControl[controlId];
  const pt = m.perType[ctrl.type];
  const pc = m.perCategory[ctrl.cat];
  pi.seen++; pt.seen++; pc.seen++; m.totalAnswered++;
  if (wasCorrect) {
    pi.correct++; pt.correct++; pc.correct++; m.totalCorrect++;
    pi.streak++; pt.streak++; pc.streak++;
    pi.box = Math.min(5, pi.box + 1);
  } else {
    pi.streak = 0; pt.streak = 0; pc.streak = 0;
    pi.box = Math.max(1, pi.box - 1);
  }
  pi.lastSeen = Date.now();
  saveCtsMastery(m);
}

function ctsPickControl() {
  const m = getCtsMastery();
  // Weight toward weakest types — un-mastered controls (box < 3) preferred
  const typeScores = {};
  CTS_TYPE_IDS.forEach(t => {
    const pt = m.perType[t] || { seen: 0, correct: 0 };
    const acc = pt.seen > 0 ? pt.correct / pt.seen : 0;
    typeScores[t] = 1.5 - acc;
  });
  const unmastered = CTS_DATA.filter(c => {
    const pi = m.perControl[c.id] || { box: 1 };
    return pi.box < 3;
  });
  const pool = unmastered.length >= 5 ? unmastered : CTS_DATA;
  const weights = pool.map(c => typeScores[c.type] || 1);
  const total = weights.reduce((s, w) => s + w, 0);
  let r = Math.random() * total;
  for (let i = 0; i < pool.length; i++) {
    r -= weights[i];
    if (r <= 0) return pool[i];
  }
  return pool[pool.length - 1];
}

function ctsNextQuestion() {
  if (ctsIdx >= ctsSessionLength) { ctsEndSession(); return; }
  ctsIdx++;
  ctsQ = ctsPickControl();
  ctsPickedType = null;
  ctsPickedCat = null;
  ctsRenderQuestion();
}

// v4.99.77 (Rebrand Batch 4m): the secplus-control-type-sorter mockup's
// exact monoline SVG icon set for the 6 control types. Additive + render-
// only (the Network Builder tbPaletteLineIcon precedent) — replaces the
// emoji `t.icon` at every CTS type-icon site so the drill is icon-faithful
// to the locked mockup. Inherits currentColor; sized by scoped Batch 4m.
function _ctsLineIcon(typeId) {
  const P = {
    prev:  '<rect x="5" y="11" width="14" height="9" rx="2" stroke="currentColor" stroke-width="1.6"/><path d="M8 11V8a4 4 0 0 1 8 0v3" stroke="currentColor" stroke-width="1.6"/>',
    det:   '<circle cx="11" cy="11" r="6" stroke="currentColor" stroke-width="1.6"/><path d="M16 16l4 4" stroke="currentColor" stroke-width="1.6" stroke-linecap="round"/>',
    corr:  '<path d="M14.7 6.3a4 4 0 0 0-5.4 5.3L3 18l3 3 6.4-6.3a4 4 0 0 0 5.3-5.4l-2.6 2.6-2.4-.6-.6-2.4 2.6-2.6z" stroke="currentColor" stroke-width="1.5" stroke-linejoin="round"/>',
    deter: '<path d="M10.3 4l-7 12a2 2 0 0 0 1.7 3h14a2 2 0 0 0 1.7-3l-7-12a2 2 0 0 0-3.4 0z" stroke="currentColor" stroke-width="1.6" stroke-linejoin="round"/><path d="M12 9v4M12 16h.01" stroke="currentColor" stroke-width="1.6" stroke-linecap="round"/>',
    comp:  '<path d="M4 12a8 8 0 0 1 13.7-5.7L20 8M20 4v4h-4M20 12a8 8 0 0 1-13.7 5.7L4 16M4 20v-4h4" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"/>',
    dir:   '<rect x="6" y="4" width="12" height="16" rx="2" stroke="currentColor" stroke-width="1.6"/><path d="M9 8h6M9 12h6M9 16h4" stroke="currentColor" stroke-width="1.6" stroke-linecap="round"/>'
  };
  return '<svg viewBox="0 0 24 24" fill="none" aria-hidden="true">' + (P[typeId] || '') + '</svg>';
}

function ctsRenderQuestion() {
  const card = document.getElementById('cts-q-card');
  if (!card || !ctsQ) return;
  const ctrl = ctsQ;
  card.innerHTML = `
    <div class="cts-q-eyebrow">Classify the control</div>
    <div class="cts-q-stem-card">
      <div class="cts-q-stem-name">${escHtml(ctrl.name)}</div>
      <div class="cts-q-stem-sub">${escHtml(ctrl.desc)}</div>
      <div class="cts-q-stem-meta">SY0-701 &middot; Domain ${escHtml(ctrl.obj || '?')} &middot; Security controls</div>
    </div>
    <div class="cts-q-arrow">&darr; pick the TYPE</div>
    <div class="cts-q-grid">
      ${CTS_TYPE_IDS.map(tid => {
        const t = CTS_TYPES[tid];
        return `<button class="cts-q-opt" data-cts-type="${tid}" onclick="ctsPickType('${tid}')">
          <span class="cts-q-opt-icon">${_ctsLineIcon(tid)}</span>
          ${escHtml(t.label)}
        </button>`;
      }).join('')}
    </div>
    <div class="cts-q-cat-row">
      <span class="cts-q-cat-row-label">&darr; AND category</span>
      ${CTS_CAT_IDS.map(cid => {
        const c = CTS_CATEGORIES[cid];
        return `<button class="cts-q-cat-pill" data-cts-cat="${cid}" onclick="ctsPickCat('${cid}')">${escHtml(c.label)}</button>`;
      }).join('')}
    </div>
    <div id="cts-reveal" class="is-hidden"></div>
    <div class="cts-q-foot">
      <span id="cts-q-status">Pick TYPE + CATEGORY</span>
      <span style="display:flex;gap:10px;align-items:center">
        <span class="cts-q-progress">Q ${ctsIdx} / ${ctsSessionLength}</span>
        <button class="cts-submit-btn" id="cts-submit-btn" onclick="ctsSubmitAnswer()" disabled>Submit &rarr;</button>
      </span>
    </div>
  `;
  // Update stats strip
  const scoreEl = document.getElementById('cts-score');
  const streakEl = document.getElementById('cts-streak');
  const progEl = document.getElementById('cts-q-progress');
  const badgeEl = document.getElementById('cts-streak-badge');
  if (scoreEl) scoreEl.textContent = ctsCorrect + ' / ' + ctsTotal;
  if (streakEl) streakEl.textContent = '' + ctsStreak;
  if (progEl) progEl.textContent = 'Q ' + ctsIdx + ' / ' + ctsSessionLength;
  if (badgeEl) badgeEl.textContent = '' + ctsStreak;
}

function ctsPickType(typeId) {
  if (!ctsQ) return;
  ctsPickedType = typeId;
  // Highlight chosen type with type-specific color class
  document.querySelectorAll('.cts-q-opt').forEach(b => {
    b.classList.remove('cts-active-prev','cts-active-det','cts-active-corr','cts-active-deter','cts-active-comp','cts-active-dir');
    if (b.getAttribute('data-cts-type') === typeId) {
      b.classList.add('cts-active-' + typeId);
    }
  });
  ctsUpdateSubmitButton();
}

function ctsPickCat(catId) {
  if (!ctsQ) return;
  ctsPickedCat = catId;
  document.querySelectorAll('.cts-q-cat-pill').forEach(b => {
    b.classList.toggle('cts-cat-active', b.getAttribute('data-cts-cat') === catId);
  });
  ctsUpdateSubmitButton();
}

function ctsUpdateSubmitButton() {
  const btn = document.getElementById('cts-submit-btn');
  const status = document.getElementById('cts-q-status');
  if (!btn) return;
  const ready = ctsPickedType && ctsPickedCat;
  btn.disabled = !ready;
  if (status) status.textContent = ready ? 'Both axes locked in · ready to submit' : 'Pick TYPE + CATEGORY';
}

function ctsSubmitAnswer() {
  if (!ctsQ || !ctsPickedType || !ctsPickedCat) return;
  const ctrl = ctsQ;
  const typeCorrect = ctsPickedType === ctrl.type;
  const catCorrect = ctsPickedCat === ctrl.cat;
  const isCorrect = typeCorrect && catCorrect;
  ctsTotal++;
  if (isCorrect) { ctsCorrect++; ctsStreak++; } else { ctsStreak = 0; }
  updateCtsMastery(ctrl.id, isCorrect);

  // Disable buttons + show correct/wrong styling
  document.querySelectorAll('.cts-q-opt').forEach(b => {
    b.disabled = true;
    const tid = b.getAttribute('data-cts-type');
    if (tid === ctrl.type) b.classList.add('cts-show-correct');
    if (tid === ctsPickedType && !typeCorrect) b.classList.add('cts-show-wrong');
  });
  document.querySelectorAll('.cts-q-cat-pill').forEach(b => {
    b.disabled = true;
    const cid = b.getAttribute('data-cts-cat');
    if (cid === ctrl.cat) b.classList.add('cts-show-correct');
    if (cid === ctsPickedCat && !catCorrect) b.classList.add('cts-show-wrong');
  });

  // Reveal panel
  const reveal = document.getElementById('cts-reveal');
  if (reveal) {
    const correctType = CTS_TYPES[ctrl.type];
    const correctCat = CTS_CATEGORIES[ctrl.cat];
    const headLine = isCorrect
      ? `${escHtml(correctType.label)} ✓ + ${escHtml(correctCat.label)} ✓`
      : `${typeCorrect ? '✓' : '✗'} ${escHtml(correctType.label)} type · ${catCorrect ? '✓' : '✗'} ${escHtml(correctCat.label)} category`;
    reveal.classList.remove('is-hidden');
    reveal.innerHTML = `
      <div class="cts-reveal">
        <div class="cts-reveal-head">${headLine}</div>
        <p class="cts-reveal-prose">${escHtml(ctrl.why)}</p>
        <div class="cts-reveal-actions">
          <button class="btn btn-primary cts-reveal-btn" onclick="ctsNextQuestion()">${ctsIdx >= ctsSessionLength ? 'See results &rarr;' : 'Next question &rarr;'}</button>
        </div>
      </div>
    `;
  }
  // Hide submit button (replaced by Next in reveal panel)
  const btn = document.getElementById('cts-submit-btn');
  if (btn) btn.style.display = 'none';
  const status = document.getElementById('cts-q-status');
  if (status) status.innerHTML = isCorrect
    ? '<span style="color:var(--green)">✓ Both axes correct &middot; ' + ctsStreak + '/' + ctsStreak + ' streak</span>'
    : '<span style="color:var(--red)">✗ Wrong &middot; streak reset</span>';

  // Update score
  const scoreEl = document.getElementById('cts-score');
  const streakEl = document.getElementById('cts-streak');
  const badgeEl = document.getElementById('cts-streak-badge');
  if (scoreEl) scoreEl.textContent = ctsCorrect + ' / ' + ctsTotal;
  if (streakEl) streakEl.textContent = '' + ctsStreak;
  if (badgeEl) badgeEl.textContent = '' + ctsStreak;
  if (typeof evaluateMilestones === 'function') evaluateMilestones();
}

function ctsEndSession() {
  ctsSessionDone = true;
  const card = document.getElementById('cts-q-card');
  const endCard = document.getElementById('cts-end-card');
  if (card) card.classList.add('is-hidden');
  if (!endCard) return;
  endCard.classList.remove('is-hidden');
  // Find weakest type
  const m = getCtsMastery();
  let weakest = null, weakestAcc = 1.1;
  CTS_TYPE_IDS.forEach(t => {
    const pt = m.perType[t] || { seen: 0, correct: 0 };
    if (pt.seen >= 1) {
      const acc = pt.correct / pt.seen;
      if (acc < weakestAcc) { weakestAcc = acc; weakest = t; }
    }
  });
  const weakestLabel = weakest ? CTS_TYPES[weakest].label : '—';
  const acc = ctsTotal > 0 ? Math.round((ctsCorrect / ctsTotal) * 100) : 0;
  endCard.innerHTML = `
    <div class="cts-eos-card">
      <div class="cts-eos-burst">🛡</div>
      <h2 class="cts-eos-title">Drill complete.</h2>
      <p class="cts-eos-sub">${ctsCorrect}/${ctsTotal} right &middot; ${ctsStreak >= 5 ? ctsStreak + '-question streak!' : 'Keep stacking those reps.'}</p>
      <div class="cts-eos-score-row">
        <div class="cts-eos-score-tile"><div class="cts-eos-score-num">${acc}%</div><div class="cts-eos-score-lbl">accuracy</div></div>
        <div class="cts-eos-score-tile"><div class="cts-eos-score-num">${ctsCorrect}</div><div class="cts-eos-score-lbl">correct</div></div>
        <div class="cts-eos-score-tile"><div class="cts-eos-score-num">${m.totalAnswered}</div><div class="cts-eos-score-lbl">total seen</div></div>
      </div>
      ${weakest ? `<div class="cts-eos-weak"><strong>Next focus:</strong> ${weakestLabel} (${Math.round(weakestAcc * 100)}% mastered) — drill weighted there next.</div>` : ''}
      <div class="cts-eos-actions">
        <button class="btn btn-primary" onclick="startControlTypeSorter()">Practice again →</button>
        <button class="btn btn-ghost" onclick="setCtsTab('dashboard')">Back to dashboard</button>
      </div>
    </div>
  `;
}

function ctsRenderLessons() {
  const host = document.getElementById('cts-lessons-content');
  if (!host) return;
  if (!CTS_LESSONS.length) {
    host.innerHTML = '<p style="text-align:center;color:var(--text-mid);padding:32px">No lessons available.</p>';
    return;
  }
  // Render the full 6×4 matrix as a single reference card
  host.innerHTML = `
    <div class="cts-lesson-card">
      <div class="cts-lesson-head">
        <div class="cts-lesson-icon">🛡</div>
        <div>
          <div class="cts-lesson-title">The CompTIA 6×4 control matrix</div>
          <div class="cts-lesson-sub">SY0-701 Domain 1.1 · 24 cells with example controls</div>
        </div>
      </div>
      <div class="cts-lesson-matrix">
        <div class="cts-lm-h"></div>
        ${CTS_CAT_IDS.map(cid => `<div class="cts-lm-h">${escHtml(CTS_CATEGORIES[cid].label)}</div>`).join('')}
        ${CTS_LESSONS.map(l => {
          const tid = l.type;
          const t = CTS_TYPES[tid] || { label: tid, icon: '', color: 'var(--accent)' };
          return `
            <div class="cts-lm-h cts-lm-row" style="color:${t.color}">${_ctsLineIcon(tid)} ${escHtml(t.label)}</div>
            ${CTS_CAT_IDS.map(cid => {
              const examples = (l.cells && l.cells[cid]) || [];
              return `<div class="cts-lm-cell">${examples.map(e => escHtml(e)).join('<br><em>')}</em></div>`;
            }).join('')}
          `;
        }).join('')}
      </div>
      <div class="cts-lesson-summaries">
        ${CTS_LESSONS.map(l => `
          <div class="cts-lesson-sum"><span class="cts-lesson-sum-label" style="color:${(CTS_TYPES[l.type] || {}).color}">${_ctsLineIcon(l.type)} ${escHtml(l.title)}:</span> ${escHtml(l.summary)}</div>
        `).join('')}
      </div>
    </div>
  `;
}

function ctsRenderDashboard() {
  const host = document.getElementById('cts-dashboard-content');
  if (!host) return;
  const m = getCtsMastery();
  const totalMastered = Object.values(m.perControl).filter(p => p.box >= 3).length;
  const totalSeen = Object.values(m.perControl).filter(p => p.seen > 0).length;
  const overallAcc = m.totalAnswered > 0 ? Math.round((m.totalCorrect / m.totalAnswered) * 100) : 0;

  // Per-type rows
  const typeRows = CTS_TYPE_IDS.map(tid => {
    const t = CTS_TYPES[tid];
    const pt = m.perType[tid] || { seen: 0, correct: 0 };
    const total = CTS_DATA.filter(c => c.type === tid).length;
    const mastered = CTS_DATA.filter(c => c.type === tid && (m.perControl[c.id] || {}).box >= 3).length;
    const pct = total > 0 ? Math.round((mastered / total) * 100) : 0;
    return { tid, t, mastered, total, pct, seen: pt.seen };
  });
  const weakestType = typeRows.filter(r => r.seen > 0).sort((a, b) => a.pct - b.pct)[0] || null;

  host.innerHTML = `
    <div class="cts-dash">
      <div class="cts-dash-card">
        <div class="cts-dash-card-head">Mastery by control type</div>
        <div class="cts-dash-type-grid">
          ${typeRows.map(r => `
            <div class="cts-dash-type-row" style="background:${r.t.color}1a;border-left:3px solid ${r.t.color}">
              <span class="cts-dash-type-icon">${_ctsLineIcon(r.tid)}</span>
              <span class="cts-dash-type-name">${escHtml(r.t.label)}</span>
              <span class="cts-dash-type-pct">${r.mastered}/${r.total}</span>
            </div>
          `).join('')}
        </div>
      </div>
      <div class="cts-dash-side">
        ${weakestType ? `
          <div class="cts-dash-card cts-dash-weakest">
            <div class="cts-dash-card-head">Weakest type</div>
            <div class="cts-dash-weak-name">${_ctsLineIcon(weakestType.tid)} ${escHtml(weakestType.t.label)} (${weakestType.mastered}/${weakestType.total} mastered)</div>
            <div class="cts-dash-weak-sub">Drill weighted there next session.</div>
          </div>
        ` : `
          <div class="cts-dash-card">
            <div class="cts-dash-card-head">Common confusion</div>
            <div style="font-size:12px;color:var(--text-mid);line-height:1.5">Detective vs Preventive — IDS is Detective (alerts), IPS is Preventive (blocks). Same hardware, different control type.</div>
          </div>
        `}
        <button class="cts-dash-cta" onclick="startControlTypeSorter()">Start ${ctsSessionLength}-question MCQ drill →</button>
        <div class="cts-dash-overall">
          <div><span class="cts-dash-overall-num">${totalMastered}</span><span class="cts-dash-overall-lbl">mastered</span></div>
          <div><span class="cts-dash-overall-num">${totalSeen}</span><span class="cts-dash-overall-lbl">seen</span></div>
          <div><span class="cts-dash-overall-num">${overallAcc}%</span><span class="cts-dash-overall-lbl">accuracy</span></div>
        </div>
      </div>
    </div>
  `;
}

function setCtsTab(tabId) {
  document.querySelectorAll('.cts-tab-btn').forEach(b => {
    const id = b.id.replace('cts-tab-btn-', '');
    const active = id === tabId;
    b.classList.toggle('cts-tab-active', active);
    b.setAttribute('aria-selected', active ? 'true' : 'false');
    b.tabIndex = active ? 0 : -1;
  });
  ['practice', 'lessons', 'dashboard'].forEach(p => {
    const panel = document.getElementById('cts-tab-' + p);
    if (!panel) return;
    panel.classList.toggle('is-hidden', p !== tabId);
  });
  if (tabId === 'lessons') ctsRenderLessons();
  else if (tabId === 'dashboard') ctsRenderDashboard();
}

function startControlTypeSorter() {
  if (!_gateProOnly('Control Type Sorter')) return;
  if (!_USE_SECPLUS_CTS) {
    if (typeof showToast === 'function') showToast('Control Type Sorter is Security+ only.', 'info');
    return;
  }
  ctsIdx = 0; ctsCorrect = 0; ctsTotal = 0; ctsStreak = 0;
  ctsSessionDone = false;
  ctsPickedType = null; ctsPickedCat = null;
  setCtsTab('practice');
  const card = document.getElementById('cts-q-card');
  const endCard = document.getElementById('cts-end-card');
  if (card) card.classList.remove('is-hidden');
  if (endCard) endCard.classList.add('is-hidden');
  ctsNextQuestion();
}

// ── Packet Trace Drill (v4.96.0, issue #305) ────────────────────────────
// Network+-only drill walking a packet through curated networks hop-by-hop.
// 5 scenarios at v1 (~21 step questions). Visual contract: yellow trace stage
// with animated orange-amber packet dot + caption card + MCQ panel beneath.
// State machine:
//   - Dashboard (scenario picker) → user picks a scenario → Practice (in-trace)
//   - Within a scenario: step 1..N, each step pins packet to a device, asks MCQ
//   - Wrong → reveal explanation, advance anyway (teaching moment)
//   - Right → reveal explanation, advance
//   - Last step → end-of-scenario card, mastery if all correct in this run
let ptrScenario = null, ptrStepIdx = 0, ptrCorrectThisRun = 0;
let ptrAnswered = false, ptrPickedIdx = null;

function getPtrMastery() {
  try {
    const raw = JSON.parse(localStorage.getItem(STORAGE.PT_MASTERY) || 'null');
    if (raw && raw.perScenario) return raw;
  } catch (_) {}
  return ptrInitMastery();
}

function ptrInitMastery() {
  const m = { perScenario: {}, totalAttempted: 0, totalCorrect: 0 };
  PT_DATA.forEach(s => { m.perScenario[s.id] = { mastered: false, runs: 0, bestStepsCorrect: 0, totalSteps: s.steps.length, lastAttemptAt: null }; });
  return m;
}

function savePtrMastery(m) {
  try { localStorage.setItem(STORAGE.PT_MASTERY, JSON.stringify(m)); _cloudFlush(STORAGE.PT_MASTERY); } catch (_) {}
}

function ptrSaveResume(state) {
  try {
    if (state == null) localStorage.removeItem(STORAGE.PT_RESUME);
    else localStorage.setItem(STORAGE.PT_RESUME, JSON.stringify(state));
    _cloudFlush(STORAGE.PT_RESUME);
  } catch (_) {}
}

function ptrGetResume() {
  try { return JSON.parse(localStorage.getItem(STORAGE.PT_RESUME) || 'null'); } catch (_) { return null; }
}

function ptrIsScenarioUnlocked(scenario) {
  if (!scenario.unlockAfter || scenario.unlockAfter.length === 0) return true;
  const m = getPtrMastery();
  return scenario.unlockAfter.every(reqId => (m.perScenario[reqId] || {}).mastered);
}

// Shared SVG renderer — reads JSON network description, returns SVG string.
// Devices supported: pc, laptop, switch, router, server. Unknown = generic rect.
function _renderTraceSvg(network, packetAtId, opts) {
  opts = opts || {};
  const w = 600, h = 320;
  let out = '<svg viewBox="0 0 ' + w + ' ' + h + '" xmlns="http://www.w3.org/2000/svg">';

  // Subnet boxes (background — under everything)
  (network.subnets || []).forEach(sn => {
    const fill = sn.color === 'amber' ? 'rgba(217,119,6,.08)'
               : 'rgba(107,107,144,.08)';
    const stroke = sn.color === 'amber' ? 'rgba(217,119,6,.3)'
                 : 'rgba(107,107,144,.3)';
    const text = sn.color === 'amber' ? '#d97706'
               : '#6b6b90';
    out += '<rect x="' + sn.boxX + '" y="' + sn.boxY + '" width="' + sn.boxW + '" height="' + sn.boxH + '" rx="4" fill="' + fill + '" stroke="' + stroke + '" stroke-width="1"/>';
    out += '<text x="' + (sn.boxX + sn.boxW/2) + '" y="' + (sn.boxY + sn.boxH/2 + 4) + '" text-anchor="middle" fill="' + text + '" font-size="11" font-weight="700">' + escHtml(sn.cidr) + (sn.label ? ' — ' + escHtml(sn.label) : '') + '</text>';
  });

  // Cables (under devices)
  const deviceById = {};
  (network.devices || []).forEach(d => { deviceById[d.id] = d; });
  (network.cables || []).forEach(c => {
    const a = deviceById[c.from], b = deviceById[c.to];
    if (!a || !b) return;
    const stroke = c.type === 'remote' ? '#d1d5db' : '#9ca3af';
    const dash = c.type === 'remote' ? ' stroke-dasharray="4 4"' : '';
    // Estimate centers (devices are ~44 wide × ~32 tall; centered roughly)
    out += '<line x1="' + (a.x + 22) + '" y1="' + (a.y + 16) + '" x2="' + (b.x + 22) + '" y2="' + (b.y + 16) + '" stroke="' + stroke + '" stroke-width="2"' + dash + '/>';
  });

  // Devices
  (network.devices || []).forEach(d => {
    out += _renderDeviceGlyph(d);
  });

  // Animated packet at current device. Class hooks on the <circle> + <text>
  // let v4.96.1's slide animation in ptrAdvance() tween cx/cy between hops.
  if (packetAtId) {
    const dev = deviceById[packetAtId];
    if (dev) {
      const cx = dev.x + 22, cy = dev.y + 16;
      out += '<circle class="ptr-packet" cx="' + cx + '" cy="' + cy + '" r="9" fill="#d97706" stroke="#fff" stroke-width="2.5">';
      out += '<animate attributeName="opacity" values=".7;1;.7" dur="1.6s" repeatCount="indefinite"/>';
      out += '</circle>';
      out += '<text class="ptr-packet-here" x="' + cx + '" y="' + (cy - 35) + '" text-anchor="middle" fill="#d97706" font-size="9" font-weight="700">packet here</text>';
    }
  }

  out += '</svg>';
  return out;
}

function _renderDeviceGlyph(d) {
  const x = d.x, y = d.y;
  let out = '';
  const safeIp = d.ip ? escHtml(String(d.ip).replace(/\n/g, ' ')) : '';
  const safeLabel = escHtml(String(d.label).replace(/\n/g, ' '));
  if (d.type === 'pc' || d.type === 'laptop') {
    out += '<rect x="' + x + '" y="' + y + '" width="44" height="32" rx="4" fill="#fff" stroke="#d97706" stroke-width="2"/>';
    out += '<rect x="' + (x+6) + '" y="' + (y+6) + '" width="32" height="22" fill="#fbbf24"/>';
  } else if (d.type === 'switch') {
    out += '<rect x="' + x + '" y="' + y + '" width="48" height="32" rx="4" fill="#1a1a2e" stroke="#06b6d4" stroke-width="2"/>';
    out += '<line x1="' + (x+8) + '" y1="' + (y+8) + '" x2="' + (x+40) + '" y2="' + (y+8) + '" stroke="#22c55e" stroke-width="1"/>';
    out += '<line x1="' + (x+8) + '" y1="' + (y+15) + '" x2="' + (x+40) + '" y2="' + (y+15) + '" stroke="#22c55e" stroke-width="1"/>';
    out += '<line x1="' + (x+8) + '" y1="' + (y+22) + '" x2="' + (x+40) + '" y2="' + (y+22) + '" stroke="#fbbf24" stroke-width="1"/>';
  } else if (d.type === 'router') {
    out += '<rect x="' + x + '" y="' + (y-5) + '" width="48" height="42" rx="6" fill="#1a1a2e" stroke="#9ca3af" stroke-width="2"/>';
    out += '<circle cx="' + (x+10) + '" cy="' + (y+8) + '" r="2" fill="#22c55e"/>';
    out += '<circle cx="' + (x+20) + '" cy="' + (y+8) + '" r="2" fill="#22c55e"/>';
    out += '<circle cx="' + (x+30) + '" cy="' + (y+8) + '" r="2" fill="#fbbf24"/>';
    out += '<circle cx="' + (x+40) + '" cy="' + (y+8) + '" r="2" fill="#22c55e"/>';
  } else if (d.type === 'server') {
    out += '<rect x="' + x + '" y="' + y + '" width="44" height="36" rx="4" fill="#fff" stroke="#16a34a" stroke-width="2"/>';
    out += '<rect x="' + (x+5) + '" y="' + (y+5) + '" width="14" height="8" fill="#22c55e"/>';
    out += '<rect x="' + (x+5) + '" y="' + (y+17) + '" width="34" height="3" fill="#9ca3af"/>';
    out += '<rect x="' + (x+5) + '" y="' + (y+24) + '" width="34" height="3" fill="#9ca3af"/>';
    out += '<rect x="' + (x+5) + '" y="' + (y+31) + '" width="34" height="3" fill="#9ca3af"/>';
  } else {
    out += '<rect x="' + x + '" y="' + y + '" width="44" height="32" rx="4" fill="#f4f5fa" stroke="#9ca3af" stroke-width="2"/>';
  }
  // Label below device
  out += '<text x="' + (x+22) + '" y="' + (y+50) + '" text-anchor="middle" fill="currentColor" font-size="10" font-weight="700" class="ptr-device-label">' + safeLabel + '</text>';
  if (safeIp) {
    out += '<text x="' + (x+22) + '" y="' + (y+62) + '" text-anchor="middle" fill="#6b6b90" font-size="9" class="ptr-device-ip">' + safeIp + '</text>';
  }
  return out;
}

function ptrRenderStage() {
  const host = document.getElementById('ptr-stage-host');
  if (!host || !ptrScenario) return;
  const step = ptrScenario.steps[ptrStepIdx];
  const network = ptrScenario.network;
  const totalSteps = ptrScenario.steps.length;
  // Build progress dots
  const dots = ptrScenario.steps.map((_, i) => {
    let cls = 'ptr-prog-dot';
    if (i < ptrStepIdx) cls += ' is-done';
    else if (i === ptrStepIdx) cls += ptrAnswered ? ' is-current is-answered' : ' is-current';
    return '<span class="' + cls + '"></span>';
  }).join('');
  let optionsHtml = '';
  step.question.options.forEach((opt, i) => {
    let cls = 'ptr-opt';
    if (ptrAnswered) {
      if (i === step.question.correctIdx) cls += ' is-correct';
      if (i === ptrPickedIdx && i !== step.question.correctIdx) cls += ' is-wrong';
    }
    const letter = String.fromCharCode(65 + i);
    optionsHtml += `<button class="${cls}" data-ptr-opt="${i}" onclick="ptrPickAnswer(${i})" ${ptrAnswered ? 'disabled' : ''}><span class="ptr-opt-letter">${letter}</span> ${escHtml(opt)}</button>`;
  });
  let revealHtml = '';
  if (ptrAnswered) {
    const isCorrect = ptrPickedIdx === step.question.correctIdx;
    const nextLabel = ptrStepIdx + 1 >= totalSteps ? 'See results &rarr;' : 'Next hop &rarr;';
    revealHtml = `
      <div class="ptr-reveal">
        <div class="ptr-reveal-head">${isCorrect ? 'Correct' : 'Why ' + escHtml(step.question.options[step.question.correctIdx]) + ' is the answer'}</div>
        <p class="ptr-reveal-prose">${escHtml(step.question.why)}</p>
        <div class="ptr-reveal-actions">
          <button class="btn btn-primary ptr-reveal-btn" onclick="ptrAdvance()">${nextLabel}</button>
        </div>
      </div>
    `;
  }
  host.innerHTML = `
    <div class="trace-stage">
      <div class="trace-stage-head">
        <div>
          <div class="trace-stage-title"><span class="trace-stage-icon">${escHtml(ptrScenario.icon || '')}</span>${escHtml(ptrScenario.title)}</div>
          <div class="trace-stage-sub">${escHtml(ptrScenario.summary)}</div>
        </div>
        <span class="trace-step-pill">Step ${ptrStepIdx + 1} of ${totalSteps}</span>
      </div>
      <div class="trace-canvas-wrap">
        <div class="trace-stage-bg"></div>
        ${_renderTraceSvg(network, step.at)}
        <div class="trace-caption">
          <div class="trace-caption-step">${escHtml(step.caption.title)}</div>
          <div class="trace-caption-action">${escHtml(step.caption.action)}</div>
          <div class="trace-caption-detail">${escHtml(step.caption.detail)}</div>
        </div>
      </div>
    </div>
    <div class="trace-question">
      <div class="tq-eyebrow">Hop question — Step ${ptrStepIdx + 1}</div>
      <div class="tq-stem">${escHtml(step.question.stem)}</div>
      <div class="tq-options">${optionsHtml}</div>
      ${revealHtml}
      <div class="tq-foot">
        <span style="font-family:'SF Mono',monospace">scenario · ${totalSteps} hops</span>
        <span class="tq-progress">${dots}</span>
      </div>
    </div>
  `;
  // Update streak badge
  const badge = document.getElementById('ptr-streak-badge');
  if (badge) badge.textContent = '' + ptrCorrectThisRun;
}

function ptrPickAnswer(optIdx) {
  if (ptrAnswered || !ptrScenario) return;
  ptrAnswered = true;
  ptrPickedIdx = optIdx;
  const step = ptrScenario.steps[ptrStepIdx];
  const isCorrect = optIdx === step.question.correctIdx;
  if (isCorrect) ptrCorrectThisRun++;
  // Save resume
  ptrSaveResume({ scenarioId: ptrScenario.id, stepIdx: ptrStepIdx, correctSoFar: ptrCorrectThisRun });
  ptrRenderStage();
  if (typeof evaluateMilestones === 'function') evaluateMilestones();
}

function ptrAdvance() {
  if (!ptrScenario) return;
  // v4.96.1: slide the packet across the cable from current device → next device
  // before re-rendering. Falls back to instant teleport if motion is suppressed
  // or the SVG packet element isn't present (initial step, fast-clicks, etc.).
  const nextStepIdx = ptrStepIdx + 1;
  if (nextStepIdx >= ptrScenario.steps.length) {
    ptrStepIdx = nextStepIdx;
    ptrEndScenario();
    return;
  }
  const fromStep = ptrScenario.steps[ptrStepIdx];
  const toStep = ptrScenario.steps[nextStepIdx];
  const devices = (ptrScenario.network && ptrScenario.network.devices) || [];
  const fromDev = devices.find(d => d.id === fromStep.at);
  const toDev = devices.find(d => d.id === toStep.at);
  const prefersReduced = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const packet = document.querySelector('#ptr-stage-host .ptr-packet');
  const indicator = document.querySelector('#ptr-stage-host .ptr-packet-here');

  const finalize = () => {
    ptrStepIdx = nextStepIdx;
    ptrAnswered = false;
    ptrPickedIdx = null;
    ptrSaveResume({ scenarioId: ptrScenario.id, stepIdx: ptrStepIdx, correctSoFar: ptrCorrectThisRun });
    ptrRenderStage();
  };

  if (!prefersReduced && packet && fromDev && toDev && fromDev.id !== toDev.id) {
    // Suppress the "⬇ packet here" indicator during the slide so it doesn't
    // visually lag behind the packet. The new step's render restores it.
    if (indicator) indicator.style.opacity = '0';
    // Disable next-button + answer buttons during the tween (they're already
    // disabled, but a fast double-click during the tween shouldn't requeue).
    document.querySelectorAll('#ptr-stage-host .ptr-reveal-btn').forEach(b => { b.disabled = true; });
    // Update circle attrs — CSS transition on .ptr-packet handles the tween.
    packet.setAttribute('cx', String(toDev.x + 22));
    packet.setAttribute('cy', String(toDev.y + 16));
    setTimeout(finalize, 700);  // tween duration (650ms) + small safety buffer
  } else {
    finalize();
  }
}

function ptrEndScenario() {
  if (!ptrScenario) return;
  // Update mastery
  const m = getPtrMastery();
  if (!m.perScenario[ptrScenario.id]) m.perScenario[ptrScenario.id] = { mastered: false, runs: 0, bestStepsCorrect: 0, totalSteps: ptrScenario.steps.length, lastAttemptAt: null };
  const sm = m.perScenario[ptrScenario.id];
  sm.runs++;
  sm.totalSteps = ptrScenario.steps.length;
  if (ptrCorrectThisRun > sm.bestStepsCorrect) sm.bestStepsCorrect = ptrCorrectThisRun;
  if (ptrCorrectThisRun === ptrScenario.steps.length) sm.mastered = true;
  sm.lastAttemptAt = Date.now();
  m.totalAttempted++;
  m.totalCorrect += ptrCorrectThisRun;
  savePtrMastery(m);
  // Clear resume — scenario is done
  ptrSaveResume(null);
  // Render end card
  const stageHost = document.getElementById('ptr-stage-host');
  const endCard = document.getElementById('ptr-end-card');
  if (stageHost) stageHost.innerHTML = '';
  if (!endCard) return;
  endCard.classList.remove('is-hidden');
  const isPerfect = ptrCorrectThisRun === ptrScenario.steps.length;
  const acc = Math.round((ptrCorrectThisRun / ptrScenario.steps.length) * 100);
  endCard.innerHTML = `
    <div class="ptr-eos-card">
      <div class="ptr-eos-burst"></div>
      <h2 class="ptr-eos-title">${isPerfect ? 'Scenario mastered.' : 'Scenario complete.'}</h2>
      <p class="ptr-eos-sub">${ptrCorrectThisRun}/${ptrScenario.steps.length} hops correct${isPerfect ? ' — perfect run, scenario marked mastered ✓' : ' · keep practicing for the perfect run that locks in mastery'}</p>
      <div class="ptr-eos-score-row">
        <div class="ptr-eos-score-tile"><div class="ptr-eos-score-num">${acc}%</div><div class="ptr-eos-score-lbl">accuracy</div></div>
        <div class="ptr-eos-score-tile"><div class="ptr-eos-score-num">${ptrCorrectThisRun}/${ptrScenario.steps.length}</div><div class="ptr-eos-score-lbl">hops</div></div>
        <div class="ptr-eos-score-tile"><div class="ptr-eos-score-num">${sm.runs}</div><div class="ptr-eos-score-lbl">runs</div></div>
      </div>
      <div class="ptr-eos-actions">
        <button class="btn btn-primary" onclick="ptrStartScenario('${ptrScenario.id}')">${isPerfect ? 'Run again →' : 'Try again →'}</button>
        <button class="btn btn-ghost" onclick="setPtrTab('dashboard')">Back to dashboard</button>
      </div>
    </div>
  `;
  ptrScenario = null;
  ptrStepIdx = 0;
  ptrCorrectThisRun = 0;
}

function ptrStartScenario(scenarioId) {
  if (!_gateProOnly('Packet Trace')) return;
  const s = PT_DATA.find(x => x.id === scenarioId);
  if (!s) {
    if (typeof showToast === 'function') showToast('Scenario not found.', 'error');
    return;
  }
  if (!ptrIsScenarioUnlocked(s)) {
    if (typeof showToast === 'function') showToast('Master earlier scenarios to unlock this one.', 'info');
    return;
  }
  ptrScenario = s;
  ptrStepIdx = 0;
  ptrCorrectThisRun = 0;
  ptrAnswered = false;
  ptrPickedIdx = null;
  setPtrTab('practice');
  const endCard = document.getElementById('ptr-end-card');
  if (endCard) endCard.classList.add('is-hidden');
  ptrSaveResume({ scenarioId: s.id, stepIdx: 0, correctSoFar: 0 });
  ptrRenderStage();
}

function ptrResumeScenario() {
  const r = ptrGetResume();
  if (!r || !r.scenarioId) {
    if (typeof showToast === 'function') showToast('Nothing to resume — pick a scenario.', 'info');
    return;
  }
  const s = PT_DATA.find(x => x.id === r.scenarioId);
  if (!s) { ptrSaveResume(null); return; }
  ptrScenario = s;
  ptrStepIdx = Math.min(r.stepIdx || 0, s.steps.length - 1);
  ptrCorrectThisRun = r.correctSoFar || 0;
  ptrAnswered = false;
  ptrPickedIdx = null;
  setPtrTab('practice');
  const endCard = document.getElementById('ptr-end-card');
  if (endCard) endCard.classList.add('is-hidden');
  ptrRenderStage();
}

function ptrRenderDashboard() {
  const host = document.getElementById('ptr-dashboard-content');
  if (!host) return;
  const m = getPtrMastery();
  const masteredCount = Object.values(m.perScenario).filter(s => s.mastered).length;
  const totalSteps = PT_DATA.reduce((acc, s) => acc + s.steps.length, 0);
  const stepsMastered = Object.values(m.perScenario).reduce((acc, s) => acc + (s.bestStepsCorrect || 0), 0);
  const overallAcc = m.totalAttempted > 0 ? Math.round((m.totalCorrect / (m.totalAttempted * (totalSteps / PT_DATA.length))) * 100) : 0;
  const resume = ptrGetResume();
  const resumeScenario = resume ? PT_DATA.find(s => s.id === resume.scenarioId) : null;

  const rowsHtml = PT_DATA.map(s => {
    const sm = m.perScenario[s.id] || { mastered: false, runs: 0, bestStepsCorrect: 0 };
    const unlocked = ptrIsScenarioUnlocked(s);
    let cls = 'dash-scenario-row';
    let masteryHtml;
    if (!unlocked) {
      cls += ' is-locked';
      masteryHtml = '<span class="dash-scenario-mastery">unlock</span>';
    } else if (sm.mastered) {
      cls += ' is-mastered';
      masteryHtml = '<span class="dash-scenario-mastery">' + sm.bestStepsCorrect + '/' + s.steps.length + ' ✓</span>';
    } else {
      masteryHtml = '<span class="dash-scenario-mastery">' + (sm.bestStepsCorrect || 0) + '/' + s.steps.length + '</span>';
    }
    const diffPips = Array.from({length:3}, (_,i) => '<i class="ptr-pip' + (i < (s.diff || 1) ? ' on' : '') + '"></i>').join('');
    const onclick = unlocked ? `onclick="ptrStartScenario('${s.id}')"` : 'aria-disabled="true"';
    return `
      <button class="${cls}" ${onclick} type="button">
        <span class="dash-scenario-icon"></span>
        <div>
          <div class="dash-scenario-name">${escHtml(s.title)}</div>
          <div class="dash-scenario-meta">${s.steps.length} hops · objective ${escHtml(s.obj)} · <span class="ptr-pips">${diffPips}</span></div>
        </div>
        ${masteryHtml}
      </button>
    `;
  }).join('');

  host.innerHTML = `
    <div class="ptr-dash-head">
      <div>
        <div class="ptr-dash-eyebrow">Drill · Network+</div>
        <h2 class="ptr-dash-title">Packet Trace</h2>
        <p class="ptr-dash-sub">${PT_DATA.length} scenarios. Walk a packet through each network hop-by-hop, answer a question at each step.</p>
      </div>
      <div class="ptr-dash-stats">
        <div><div class="ptr-dash-stat-num">${masteredCount}</div><div>scenarios mastered</div></div>
        <div><div class="ptr-dash-stat-num">${stepsMastered}/${totalSteps}</div><div>steps mastered</div></div>
        <div><div class="ptr-dash-stat-num">${overallAcc || 0}%</div><div>accuracy</div></div>
      </div>
    </div>
    <div class="ptr-dash">
      <div class="ptr-dash-card">
        <div class="ptr-dash-card-head">Scenarios · ${PT_DATA.length} total</div>
        <div class="dash-scenario-list">${rowsHtml}</div>
      </div>
      <div class="ptr-dash-side">
        ${resumeScenario ? `
          <div class="ptr-dash-card">
            <div class="ptr-dash-card-head">Resume where you left off</div>
            <div style="font-size:13px;font-weight:600;margin-bottom:4px">${escHtml(resumeScenario.title)}</div>
            <div style="font-size:11.5px;color:var(--text-mid)">Step ${resume.stepIdx + 1} of ${resumeScenario.steps.length}</div>
            <button class="ptr-dash-cta" onclick="ptrResumeScenario()" style="margin-top:10px">▶ Resume scenario →</button>
          </div>
        ` : `
          <div class="ptr-dash-card">
            <div class="ptr-dash-card-head">Get started</div>
            <div style="font-size:12.5px;color:var(--text-mid);line-height:1.5">Pick any unlocked scenario from the list. First scenario (ARP basics) unlocks the rest progressively.</div>
          </div>
        `}
        ${PT_DATA.filter(s => !ptrIsScenarioUnlocked(s)).length > 0 ? `
          <div class="ptr-dash-card">
            <div class="ptr-dash-card-head">Locked</div>
            <div style="font-size:11.5px;color:var(--text-mid);line-height:1.5">${PT_DATA.filter(s => !ptrIsScenarioUnlocked(s)).length} scenarios stay locked until you master earlier ones (perfect run = mastered).</div>
          </div>
        ` : ''}
      </div>
    </div>
  `;
}

function ptrRenderLessons() {
  const host = document.getElementById('ptr-lessons-content');
  if (!host) return;
  if (!PT_LESSONS.length) {
    host.innerHTML = '<p style="text-align:center;color:var(--text-mid);padding:32px">No lessons available.</p>';
    return;
  }
  host.innerHTML = PT_LESSONS.map(l => `
    <div class="ptr-lesson-card">
      <div class="ptr-lesson-head">
        <div class="ptr-lesson-icon"></div>
        <div>
          <div class="ptr-lesson-title">${escHtml(l.title)}</div>
          <div class="ptr-lesson-sub">${escHtml(l.summary)}</div>
        </div>
      </div>
      <ul class="ptr-lesson-points">
        ${(l.keyPoints || []).map(p => '<li>' + escHtml(p) + '</li>').join('')}
      </ul>
    </div>
  `).join('');
}

function setPtrTab(tabId) {
  document.querySelectorAll('.ptr-tab-btn').forEach(b => {
    const id = b.id.replace('ptr-tab-btn-', '');
    const active = id === tabId;
    b.classList.toggle('ptr-tab-active', active);
    b.setAttribute('aria-selected', active ? 'true' : 'false');
    b.tabIndex = active ? 0 : -1;
  });
  ['practice', 'lessons', 'dashboard'].forEach(p => {
    const panel = document.getElementById('ptr-tab-' + p);
    if (!panel) return;
    panel.classList.toggle('is-hidden', p !== tabId);
  });
  if (tabId === 'lessons') ptrRenderLessons();
  else if (tabId === 'dashboard') ptrRenderDashboard();
}

function startPacketTrace() {
  if (!_USE_NETPLUS_PT) {
    if (typeof showToast === 'function') showToast('Packet Trace drill is Network+ only.', 'info');
    return;
  }
  // v4.99.48 Phase 8: desktop-only nudge for phones + iPad portrait. Packet
  // Trace renders a wide horizontal timeline of hops + a per-hop inspector
  // pane — the layout assumes landscape room.
  if (_isDesktopOnlyViewport()) {
    _showDesktopOnlyNudge('Packet Trace',
      'Hop-by-hop wireshark-style packet inspector with a horizontal timeline + per-frame protocol decoder. The timeline needs landscape room — open this on a laptop or desktop.');
    return;
  }
  // If there's a resume, offer it; otherwise show dashboard
  const resume = ptrGetResume();
  if (resume && resume.scenarioId) {
    setPtrTab('dashboard');  // dashboard surfaces the Resume card
    ptrRenderDashboard();
  } else {
    setPtrTab('dashboard');
    ptrRenderDashboard();
  }
}

// ════════════════════════════════════════════════════════════════════
// INCIDENT RESPONSE WAR ROOM (v4.97.0, issue #312) — Flagship #1 for Sec+
// SY0-701 Domain 4 (28%) flagship. 6-phase SANS PICERL drill. Practice
// mode only at v1; Pressure + AI gen + dashboard land v4.97.1+.
// ════════════════════════════════════════════════════════════════════
// ══════════════════════════════════════════
// v4.99.39 (Phase 11b) — IRW state + functions + init-IIFE block REMOVED.
// Full body lives in features/incident-response.js IIFE wrapper.
// ══════════════════════════════════════════

// ══════════════════════════════════════════
// v4.99.37 (Phase 11b) — Phishing Triage Lab functions block REMOVED.
// Full body lives in features/phishing-triage.js IIFE wrapper. Shell stub
// is at the constants region above (line ~32230).
// ══════════════════════════════════════════
function setOsDifficulty(diff) {
  osDifficulty = diff;
  // v4.42.5 (#128): ARIA state sync for difficulty toggle buttons.
  document.querySelectorAll('.os-diff-btn').forEach(b => {
    b.classList.remove('os-diff-active');
    b.setAttribute('aria-pressed', 'false');
  });
  const active = document.getElementById('os-diff-' + diff);
  if (active) {
    active.classList.add('os-diff-active');
    active.setAttribute('aria-pressed', 'true');
  }
  osIdx = 0; osCorrect = 0; osTotal = 0; osStreak = 0;
  osStartPractice();
}

function osGetPool() {
  if (osDifficulty === 'easy') return OS_DATA.filter(d => d.diff === 'easy');
  if (osDifficulty === 'medium') return OS_DATA.filter(d => d.diff === 'easy' || d.diff === 'medium');
  return OS_DATA;
}

function osStartPractice() {
  if (osMode === 'sort') osGenSortRound();
  else osGenIdentifyQ();
}

// ── Sort mode ──
function osGenSortRound() {
  const pool = osGetPool();
  const count = Math.min(pool.length, Math.floor(Math.random() * 4) + 5); // 5-8 items
  const items = pool.sort(() => Math.random() - 0.5).slice(0, count);
  osSortState = { items, placements: {} };
  osSortSelectedItem = null;
  osRenderSort();
}

function osRenderSort() {
  const area = document.getElementById('os-practice-area');
  if (!area) return;
  const st = osSortState;
  const placedNames = new Set(Object.values(st.placements));
  // Item bank
  let html = '<div class="os-sort-bank" id="os-sort-bank">';
  st.items.forEach(item => {
    const placed = placedNames.has(item.name);
    const selected = osSortSelectedItem === item.name;
    html += `<div class="os-sort-item${placed ? ' os-sort-placed' : ''}${selected ? ' os-sort-selected' : ''}" draggable="${!placed}" data-name="${escHtml(item.name)}" onclick="osClickItem('${escHtml(item.name)}')" ondragstart="osDragStart(event,'${escHtml(item.name)}')">${escHtml(item.name)}</div>`;
  });
  html += '</div>';
  // Lanes
  html += '<div class="os-lanes">';
  OSI_LAYERS.forEach(layer => {
    const laneItems = Object.entries(st.placements).filter(([, n]) => {
      const itm = st.items.find(x => x.name === n);
      return itm && Object.entries(st.placements).find(([k, v]) => v === n && parseInt(k) === layer.num);
    });
    const placedHere = Object.entries(st.placements).filter(([k]) => parseInt(k) === layer.num).map(([, v]) => v);
    html += `<div class="os-lane" data-layer="${layer.num}" ondragover="osDragOver(event)" ondrop="osDrop(event,${layer.num})" onclick="osClickLane(${layer.num})">`;
    html += `<div class="os-lane-num">${layer.num}</div>`;
    html += `<div class="os-lane-name">${layer.name}</div>`;
    html += `<div class="os-lane-items">`;
    placedHere.forEach(n => {
      html += `<div class="os-sort-item" onclick="osReturnItem('${escHtml(n)}',${layer.num})" style="cursor:pointer">${escHtml(n)}</div>`;
    });
    html += `</div></div>`;
  });
  html += '</div>';
  // Check button
  const allPlaced = st.items.every(item => Object.values(st.placements).includes(item.name));
  if (allPlaced) {
    html += '<button class="os-sort-check-btn" onclick="osCheckSort()">Check Answers</button>';
  }
  area.innerHTML = html;
  document.getElementById('os-score').textContent = osCorrect + ' / ' + osTotal;
  document.getElementById('os-streak').textContent = '' + osStreak;
  osRenderLevelBadge();
}

function osDragStart(e, name) { e.dataTransfer.setData('text/plain', name); }
function osDragOver(e) { e.preventDefault(); e.currentTarget.classList.add('os-lane-hover'); }
function osDrop(e, layerNum) {
  e.preventDefault();
  e.currentTarget.classList.remove('os-lane-hover');
  const name = e.dataTransfer.getData('text/plain');
  if (!name) return;
  // Remove from any previous lane
  Object.keys(osSortState.placements).forEach(k => { if (osSortState.placements[k] === name) delete osSortState.placements[k]; });
  // Find an available slot key for this lane
  const key = layerNum;
  // Use name as value, layer as key — but multiple items per layer need unique keys
  if (!osSortState.placements['_items']) osSortState.placements['_items'] = {};
  osSortState.placements['_items'][name] = layerNum;
  // Rebuild simple placements from _items
  const items = osSortState.placements['_items'];
  osSortState.placements = { '_items': items };
  Object.entries(items).forEach(([n, l]) => { osSortState.placements[l + '_' + n] = n; });
  osSortSelectedItem = null;
  osRenderSort();
}

// Simplified placement tracking using _items sub-object
function _osGetPlacements() {
  if (!osSortState.placements['_items']) osSortState.placements['_items'] = {};
  return osSortState.placements['_items'];
}

function osClickItem(name) {
  const placements = _osGetPlacements();
  if (placements[name] !== undefined) return; // already placed
  if (osSortSelectedItem === name) { osSortSelectedItem = null; osRenderSort(); return; }
  osSortSelectedItem = name;
  osRenderSort();
}

function osClickLane(layerNum) {
  if (!osSortSelectedItem) return;
  const placements = _osGetPlacements();
  placements[osSortSelectedItem] = layerNum;
  osSortSelectedItem = null;
  // Rebuild top-level placements
  osSortState.placements = { '_items': placements };
  Object.entries(placements).forEach(([n, l]) => { osSortState.placements[l + '_' + n] = n; });
  osRenderSort();
}

function osReturnItem(name, layerNum) {
  const placements = _osGetPlacements();
  delete placements[name];
  osSortState.placements = { '_items': placements };
  Object.entries(placements).forEach(([n, l]) => { osSortState.placements[l + '_' + n] = n; });
  osRenderSort();
}

function osCheckSort() {
  const placements = _osGetPlacements();
  const area = document.getElementById('os-practice-area');
  if (!area) return;
  let html = '<div class="os-lanes">';
  let roundCorrect = 0;
  let roundTotal = osSortState.items.length;
  OSI_LAYERS.forEach(layer => {
    const itemsHere = Object.entries(placements).filter(([, l]) => l === layer.num).map(([n]) => n);
    const correctItems = itemsHere.filter(n => { const d = OS_DATA.find(x => x.name === n); return d && d.layer === layer.num; });
    const wrongItems = itemsHere.filter(n => { const d = OS_DATA.find(x => x.name === n); return !d || d.layer !== layer.num; });
    const isAllCorrect = itemsHere.length > 0 && wrongItems.length === 0;
    const hasWrong = wrongItems.length > 0;
    roundCorrect += correctItems.length;
    html += `<div class="os-lane${isAllCorrect && itemsHere.length > 0 ? ' os-lane-correct' : ''}${hasWrong ? ' os-lane-wrong' : ''}" data-layer="${layer.num}">`;
    html += `<div class="os-lane-num">${layer.num}</div>`;
    html += `<div class="os-lane-name">${layer.name}</div>`;
    html += `<div class="os-lane-items">`;
    itemsHere.forEach(n => {
      const d = OS_DATA.find(x => x.name === n);
      const correct = d && d.layer === layer.num;
      html += `<div class="os-sort-item ${correct ? 'os-sort-correct' : 'os-sort-wrong'}">${escHtml(n)}${correct ? '' : ' L' + (d ? d.layer : '?')}</div>`;
    });
    html += '</div></div>';
  });
  html += '</div>';
  // Update mastery for each item
  osSortState.items.forEach(item => {
    const placedLayer = placements[item.name];
    const correct = placedLayer === item.layer;
    updateOsMastery(item.name, correct);
    osTotal++;
    if (correct) { osCorrect++; osStreak++; } else { osStreak = 0; }
  });
  html += `<div style="text-align:center;margin-top:16px;font-size:18px;font-weight:800">${roundCorrect}/${roundTotal} correct</div>`;
  html += '<button class="os-sort-check-btn" onclick="osGenSortRound()" style="margin-top:12px">Next Round \u2192</button>';
  area.innerHTML = html;
  document.getElementById('os-score').textContent = osCorrect + ' / ' + osTotal;
  document.getElementById('os-streak').textContent = '' + osStreak;
  osRenderHeatmap();
  osRenderLevelBadge();
  evaluateMilestones();
}

// ── Identify mode (MCQ) ──
function osGenIdentifyQ() {
  osIdx++;
  const pool = osGetPool();
  const item = pool[Math.floor(Math.random() * pool.length)];
  const layer = OSI_LAYERS.find(l => l.num === item.layer);
  // Randomly ask "what layer?" or "which item at layer N?"
  const askLayer = Math.random() < 0.5;
  let opts, correctAnswer, question;
  if (askLayer) {
    question = `What OSI layer does <strong>${escHtml(item.name)}</strong> operate at?`;
    correctAnswer = 'Layer ' + item.layer + ' (' + layer.name + ')';
    const wrongLayers = OSI_LAYERS.filter(l => l.num !== item.layer).sort(() => Math.random() - 0.5).slice(0, 3);
    opts = [{ label: correctAnswer, correct: true }, ...wrongLayers.map(l => ({ label: 'Layer ' + l.num + ' (' + l.name + ')', correct: false }))].sort(() => Math.random() - 0.5);
  } else {
    question = `Which of these operates at <strong>Layer ${item.layer} (${layer.name})</strong>?`;
    correctAnswer = item.name;
    const wrongItems = pool.filter(d => d.layer !== item.layer).sort(() => Math.random() - 0.5).slice(0, 3);
    opts = [{ label: item.name, correct: true }, ...wrongItems.map(d => ({ label: d.name, correct: false }))].sort(() => Math.random() - 0.5);
  }
  osQ = { item, askLayer, opts, correctAnswer };
  const area = document.getElementById('os-practice-area');
  if (!area) return;
  let html = `<div class="subnet-card"><div class="subnet-q-num">Q${osIdx}</div><div class="subnet-question">${question}</div>`;
  html += '<div class="os-mcq-grid">';
  opts.forEach(o => {
    html += `<button class="os-mcq-btn" onclick="osPickIdentify(this,${o.correct},'${escHtml(o.label)}')">${escHtml(o.label)}</button>`;
  });
  html += '</div><div id="os-identify-fb"></div>';
  html += `<button class="btn btn-primary btn-full is-hidden" id="os-next-btn" style="margin-top:14px" onclick="osGenIdentifyQ()">Next Question \u2192</button>`;
  html += '</div>';
  area.innerHTML = html;
  document.getElementById('os-score').textContent = osCorrect + ' / ' + osTotal;
  document.getElementById('os-streak').textContent = '' + osStreak;
  osRenderLevelBadge();
}

function osPickIdentify(btn, isCorrect, label) {
  document.querySelectorAll('.os-mcq-btn').forEach(b => { b.disabled = true; });
  osTotal++;
  updateOsMastery(osQ.item.name, isCorrect);
  if (isCorrect) { osCorrect++; osStreak++; } else { osStreak = 0; if (osMode === 'endless') { osEndEndless(); return; } }
  document.getElementById('os-score').textContent = osCorrect + ' / ' + osTotal;
  document.getElementById('os-streak').textContent = '' + osStreak;
  document.getElementById('os-next-btn')?.classList.remove('is-hidden');
  const fb = document.getElementById('os-identify-fb');
  if (fb) {
    if (isCorrect) {
      fb.innerHTML = `<div class="os-fb-correct" style="margin-top:12px"><strong>Correct!</strong> ${escHtml(osQ.item.name)} = Layer ${osQ.item.layer} (${OSI_LAYERS.find(l => l.num === osQ.item.layer).name})</div>`;
    } else {
      fb.innerHTML = `<div class="os-fb-wrong" style="margin-top:12px"><strong>Incorrect.</strong></div><div class="os-fb-correct-answer">Correct: ${escHtml(osQ.correctAnswer)}</div>`;
    }
  }
  osRenderHeatmap();
  osRenderLevelBadge();
  evaluateMilestones();
}

// OS gate (drill-specific question format)
function osRenderGate(lesson) {
  const area = document.getElementById('os-gate-area');
  if (!area) return;
  const layerNum = parseInt(lesson.id.replace('layer', ''));
  const layerItems = OS_DATA.filter(d => d.layer === layerNum);
  const gs = { questions: [], current: 0, correct: 0 };
  for (let i = 0; i < 5; i++) {
    const item = layerItems[Math.floor(Math.random() * layerItems.length)];
    const wrongItems = OS_DATA.filter(d => d.layer !== layerNum).sort(() => Math.random() - 0.5).slice(0, 3);
    gs.questions.push({ item, wrongItems });
  }
  window._osGateState = gs;
  osRenderGateQuestion(area, gs);
}

function osRenderGateQuestion(area, gs) {
  if (osScaffold.renderGateResult(area, gs)) return;
  const q = gs.questions[gs.current];
  const layer = OSI_LAYERS.find(l => l.num === q.item.layer);
  const opts = [q.item, ...q.wrongItems].sort(() => Math.random() - 0.5);
  area.innerHTML = `<div><div class="os-gate-progress">${gs.current + 1} / 5</div><div class="subnet-question" style="font-size:15px;margin-bottom:14px">Which operates at <strong>Layer ${q.item.layer} (${layer.name})</strong>?</div><div class="os-mcq-grid">${opts.map(o => `<button class="os-mcq-btn" onclick="osCheckGate(this,${o.name === q.item.name})">${escHtml(o.name)}</button>`).join('')}</div><div id="os-gate-fb"></div></div>`;
}

function osCheckGate(btn, isCorrect) { osScaffold.checkGate(btn, isCorrect); }

